INSERT INTO product (ID_PRODUCT,name,description,price,stock,original_price,category,image_link,sub_category) VALUE
    (NULL,'Tai nghe Bluetooth','Trải nghiệm âm thanh đỉnh cao với dòng tai nghe Bluetooth thế hệ mới, được thiết kế tinh tế và hiện đại. Sản phẩm sở hữu công nghệ kết nối không dây ổn định, giúp bạn tận hưởng âm nhạc mọi lúc mọi nơi mà không lo vướng víu dây cáp. Với màng loa chất lượng cao, tai nghe mang đến dải âm trầm sâu lắng.',499000,10,399000,'Âm thanh','https://cf.shopee.vn/file/sg-11134201-22100-tyb9vvkk66iva2','Tai nghe'),
    (NULL,'Bàn phím cơ RGB','Nâng tầm không gian làm việc và giải trí của bạn với chiếc bàn phím cơ RGB rực rỡ. Sản phẩm được trang bị hệ thống đèn LED đa sắc màu với nhiều chế độ tùy chỉnh, tạo nên hiệu ứng thị giác ấn tượng trong đêm tối. Switch cơ học cao cấp mang lại cảm giác gõ phím cực kỳ đầm tay, độ phản hồi nhanh.',1090000,20,890000,'Thiết bị','https://bizweb.dktcdn.net/thumb/1024x1024/100/466/510/products/1-mode-xanh-trang.jpg?v=1693476924560','Bàn phím'),
    (NULL,'Sạc dự phòng 10000mAh','Dung lượng 10000mAh nhỏ gọn, là người bạn đồng hành lý tưởng trong mọi chuyến đi. Công nghệ sạc nhanh thông minh giúp tối ưu hóa thời gian nạp năng lượng cho điện thoại và máy tính bảng mà vẫn đảm bảo an toàn tuyệt đối, chống cháy nổ. Lớp vỏ ngoài được làm từ chất liệu cao cấp, chống bám vân tay.',350000,15,299000,'Phụ kiện','https://cf.shopee.vn/file/cd25f3ec676ee91e06f433d5acae11da','Sạc dự phòng'),
    (NULL,'Chuột gaming Razer','Đạt đến độ chính xác tuyệt đối trong mọi trận game với chuột gaming Razer chuyên dụng. Sản phẩm sở hữu cảm biến quang học hiện đại với DPI có thể tùy chỉnh linh hoạt, cho phép bạn thực hiện những cú di chuột mượt mà và chuẩn xác nhất. Thiết kế form cầm ôm sát lòng bàn tay giúp game thủ không bị mỏi.',850000,30,690000,'Thiết bị','https://tse1.mm.bing.net/th/id/OIP.zymVox8ztktc61TVtHsLvwHaHa?pid=Api&P=0&h=180','Chuột'),
    (NULL,'Ống kính điện thoại','Biến chiếc điện thoại của bạn thành một máy ảnh chuyên nghiệp với bộ ống kính rời tiện lợi. Sản phẩm giúp mở rộng góc chụp, tăng cường khả năng thu phóng hoặc tạo ra những bức ảnh macro sắc nét đến từng chi tiết nhỏ nhất. Thấu kính được chế tác từ thủy tinh quang học chất lượng cao, giúp giảm nhiễu.',150000,100,110000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lziqeg7b1k0x5b','Ống kính'),
    (NULL,'Đồng hồ thông minh','Chiếc đồng hồ thông minh này là một trợ lý sức khỏe cá nhân ngay trên cổ tay bạn. Sản phẩm tích hợp các tính năng hiện đại như đo nhịp tim, theo dõi giấc ngủ, đếm bước chân và thông báo cuộc gọi, tin nhắn từ điện thoại một cách tức thì. Màn hình hiển thị sắc nét với độ phân giải cao, kháng nước bền bỉ.',2090000,25,1850000,'Thiết bị','https://cdn.tgdd.vn/Products/Images/7077/231681/beu-b2-hong-thumb-1-2-600x600.jpg','Đồng hồ'),
    (NULL,'Tai nghe True Wireless','Tận hưởng sự tự do hoàn toàn với tai nghe True Wireless không dây hoàn toàn, mang đến trải nghiệm âm thanh không giới hạn. Công nghệ Bluetooth mới nhất giúp kết nối nhanh chóng và ổn định, loại bỏ hoàn toàn độ trễ khi xem phim hoặc chơi game. Hộp sạc đi kèm nhỏ gọn, cung cấp thêm nhiều giờ sử dụng.',999000,45,799000,'Âm thanh','https://cdn.tgdd.vn/Products/Images/54/324577/tai-nghe-bluetooth-true-wireless-jbl-live-pro-2-xanh-600x600.jpg','Tai nghe'),
    (NULL,'Loa mini Xiaomi','Thưởng thức âm nhạc mọi lúc mọi nơi với chiếc loa mini Xiaomi sở hữu thiết kế cực kỳ tối giản nhưng sang trọng. Dù có kích thước nhỏ gọn nằm lòng bàn tay, loa vẫn mang đến chất lượng âm thanh đáng kinh ngạc với âm bass mạnh mẽ. Kết nối không dây mượt mà cùng thời lượng pin bền bỉ cho các buổi dã ngoại.',420000,60,340000,'Âm thanh','https://down-vn.img.susercontent.com/file/vn-11134207-7ra0g-m8foweiqwnzi8d','Loa'),
    (NULL,'Miếng dán cường lực','Bảo vệ tối ưu cho màn hình điện thoại của bạn với miếng dán cường lực độ cứng tiêu chuẩn. Sản phẩm có khả năng chống trầy xước từ các vật sắc nhọn và giảm thiểu nguy cơ nứt vỡ khi vô tình va đập mạnh. Lớp phủ nano đặc biệt giúp hạn chế bám dấu vân tay, mồ hôi, giữ cho màn hình luôn sáng bóng và mượt mà.',70000,150,50000,'Phụ kiện','https://product.hstatic.net/200000460953/product/05d4ebd904badee487ab6_f621c79066d546c3984875fa09639df0_master.jpg','Dán màn hình'),
    (NULL,'Cáp sạc USB-C','Sợi cáp sạc USB-C cao cấp là giải pháp truyền tải dữ liệu và sạc năng lượng nhanh chóng cho các thiết bị công nghệ hiện đại. Phần lõi đồng nguyên chất giúp giảm thiểu tiêu hao năng lượng, trong khi lớp vỏ bọc ngoài chắc chắn có khả năng chống rối và chịu được hàng ngàn lần uốn cong mà không lo đứt gãy.',90000,120,70000,'Phụ kiện','https://vitinhtanhung.com/wp-content/uploads/2023/02/cap-sac-nhanh-usb-c-ugreen-60408.jpg','Cáp sạc'),
    (NULL,'Chuột không dây Apple','Chuột không dây Apple sở hữu thiết kế tối giản, sang trọng với bề mặt cảm ứng mượt mà, mang lại trải nghiệm điều khiển hoàn toàn khác biệt. Sản phẩm hỗ trợ các thao tác cử chỉ đa điểm giúp bạn duyệt web nhanh chóng. Công nghệ kết nối Bluetooth ổn định và tiết kiệm pin, cho phép sử dụng liên tục lâu dài.',1390000,10,1250000,'Thiết bị','https://cdn-v2.didongviet.vn/files/media/catalog/product/c/h/chuot-khong-day-apple-magic-mouse-2.jpg','Chuột'),
    (NULL,'Hub chuyển USB-C to HDMI','Bộ chuyển đổi Hub USB-C sang HDMI là phụ kiện cần thiết để xuất hình ảnh chất lượng cao từ laptop lên màn hình lớn, tivi hoặc máy chiếu. Sản phẩm hỗ trợ độ phân giải sắc nét, đảm bảo truyền tải tín hiệu âm thanh và hình ảnh ổn định, không bị trễ hay nhiễu. Thiết kế vỏ nhôm tản nhiệt tốt, nhỏ gọn.',620000,70,520000,'Phụ kiện','https://cf.shopee.vn/file/e544a76bdb19495365711ffad76c5367','Hub chuyển'),
    (NULL,'Máy tính bảng ipa','Máy tính bảng với màn hình hiển thị sống động, sắc nét, mang lại trải nghiệm giải trí và làm việc hiệu quả tuyệt vời. Sản phẩm sở hữu cấu hình ổn định, xử lý mượt mà các ứng dụng văn phòng, học tập cũng như chơi các tựa game phổ biến hiện nay. Thiết kế mỏng nhẹ, sang trọng, camera hỗ trợ video call tốt.',490000,40,450000,'Thiết bị','https://makelifeclick.com/wp-content/uploads/2022/11/ipad-pro-11-m1-back-design.jpg','Máy tính'),
    (NULL,'Loa di động Bose Mini','Dòng loa di động Bose Mini nổi tiếng với chất âm trung thực, ấm áp và dải trầm cực kỳ mạnh mẽ so với kích thước nhỏ gọn của nó. Vỏ loa được làm từ kim loại nguyên khối chắc chắn, mang lại vẻ ngoài đẳng cấp và bền bỉ. Công nghệ Bluetooth cho phép kết nối nhanh chóng với mọi thiết bị di động hiện nay.',3290000,15,2790000,'Âm thanh','https://tse3.mm.bing.net/th/id/OIP.pjaLlT0ZIJlTHen5GDku4gHaHa?pid=Api&P=0&h=180','Loa'),
    (NULL,'Cân điện tử thông minh','Cân điện tử thông minh giúp bạn theo dõi các chỉ số cơ thể một cách chính xác và khoa học ngay tại nhà. Ngoài việc đo cân nặng, sản phẩm còn hỗ trợ phân tích các chỉ số như tỉ lệ mỡ, lượng nước, khối lượng cơ thông qua ứng dụng kết nối trên điện thoại. Bề mặt kính cường lực sang trọng, chịu lực cực tốt.',990000,5,880000,'Thiết bị','https://mivietnam.vn/wp-content/uploads/2020/06/MIVIETNAM-CAN-DIEN-TU-THONG-MINH-XIAOMI-SMART-SCALE-GEN-2-09.jpg','Cân'),
    (NULL,'Webcam PC','Webcam giúp thực hiện các cuộc gọi video, học online hoặc họp trực tuyến dễ dàng. Sản phẩm có hình ảnh rõ nét giúp người đối diện nhìn thấy bạn rõ ràng hơn. Thiết kế nhỏ gọn, dễ lắp đặt trên màn hình laptop hoặc PC. Đây là thiết bị cần thiết cho xu hướng học tập và làm việc từ xa hiện đại.',620000,20,540000,'Công nghệ','https://cameramini.vn/wp-content/uploads/2021/10/Webcam-may-tinh-1080p-1.jpg','Webcam'),
    (NULL,'SSD di động 512GB','Nâng cấp tốc độ vượt trội cho máy tính của bạn với ổ cứng SSD dung lượng 512GB. Công nghệ lưu trữ flash giúp khởi động hệ điều hành và mở các ứng dụng nặng chỉ trong vài giây, nhanh hơn gấp nhiều lần so với ổ cứng HDD truyền thống. Sản phẩm hoạt động ổn định, êm ái và có khả năng chống sốc cao, bảo vệ dữ liệu.',1650000,25,1450000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lthmty4ahy4qd8','SSD'),
    (NULL,'Đèn cảm biến','Đèn cảm biến chuyển động thông minh tự động bật sáng khi phát hiện có người đi qua và tự tắt sau một khoảng thời gian ngắn để tiết kiệm điện. Sản phẩm rất phù hợp để lắp đặt ở hành lang, cầu thang, nhà vệ sinh hoặc trong tủ quần áo. Ánh sáng vàng dịu nhẹ không gây chói mắt, lắp đặt bằng nam châm tiện lợi.',360000,40,310000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lgvor3pfewqa93','Đèn'),
    (NULL,'Bàn phím Bluetooth mini','Bàn phím Bluetooth mini là giải pháp nhập liệu tuyệt vời cho máy tính bảng, điện thoại khi cần di chuyển nhiều. Với kích thước cực kỳ gọn nhẹ, bạn có thể dễ dàng mang theo trong túi xách. Các phím bấm có độ nảy tốt, khoảng cách hợp lý giúp thao tác gõ văn bản nhanh chóng và chính xác, tương thích nhiều hệ điều hành.',650000,40,540000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ln6x0mtvonqrd7','Bàn phím'),
    (NULL,'Chuột Logitech','Chuột văn phòng Logitech mang lại sự bền bỉ và độ tin cậy cao cho người dùng làm việc chuyên nghiệp hàng ngày. Thiết kế công thái học vừa vặn với lòng bàn tay, giúp giảm cảm giác mỏi cổ tay khi sử dụng trong thời gian dài. Mắt đọc quang học có độ nhạy cao, hoạt động mượt mà trên nhiều bề mặt khác nhau.',270000,60,220000,'Thiết bị','https://cf.shopee.vn/file/7c8b8c91b509acec7fa7ccef2d5edd74','Chuột'),
    (NULL,'Balo thời trang','Balo thời trang với thiết kế hiện đại, trẻ trung, phù hợp cho cả đi học, đi làm hay đi du lịch ngắn ngày. Sản phẩm được làm từ chất liệu vải cao cấp, bền bỉ và có khả năng chống thấm nước nhẹ, giúp bảo vệ đồ dùng bên trong an toàn. Ngăn chứa rộng rãi cùng nhiều ngăn phụ tiện lợi giúp bạn sắp xếp phụ kiện khoa học.',390000,35,320000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lpv5mh6bht5ec2','Balo'),
    (NULL,'Quạt mini USB','Giải tỏa cơn nóng tức thì với chiếc quạt mini dùng cổng USB tiện lợi, phù hợp cho nhân viên văn phòng hoặc học sinh sinh viên. Quạt có kích thước nhỏ gọn, có thể đặt gọn gàng trên bàn làm việc hoặc mang theo trong túi xách. Động cơ vận hành êm ái, không gây tiếng ồn khó chịu nhưng vẫn tạo ra luồng gió mát ổn định.',190000,80,150000,'Thiết bị','https://bizweb.dktcdn.net/100/117/153/files/a-62df2b1d-be79-4494-9214-f8fc3a984a48.jpg?v=1578401696377','Quạt'),
    (NULL,'Sổ tay da A5','Cuốn sổ tay bìa da cao cấp kích thước A5 là vật dụng không thể thiếu để ghi chép ý tưởng, kế hoạch hàng ngày của bạn. Bìa sổ được làm từ chất liệu giả da sang trọng, mềm mại và rất bền màu theo thời gian. Chất lượng giấy bên trong đạt tiêu chuẩn, có độ bám mực tốt, không gây hiện tượng nhòe hay thấm mực.',180000,90,130000,'Phụ kiện','https://tse2.mm.bing.net/th/id/OIP.-_6gZzHN9Fsa6mIN8gseGQHaHa?pid=Api&P=0&h=180','Sổ tay'),
    (NULL,'Bàn gập học sinh','Bàn gập học sinh đa năng với thiết kế thông minh, có thể gấp gọn lại sau khi sử dụng để tiết kiệm tối đa diện tích phòng. Mặt bàn được làm từ gỗ công nghiệp cao cấp, chống trầy xước và dễ dàng lau chùi vệ sinh. Chân bàn bằng thép chắc chắn, có đệm cao su chống trượt giúp bàn luôn ổn định trên mọi bề mặt.',490000,25,390000,'Nội thất','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lsc3ayu42b2x42','Bàn'),
    (NULL,'Kính chống ánh sáng xanh','Bảo vệ đôi mắt của bạn khỏi tác hại từ màn hình máy tính và điện thoại với kính chống ánh sáng xanh chuyên dụng. Tròng kính được phủ lớp lọc đặc biệt giúp ngăn chặn tia sáng xanh có hại, giảm tình trạng mỏi mắt, khô mắt và đau đầu. Gọng kính được làm từ nhựa siêu nhẹ mang lại cảm giác thoải mái khi đeo.',290000,100,230000,'Phụ kiện','https://kavi.vn/upload/image/kinh-titan-nua-vien-titanium-kavi-a4-kinh-chong-anh-sang-xanh-anhbia2.jpg','Kính'),
    (NULL,'Bình giữ nhiệt Lock','Bình giữ nhiệt Lock&Lock nổi tiếng với khả năng giữ nóng và lạnh tuyệt vời suốt nhiều giờ. Sản phẩm được làm từ thép không gỉ 304 cao cấp, an toàn cho sức khỏe và không để lại mùi ám vào nước uống. Thiết kế nắp đậy kín khít chống rò rỉ nước hoàn toàn, cho phép bạn thoải mái mang theo trong cặp sách.',350000,20,290000,'Gia dụng','https://locknlockvietnam.com/wp-content/uploads/2022/01/binh-giu-nhiet-lock-lock-belt-bottle-490ml-lhc4267.jpg','Bình giữ nhiệt'),
    (NULL,'Máy tạo độ ẩm','Máy tạo độ ẩm mini giúp cân bằng độ ẩm trong phòng điều hòa, bảo vệ làn da và hệ hô hấp khỏi tình trạng khô ráp. Hoạt động bằng công nghệ phun sương siêu âm cực êm, không tạo ra tiếng ồn ảnh hưởng giấc ngủ. Thiết kế nhỏ gọn tích hợp đèn LED đổi màu sinh động, có thể dùng làm đèn ngủ trang trí cá tính.',410000,15,330000,'Thiết bị','https://mivietnam.vn/wp-content/uploads/2021/05/mivietnm-may-tao-am-f628s.jpg','Máy tạo ẩm'),
    (NULL,'Giá đỡ laptop','Giá đỡ laptop hợp kim nhôm cao cấp giúp nâng cao màn hình lên ngang tầm mắt, cải thiện tư thế ngồi và hạn chế đau mỏi cổ vai gáy. Thiết kế rỗng hỗ trợ tản nhiệt cho máy hiệu quả hơn trong quá trình sử dụng lâu dài. Sản phẩm có thể điều chỉnh nhiều mức độ cao và gấp gọn mang theo trong balo vô cùng tiện lợi.',520000,50,430000,'Thiết bị','https://product.hstatic.net/200000427229/product/upload_7576af16d8264006996f1ff33def07c9_05f329c7b4394aaaaeb35b20bcfd1511_master.jpg','Giá đỡ'),
    (NULL,'Bộ vệ sinh laptop','Giữ cho chiếc laptop luôn sạch sẽ với bộ vệ sinh 5 trong 1. Bộ sản phẩm bao gồm đầy đủ dụng cụ như bình xịt dung dịch vệ sinh, khăn lau sợi mịn, chổi quét bụi, dụng cụ thổi bụi và tăm bông. Giúp loại bỏ hoàn toàn bụi bẩn bám trên màn hình, bàn phím và các kẽ hở khó tiếp cận nhất, duy trì độ bền máy.',210000,40,170000,'Phụ kiện','https://down-vn.img.susercontent.com/file/sg-11134201-22110-44jbkf1y4ejv88','Vệ sinh laptop'),
    (NULL,'Sạc nhanh 33W','Củ sạc nhanh công suất 33W của Xiaomi giúp rút ngắn đáng kể thời gian nạp đầy năng lượng cho điện thoại. Sản phẩm hỗ trợ nhiều chuẩn sạc nhanh phổ biến, đảm bảo dòng điện ra ổn định và an toàn cho pin thiết bị. Tích hợp nhiều lớp bảo vệ chống quá nhiệt, quá dòng, mang lại sự an tâm tuyệt đối khi sử dụng.',450000,50,390000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lnlgk2lrrblm2b','Sạc'),
    (NULL,'Áo mưa tiện lợi','Áo mưa tiện lợi với chất liệu nilon cao cấp, dày dặn và dẻo dai, giúp bảo vệ bạn hoàn toàn khỏi những cơn mưa bất chợt. Thiết kế dạng áo choàng rộng rãi, che kín người và có mũ trùm đầu đi kèm dây rút chắc chắn. Sản phẩm có khả năng chống thấm nước tuyệt đối, dễ dàng gấp gọn lại sau khi sử dụng.',70000,200,50000,'Tiện ích','https://aomuakhaihoan.com/wp-content/uploads/2018/08/ao-mua-tien-loi-3-1.jpg','Áo mưa'),
    (NULL,'Đế tản nhiệt','Đế tản nhiệt laptop trang bị hệ thống quạt làm mát công suất lớn giúp hạ nhiệt độ máy tính hiệu quả, bảo vệ linh kiện bên trong và tăng tuổi thọ cho máy. Bề mặt đế được làm từ lưới kim loại tản nhiệt nhanh, có khả năng chịu lực tốt. Bạn có thể điều chỉnh độ nghiêng để tạo góc làm việc thoải mái nhất.',390000,40,320000,'Thiết bị','https://dalatlaptop.com/uploads/21/08/de-tan-nhiet-laptop-vsp-cooler-n28.PNG','Tản nhiệt'),
    (NULL,'Máy hút bụi mini','Máy hút bụi mini cầm tay là giải pháp dọn dẹp tuyệt vời cho các không gian nhỏ như bàn làm việc, kệ sách hay nội thất ô tô. Với lực hút mạnh mẽ ẩn trong thiết kế gọn nhẹ, sản phẩm dễ dàng lấy đi bụi bẩn ở những khe hẹp khó tiếp cận nhất. Máy sử dụng pin sạc tiện lợi, không vướng víu dây điện rườm rà.',850000,15,760000,'Gia dụng','https://down-vn.img.susercontent.com/file/7faaee999ae01950a89f09437a3b336d','Máy hút bụi'),
    (NULL,'Hộp cơm giữ nhiệt','Hộp cơm giữ nhiệt đa năng giúp bạn thưởng thức bữa trưa tự nấu thơm ngon và ấm nóng ngay tại văn phòng hay trường học. Sản phẩm gồm nhiều ngăn tách biệt giúp giữ trọn hương vị các món ăn mà không bị lẫn mùi. Lớp vỏ cách nhiệt cao cấp đảm bảo giữ nhiệt hiệu quả trong nhiều giờ mà vẫn an toàn khi chạm.',210000,35,170000,'Đồ dùng','https://locknlockvietnam.com/wp-content/uploads/2022/11/bo-hop-com-giu-nhiet-hut-chan-khong-lock-lock-nvy-4-lhc8052s01-1.jpg','Hộp cơm'),
    (NULL,'Ô dù gấp gọn','Ô dù gấp gọn thông minh với khung xương chắc chắn, có khả năng chống chịu gió mạnh và bảo vệ bạn hoàn toàn trước những cơn mưa bất chợt hay ánh nắng gay gắt. Vải dù cao cấp có lớp phủ chống tia UV hiệu quả, bảo vệ làn da của bạn tối ưu hơn. Thiết kế nhỏ gọn dễ dàng nằm gọn trong túi xách hay cốp xe.',150000,50,120000,'Đồ dùng','https://tse2.mm.bing.net/th/id/OIP.kuH1ZLuCyUUhC2v--cRG9wHaHa?pid=Api&P=0&h=180','Ô dù'),
    (NULL,'Áo thun nam basic','Áo thun nam thiết kế basic là món đồ không thể thiếu trong tủ đồ của phái mạnh nhờ tính ứng dụng cao và sự đơn giản tinh tế. Sản phẩm được làm từ chất liệu vải cotton co giãn tốt, thấm hút mồ hôi hiệu quả, mang lại cảm giác thoáng mát suốt ngày dài. Đường may tỉ mỉ, form dáng vừa vặn tôn nam tính.',230000,50,180000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lsl2p5f20syhed','Áo thun'),
    (NULL,'Áo thun nam cotton','Áo thun nam chất liệu 100% cotton tự nhiên mang đến sự mềm mại tuyệt đối và cực kỳ thân thiện với làn da. Vải có độ dày vừa phải, bền màu và không bị xù lông sau nhiều lần giặt. Khả năng thoát khí tối ưu giúp người mặc luôn cảm thấy dễ chịu, ngay cả trong những ngày hè oi bức. Thiết kế tối giản hiện đại.',240000,45,190000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ludq1oagkro1a6','Áo thun'),
    (NULL,'Áo thun form rộng','Áo thun nam form rộng (oversize) mang phong cách trẻ trung, năng động, đang là xu hướng thời trang được giới trẻ ưa chuộng. Thiết kế áo rộng rãi giúp che khuyết điểm cơ thể tốt và tạo sự thoải mái tối đa trong mọi cử động. Chất vải dày dặn, đứng form và bền màu. Phù hợp cho phong cách dạo phố cá tính.',250000,40,200000,'Áo','https://cf.shopee.vn/file/sg-11134201-22120-js2x6hko6qkv27','Áo thun'),
    (NULL,'Áo thun thể thao','Áo thun nam chuyên dụng cho thể thao với chất liệu vải thun lạnh cao cấp, có khả năng co giãn 4 chiều cực tốt. Công nghệ dệt hiện đại giúp áo thoát nhiệt nhanh và thấm hút mồ hôi tức thì, giữ cho cơ thể luôn khô ráo trong suốt quá trình tập luyện cường độ cao. Đây là người bạn đồng hành tại phòng gym.',260000,35,210000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ln8qj49go4ig71','Áo thun'),
    (NULL,'Áo thun cổ tròn','Áo thun nam cổ tròn là kiểu dáng kinh điển chưa bao giờ lỗi mốt, mang lại vẻ ngoài trẻ trung và cực kỳ dễ mặc. Sản phẩm được sản xuất từ sợi vải tổng hợp cao cấp giúp áo giữ được độ phẳng phiu, ít nhăn sau khi giặt. Phần cổ áo được bo chun chắc chắn, không bị giãn hay biến dạng sau thời gian dài dùng.',270000,30,220000,'Áo','https://salt.tikicdn.com/cache/600x600/ts/product/b4/39/80/de7a5adac47798df77fd1880298cd9b1.jpg','Áo thun'),
    (NULL,'Áo sơ mi nam trắng','Áo sơ mi trắng là biểu tượng của sự lịch lãm, chỉn chu. Sản phẩm sử dụng chất liệu vải chống nhăn cao cấp, giúp bạn luôn giữ được diện mạo phẳng phiu suốt cả ngày làm việc dài. Thiết kế cổ đức truyền thống kết hợp với form dáng ôm nhẹ tôn lên vẻ ngoài nam tính. Phù hợp mặc đi làm hay dự các sự kiện.',340000,30,280000,'Áo','https://aoxuanhe.com/upload/product/axh-187/ao-so-mi-nam-khoac-ngoai-trang-0.jpg','Áo sơ mi'),
    (NULL,'Áo sơ mi công sở','Áo sơ mi nam dành riêng cho môi trường công sở với thiết kế thanh lịch và màu sắc nhã nhặn. Chất liệu vải có độ bền cao, thoáng khí và khả năng thấm hút mồ hôi tốt. Form dáng áo được cắt may tỉ mỉ, giúp người mặc dễ dàng vận động mà vẫn giữ được sự gọn gàng, chuyên nghiệp, lịch sự trong mắt đối tác.',350000,25,290000,'Áo','https://cf.shopee.vn/file/74f2d7273bf062e866e4ec31d67b15eb','Áo sơ mi'),
    (NULL,'Áo sơ mi slimfit','Áo sơ mi nam dáng slimfit được thiết kế ôm gọn cơ thể một cách tinh tế, giúp tôn lên vóc dáng khỏe khoắn và hiện đại của người mặc. Chất liệu vải co giãn nhẹ tạo sự thoải mái tối đa trong mọi cử động, không gây cảm giác gò bó. Sản phẩm rất phù hợp cho những bạn nam trẻ trung năng động hiện nay.',360000,20,300000,'Áo','https://product.hstatic.net/200000341513/product/ao-so-mi-nam-slimfit-dai-tay-cao-cap-belluni-ads3-b5__1__fcb232524ffb417fb5edb2d77048137e_large.jpg','Áo sơ mi'),
    (NULL,'Áo sơ mi kẻ sọc','Áo sơ mi nam họa tiết kẻ sọc mang lại vẻ ngoài tươi mới, trẻ trung và giúp người mặc trông thon gọn hơn. Các đường kẻ được dệt sắc nét trên nền vải cao cấp, bền màu theo thời gian. Đây là lựa chọn tuyệt vời để thay đổi phong cách sau những ngày mặc áo trơn. Dễ dàng phối cùng quần kaki hoặc quần jean.',370000,18,310000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7ra0g-m9lhlkcml3lu6a','Áo sơ mi'),
    (NULL,'Áo sơ mi denim','Áo sơ mi nam chất liệu denim mang đậm phong cách phong trần, bụi bặm và vô cùng cá tính. Vải denim được xử lý mềm mại giúp người mặc không cảm thấy thô ráp mà vẫn giữ được độ dày dặn đặc trưng. Áo có độ bền cực cao, càng mặc lâu vải càng có độ sờn tự nhiên rất đẹp. Có thể khoác ngoài áo thun trắng.',380000,16,320000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7ra0g-m6xup55y2nxd67','Áo sơ mi'),
    (NULL,'Áo sơ mi ngắn tay','Áo sơ mi nam ngắn tay là lựa chọn lý tưởng cho những ngày hè nóng bức, mang lại sự mát mẻ mà vẫn giữ được nét lịch sự cần thiết. Thiết kế áo hiện đại với các chi tiết trẻ trung, giúp bạn luôn tự tin trong các hoạt động ngoài trời. Chất liệu vải mỏng nhẹ giúp cơ thể luôn dễ chịu dù phải di chuyển.',390000,15,330000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lws37uqir9i17f','Áo sơ mi'),
    (NULL,'Áo sơ mi dài tay','Áo sơ mi nam dài tay thiết kế thanh lịch, phù hợp cho mọi hoàn cảnh từ đi làm đến tham gia các buổi tiệc sang trọng. Phần tay áo có thể xắn lên gọn gàng để tạo phong cách năng động hoặc cài khuy chỉn chu. Chất liệu vải cao cấp có độ bóng nhẹ, tạo cảm giác sang trọng và đẳng cấp tuyệt đối cho quý ông.',400000,14,340000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lmidjarcyti729','Áo sơ mi'),
    (NULL,'Áo sơ mi form rộng','Áo sơ mi nam form rộng mang phong cách tự do, thoải mái, rất phù hợp với xu hướng thời trang hiện đại của giới trẻ. Thiết kế vai trễ và thân áo rộng rãi không chỉ mang lại sự dễ chịu khi mặc mà còn tạo nên gu thời trang phá cách. Chất liệu vải thô hoặc lanh mềm mại giúp áo có độ rũ tự nhiên, lãng tử.',410000,12,350000,'Áo','https://cf.shopee.vn/file/9de3ec1a314e7dedb10e486ae3761846','Áo sơ mi'),
    (NULL,'Áo sơ mi casual','Chiếc áo sơ mi nam phong cách casual hướng đến sự giản dị và gần gũi trong trang phục hàng ngày. Sản phẩm sử dụng tông màu trầm ấm, nhã nhặn, dễ dàng phối hợp với nhiều loại trang phục khác nhau. Chất vải bền bỉ, dễ giặt ủi và giữ màu tốt theo thời gian, giúp bạn tiết kiệm thời gian chăm sóc đồ.',420000,10,360000,'Áo','https://1557691689.e.cdneverest.net/fast/747x0/filters:format(webp)/static.5sfashion.vn/storage/product/xHffeAY2o6ioPj07ERgtgmMy8fonFH52_cover.jpg','Áo sơ mi'),
    (NULL,'Áo sơ mi thời trang','Áo sơ mi nam thời trang với các chi tiết thiết kế độc đáo, bắt kịp những xu hướng mới nhất trên sàn diễn quốc tế. Sản phẩm là sự kết hợp hoàn hảo giữa chất liệu cao cấp và sự sáng tạo trong kiểu dáng, mang lại vẻ ngoài ấn tượng. Đây là lựa chọn hàng đầu để khẳng định phong cách cá nhân sành điệu.',430000,10,370000,'Áo','https://cf.shopee.vn/file/f8783530bdd81b5e761c048dd46a88fd','Áo sơ mi'),
    (NULL,'Áo khoác hoodie','Áo khoác hoodie nam là biểu tượng của sự năng động và phong cách trẻ trung trong những ngày thời tiết se lạnh. Sản phẩm được làm từ chất liệu nỉ bông dày dặn, ấm áp nhưng vẫn đảm bảo độ thoáng khí. Thiết kế có mũ trùm đầu và túi rộng phía trước vô cùng tiện lợi cho các bạn trẻ dạo phố đi chơi.',480000,30,420000,'Áo','https://cf.shopee.vn/file/0627137e81edb831eecaa95a2472c2b2','Áo khoác'),
    (NULL,'Áo khoác thể thao','Áo khoác nam phong cách thể thao với thiết kế khỏe khoắn và chất liệu vải dù cao cấp, có khả năng chống gió và kháng nước nhẹ. Áo được trang bị hệ thống khóa kéo bền bỉ và các túi khóa an toàn để đựng đồ cá nhân khi tập luyện. Form dáng ôm gọn giúp tôn lên nét mạnh mẽ nhưng vẫn đảm bảo sự linh hoạt.',490000,28,430000,'Áo','https://down-vn.img.susercontent.com/file/b5d5d79b6b6dfec00fa6f5cf449aa73c','Áo khoác'),
    (NULL,'Áo khoác gió','Áo khoác gió nam là trợ thủ đắc lực bảo vệ bạn khỏi những cơn gió lạnh và mưa phùn bất chợt. Sản phẩm siêu nhẹ, có thể dễ dàng gấp gọn lại để bỏ vào balo cực kỳ tiện lợi khi di chuyển. Chất liệu vải gió đặc biệt giúp giữ ấm cơ thể hiệu quả đồng thời vẫn có khả năng thoát hơi ẩm tốt từ bên trong.',500000,25,440000,'Áo','https://down-vn.img.susercontent.com/file/1b79703be7f0a4a2e3a41ff8027dd3c9','Áo khoác'),
    (NULL,'Áo khoác bomber','Áo khoác bomber nam mang lại vẻ ngoài cực kỳ sành điệu và nam tính cho người mặc nhờ thiết kế cổ thấp và bo chun ở gấu áo và tay áo. Sản phẩm được làm từ vải kaki cao cấp với lớp lót mềm mại bên trong. Kiểu dáng bomber cổ điển phối hợp tông màu hiện đại tạo nên item thời trang không lỗi mốt.',520000,22,450000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134208-7ras8-mbjsz30ob7es2d','Áo khoác'),
    (NULL,'Áo khoác jean','Áo khoác jean nam là món đồ thời trang vượt thời gian, mang lại vẻ ngoài bụi bặm, phong trần và đầy cá tính. Chất liệu denim dày dặn, bền bỉ giúp bảo vệ cơ thể tốt và có độ bền màu cao sau nhiều lần giặt. Các chi tiết túi ngực và nút đồng tạo nên nét cổ điển nhưng vẫn vô cùng hiện đại phá cách.',530000,20,460000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134201-7r98o-lmp0abcr5ty780','Áo khoác'),
    (NULL,'Áo sơ mi nam dài tay','Áo sơ mi nam dài tay thiết kế thanh lịch, phù hợp cho mọi hoàn cảnh từ đi làm đến tham gia các buổi tiệc sang trọng. Phần tay áo có thể xắn lên gọn gàng để tạo phong cách năng động hoặc cài khuy chỉn chu cho vẻ ngoài nghiêm túc. Chất liệu vải cao cấp có độ bóng nhẹ, tạo cảm giác sang trọng và đẳng cấp cho người mặc. Đường may sắc sảo cùng form dáng chuẩn giúp che khuyết điểm cơ thể hiệu quả, mang lại sự tự tin tối đa cho phái mạnh khi xuất hiện trước đám đông hay đối tác.',400000,14,340000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lmidjarcyti729','Áo sơ mi'),
    (NULL,'Áo sơ mi nam form rộng','Áo sơ mi nam form rộng mang phong cách tự do, thoải mái, rất phù hợp với xu hướng thời trang hiện đại của giới trẻ hiện nay. Thiết kế vai trễ và thân áo rộng rãi không chỉ mang lại sự dễ chịu tuyệt đối khi mặc mà còn tạo nên gu thời trang phá cách, đầy ấn tượng. Chất liệu vải thô hoặc lanh mềm mại giúp áo có độ rũ tự nhiên, trông rất lãng tử và cuốn hút người đối diện. Đây là món đồ cực kỳ linh hoạt, có thể mặc đi học, đi làm trong các môi trường sáng tạo hoặc diện đi chơi cùng bạn bè vào những buổi tối cuối tuần đầy thú vị và phong cách.',410000,12,350000,'Áo','https://cf.shopee.vn/file/9de3ec1a314e7dedb10e486ae3761846','Áo sơ mi'),
    (NULL,'Áo sơ mi nam casual','Chiếc áo sơ mi nam phong cách casual hướng đến sự giản dị và gần gũi trong trang phục hàng ngày của phái mạnh. Sản phẩm sử dụng tông màu trầm ấm, nhã nhặn, giúp người mặc dễ dàng phối hợp với nhiều loại quần và phụ kiện khác nhau mà không lo lỗi mốt. Chất vải bền bỉ, dễ giặt ủi và giữ màu tốt theo thời gian, giúp bạn tiết kiệm tối đa thời gian chăm sóc quần áo mỗi ngày. Áo phù hợp cho những người yêu thích sự đơn giản nhưng vẫn muốn giữ được nét lịch thiệp, phong độ trong mọi hoàn cảnh giao tiếp thông thường hay các buổi gặp gỡ thân mật.',420000,10,360000,'Áo','https://static.5sfashion.vn/storage/product/xHffeAY2o6ioPj07ERgtgmMy8fonFH52_cover.jpg','Áo sơ mi'),
    (NULL,'Áo sơ mi nam thời trang','Áo sơ mi nam thời trang với các chi tiết thiết kế độc đáo, bắt kịp những xu hướng mới nhất trên các sàn diễn quốc tế hiện nay. Sản phẩm là sự kết hợp hoàn hảo giữa chất liệu vải cao cấp và sự sáng tạo đột phá trong kiểu dáng, mang lại vẻ ngoài ấn tượng và đầy sức hút cho người mặc. Từng điểm nhấn trên cổ áo, măng sét hay cúc áo đều được chăm chút kỹ lưỡng để tạo nên sự khác biệt hoàn toàn so với các dòng áo phổ thông. Đây chính là lựa chọn hàng đầu cho những quý ông muốn khẳng định phong cách thời trang cá nhân riêng biệt và sành điệu của mình.',430000,10,370000,'Áo','https://cf.shopee.vn/file/f8783530bdd81b5e761c048dd46a88fd','Áo sơ mi'),
    (NULL,'Áo khoác hoodie nam','Áo khoác hoodie nam là biểu tượng của sự năng động và phong cách trẻ trung trong những ngày thời tiết bắt đầu chuyển se lạnh. Sản phẩm được làm từ chất liệu nỉ bông dày dặn, ấm áp nhưng vẫn đảm bảo độ thoáng khí tối ưu để người mặc không cảm thấy bí bách khi vận động nhiều. Thiết kế có mũ trùm đầu và túi rộng phía trước vô cùng tiện lợi cho việc giữ ấm đôi bàn tay. Form dáng rộng rãi giúp bạn dễ dàng mặc thêm áo bên trong mà không lo chật chội. Đây là trang phục hoàn hảo cho các buổi đi chơi, dạo phố hay tham gia các hoạt động ngoại khóa đầy sôi động.',480000,30,420000,'Áo','https://cf.shopee.vn/file/0627137e81edb831eecaa95a2472c2b2','Áo khoác'),
    (NULL,'Áo khoác thể thao','Áo khoác nam phong cách thể thao với thiết kế khỏe khoắn và chất liệu vải dù cao cấp, có khả năng chống gió và kháng nước nhẹ cực kỳ hiệu quả. Áo được trang bị hệ thống khóa kéo bền bỉ và các túi khóa an toàn để bạn yên tâm đựng đồ cá nhân khi tập luyện cường độ cao. Form dáng ôm gọn giúp tôn lên nét mạnh mẽ nhưng vẫn đảm bảo sự linh hoạt tối đa trong mọi cử động hàng ngày. Sản phẩm rất phù hợp để khoác bên ngoài khi đi tập gym, chạy bộ buổi sáng hoặc mặc như một chiếc áo gió hàng ngày giúp bảo vệ sức khỏe của bạn một cách tối ưu nhất.',490000,28,430000,'Áo','https://down-vn.img.susercontent.com/file/b5d5d79b6b6dfec00fa6f5cf449aa73c','Áo khoác'),
    (NULL,'Áo khoác gió ','Áo khoác gió nam là trợ thủ đắc lực bảo vệ bạn khỏi những cơn gió lạnh và mưa phùn bất chợt trong những ngày thời tiết giao mùa. Sản phẩm có đặc điểm siêu nhẹ, có thể dễ dàng gấp gọn lại để bỏ vào balo cực kỳ tiện lợi khi di chuyển xa hoặc đi phượt. Chất liệu vải gió đặc biệt giúp giữ ấm cơ thể hiệu quả đồng thời vẫn có khả năng thoát hơi ẩm tốt từ bên trong, không gây cảm giác khó chịu. Thiết kế hiện đại với màu sắc thời trang, phù hợp cho mọi độ tuổi và phong cách. Đây là món đồ không thể thiếu trong mỗi chuyến đi khám phá vùng đất mới.',500000,25,440000,'Áo','https://down-vn.img.susercontent.com/file/1b79703be7f0a4a2e3a41ff8027dd3c9','Áo khoác'),
    (NULL,'Áo khoác bomber nam','Áo khoác bomber nam mang lại vẻ ngoài cực kỳ sành điệu và nam tính cho người mặc nhờ thiết kế cổ thấp và bo chun ở gấu áo cũng như tay áo. Sản phẩm được làm từ vải kaki hoặc nỉ cao cấp với lớp lót mềm mại bên trong, tạo cảm giác vô cùng thoải mái khi sử dụng thời gian dài. Kiểu dáng bomber cổ điển phối hợp cùng các tông màu hiện đại tạo nên một item thời trang không bao giờ lỗi mốt trong tủ đồ của phái mạnh. Bạn có thể phối chiếc áo này cùng áo thun và quần jean để tạo nên phong cách trẻ trung, mạnh mẽ và vô cùng thu hút khi ra ngoài dạo phố.',520000,22,450000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134208-7ras8-mbjsz30ob7es2d','Áo khoác'),
    (NULL,'Áo khoác jean ','Áo khoác jean nam là món đồ thời trang vượt thời gian, mang lại vẻ ngoài bụi bặm, phong trần và đầy cá tính cho người sở hữu. Chất liệu denim dày dặn, bền bỉ giúp bảo vệ cơ thể tốt và có độ bền màu cao ngay cả sau nhiều lần giặt giũ. Các chi tiết túi ngực và nút đồng đặc trưng tạo nên nét cổ điển nhưng vẫn vô cùng hiện đại, phù hợp với xu hướng streetwear. Chiếc áo này cực kỳ dễ phối đồ, bạn có thể khoác bên ngoài bất kỳ loại áo thun hay sơ mi nào cũng đều mang lại diện mạo ấn tượng và phóng khoáng cho bản thân mình trong mọi dịp.',530000,20,460000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134201-7r98o-lmp0abcr5ty780','Áo khoác'),
    (NULL,'Áo phao lót lông','Áo khoác dành riêng cho mùa đông giá rét với lớp lót bông dày hoặc lông vũ siêu ấm, giúp bạn tự tin đối phó với những đợt rét đậm rét hại. Thiết kế áo thường có thêm lớp vải chống gió bên ngoài và cổ áo cao để bảo vệ vùng cổ khỏi không khí lạnh xâm nhập. Dù có khả năng giữ ấm cực tốt nhưng áo vẫn đảm bảo được tính thời trang với form dáng gọn gàng, không gây cảm giác nặng nề hay thô kệch cho người mặc. Từng chi tiết khóa kéo, khuy bấm đều được hoàn thiện tinh xảo, mang lại một sản phẩm chất lượng cao và bền bỉ suốt nhiều mùa đông dài.',540000,18,470000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-m37sokqhhgx872','Áo khoác'),
    (NULL,'Áo khoác nam basic','Áo khoác nam thiết kế theo phong cách basic hướng đến sự đơn giản tối đa nhưng không hề đơn điệu, phù hợp cho mọi hoàn cảnh giao tiếp hàng ngày. Sản phẩm sử dụng chất liệu vải mềm mại, có khả năng giữ ấm vừa phải, rất thích hợp mặc trong tiết trời thu đông se lạnh hoặc những ngày xuân ấm áp. Màu sắc trung tính chủ đạo giúp bạn dễ dàng kết hợp áo cùng các trang phục khác sẵn có trong tủ đồ cá nhân. Đây là lựa chọn thông minh cho những ai yêu thích phong cách thời trang bền vững, thanh lịch và luôn giữ được vẻ ngoài chỉn chu dù xuất hiện ở bất cứ đâu.',550000,16,480000,'Áo','https://static.5sfashion.vn/storage/product/Irf4u5X6BEiDX3Y9v93x8a2H0moMgPG8_cover.jpg','Áo khoác'),
    (NULL,'Áo khoác local brand','Áo khoác từ thương hiệu nội địa local brand với những thiết kế sáng tạo độc bản, không trùng lặp, thể hiện rõ phong cách riêng biệt của giới trẻ Việt Nam. Chất lượng sản phẩm được khẳng định qua từng đường kim mũi chỉ sắc sảo và chất liệu vải được tuyển chọn cực kỳ khắt khe từ nhà sản xuất. Mỗi bộ sưu tập áo khoác đều mang một câu chuyện hay thông điệp riêng, giúp người mặc tự tin khẳng định bản thân và thể hiện sự am hiểu về thời trang. Sản phẩm được hoàn thiện chỉn chu từ nhãn mác đến bao bì, mang lại trải nghiệm mua sắm đẳng cấp và niềm tự hào dân tộc.',560000,15,490000,'Áo','https://bizweb.dktcdn.net/100/348/395/files/ao-khoac-unisex.jpg?v=1594797493285','Áo khoác'),
    (NULL,'Áo khoác nam form rộng','Áo khoác nam form rộng là sự kết hợp hoàn hảo giữa sự thoải mái tối đa và phong cách thời trang hiện đại phóng khoáng của giới trẻ. Thiết kế áo rộng rãi giúp người mặc không bị gò bó, cực kỳ dễ chịu khi vận động mạnh, chơi thể thao hay di chuyển nhiều. Chất vải thường là kaki hoặc nỉ dày dặn, tạo nên form áo đứng dáng và rất đẹp mắt khi nhìn từ bên ngoài. Chiếc áo này là item lý tưởng để diện theo phong cách layering nhiều lớp, tạo nên diện mạo có chiều sâu và cá tính nổi bật cho bạn nam trong các buổi tụ tập cùng bạn bè hay dạo phố cuối tuần.',570000,14,500000,'Áo','https://tse2.mm.bing.net/th/id/OIP.mgCsnLrHyJj4iQU-dBWkgQHaHa?pid=Api&P=0&h=180','Áo khoác'),
    (NULL,'Áo khoác streetwear','Áo khoác nam mang đậm hơi thở thời trang đường phố với các họa tiết graphic hoặc slogan in nổi bật và đầy ấn tượng ở mặt trước và sau. Sản phẩm là sự lựa chọn số một cho những chàng trai muốn phá cách và không ngại thể hiện cái tôi cá nhân mạnh mẽ của mình trước đám đông. Từng chi tiết khóa kéo trang trí hay các đường cắt may không đối xứng đều được tính toán kỹ lưỡng để tạo nên vẻ ngoài ấn tượng nhất. Áo phối hợp cực kỳ ăn ý với quần túi hộp cargo pants và những đôi giày sneaker cổ cao, mang lại phong cách streetwear đúng chuẩn và thời thượng.',590000,12,520000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7ra0g-m6hp62zzdys857','Áo khoác'),
    (NULL,'Chuột văn phòng','Chuột văn phòng cao cấp được thiết kế tối ưu cho các công việc hành chính và văn phòng hàng ngày với kích thước vừa vặn và độ nhạy mắt đọc cực kỳ ổn định. Sản phẩm hỗ trợ tốt cho các tác vụ như duyệt văn bản, xử lý bảng tính Excel và lướt web mượt mà không bị giật lag. Nút bấm của chuột có độ nảy rất tốt nhưng hoàn toàn không gây tiếng ồn lớn, giúp giữ không gian làm việc yên tĩnh cho những người xung quanh. Chất liệu nhựa ABS cao cấp có bề mặt chống bám mồ hôi hiệu quả, giúp bạn sử dụng liên tục trong nhiều giờ mà vẫn cảm thấy thoải mái và sạch sẽ.',300000,50,250000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lskya82qy8bd02','Chuột'),
    (NULL,'Bàn phím giả cơ','Bàn phím giả cơ là sự lựa chọn tuyệt vời cho những ai muốn trải nghiệm cảm giác gõ phím đặc trưng của bàn phím cơ nhưng với mức giá dễ tiếp cận hơn rất nhiều. Các phím bấm được thiết kế cao, mang lại hành trình phím sâu và tiếng click nhẹ nhàng đầy phấn khích khi làm việc hay chơi game. Hệ thống đèn LED nền rực rỡ với nhiều hiệu ứng màu sắc giúp bạn làm việc hay giải trí hiệu quả hơn trong môi trường thiếu sáng. Sản phẩm có độ bền cao, tích hợp các phím tắt đa phương tiện tiện lợi, là phụ kiện không thể thiếu để nâng cấp góc học tập của bạn.',1050000,20,890000,'Thiết bị','https://cf.shopee.vn/file/vn-11134207-7qukw-lj6xcv089vrgec','Bàn phím'),
    (NULL,'Bàn phím gaming','Bàn phím gaming chuyên dụng với các phím bấm có độ phản hồi cực nhanh, giúp game thủ thực hiện các thao tác combo trong trò chơi một cách chính xác tuyệt đối và nhanh chóng. Hệ thống đèn LED RGB đa dạng chế độ màu sắc tùy chỉnh tạo nên không gian giải trí đầy cảm hứng và chuyên nghiệp cho góc máy của bạn. Sản phẩm hỗ trợ tính năng anti-ghosting cho phép nhận diện nhiều phím nhấn cùng lúc mà không bị xung đột tín hiệu. Thiết kế chắc chắn, chống trượt trên bề mặt bàn, đảm bảo độ ổn định cao nhất trong những trận đấu kịch tính và căng thẳng nhất.',1100000,25,920000,'Thiết bị','https://tse2.mm.bing.net/th/id/OIP.xp0OCtX4NI8eowZAA0zC-wHaHa?pid=Api&P=0&h=180','Bàn phím'),
    (NULL,'Bàn phím bluetooth logitech','Bàn phím Bluetooth mang lại sự gọn gàng tuyệt đối cho không gian làm việc của bạn bằng cách loại bỏ hoàn toàn các loại dây cắm rườm rà và vướng víu. Sản phẩm có khả năng kết nối không dây ổn định với laptop, máy tính bảng và cả điện thoại di động thông minh chỉ bằng vài thao tác đơn giản. Thiết kế mỏng nhẹ, sang trọng giúp bạn dễ dàng cất vào balo để mang theo làm việc tại quán cà phê hay đi công tác xa. Phím bấm êm ái, công nghệ tiết kiệm pin tối ưu giúp bạn yên tâm sử dụng trong nhiều tuần chỉ với một lần sạc đầy, tăng hiệu suất làm việc.',880000,30,760000,'Thiết bị','https://cf.shopee.vn/file/sg-11134201-22100-i2h29b52llivbc','Bàn phím'),
    (NULL,'Bình nước thể thao','Bình nước thể thao được làm từ nhựa cao cấp hoàn toàn không chứa chất gây ung thư BPA, đảm bảo an toàn tuyệt đối cho sức khỏe của người sử dụng hàng ngày. Thiết kế bình có nắp đậy thông minh chống rò rỉ nước, tích hợp thêm quai xách tiện lợi để mang theo khi đi tập gym, đạp xe hay chạy bộ buổi sáng. Thân bình có vạch chia dung tích rõ ràng giúp bạn dễ dàng theo dõi lượng nước đã uống hàng ngày để đảm bảo sức khỏe. Miệng bình rộng cho phép bạn thêm đá viên dễ dàng, giúp thức uống luôn mát lạnh, mang lại cảm giác sảng khoái sau vận động.',240000,50,190000,'Gia dụng','https://aolikessports.com/wp-content/uploads/2022/10/A-SC1500-1.jpg','Bình nước'),
    (NULL,'Bình giữ nhiệt inox','Bình giữ nhiệt chất liệu inox 304 hai lớp cao cấp với lớp chân không ở giữa giúp giữ nhiệt cho đồ uống cực kỳ hiệu quả trong suốt 12 giờ liên tục. Sản phẩm không chỉ giữ ấm cực tốt cho trà, cà phê mà còn giữ lạnh tuyệt vời cho các loại nước ép trái cây hay sinh tố trong mùa hè nóng nực. Vỏ ngoài được sơn tĩnh điện bền màu, chống trầy xước và mang lại vẻ ngoài tinh tế, hiện đại cho người sử dụng. Với kích thước vừa vặn, bình dễ dàng đặt trong khay đựng nước của ô tô hoặc túi hông balo, là món quà sức khỏe ý nghĩa cho người thân.',350000,30,290000,'Gia dụng','https://images.unsplash.com/photo-1602143407151-7111542de6e8','Bình nước'),
    (NULL,'Bình pha trà','Bình pha trà được thiết kế chuyên dụng với lõi lọc bằng thép không gỉ giúp lọc sạch hoàn toàn bã trà, mang lại những tách trà thơm ngon và tinh khiết nhất cho bạn. Thân bình được làm bằng thủy tinh chịu nhiệt cao cấp, cho phép bạn quan sát quá trình lá trà nở ra vô cùng đẹp mắt và thư giãn. Nắp bình đậy kín giúp giữ trọn vẹn hương vị đặc trưng và độ ấm nóng của trà trong thời gian dài sau khi pha. Đây là vật dụng tuyệt vời để bạn thưởng thức những giây phút nghỉ ngơi bên tách trà yêu thích tại văn phòng làm việc hoặc trong không gian gia đình.',270000,35,220000,'Gia dụng','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lk9q23tlesnw2f','Bình nước'),
    (NULL,'Nồi cơm điện Sharp','Nồi cơm điện Sharp nổi tiếng với công nghệ nấu nhiệt độ 3D tiên tiến giúp hạt cơm chín đều từ mọi phía, tơi xốp và giữ trọn dưỡng chất quý giá từ hạt gạo. Lòng nồi được phủ lớp chống dính cao cấp theo tiêu chuẩn Nhật Bản, ngăn chặn cơm bám dính và giúp việc vệ sinh trở nên vô cùng nhanh chóng sau khi sử dụng. Thiết kế nồi hiện đại, màu sắc trang nhã phù hợp với mọi không gian bếp từ cổ điển đến hiện đại. Ngoài nấu cơm, bạn còn có thể sử dụng nồi để hấp bánh, nấu cháo rất tiện lợi cho gia đình. Đây là người bạn đồng hành tin cậy cho mỗi bữa cơm.',1050000,20,890000,'Gia dụng','https://mediamart.vn/images/uploads/2024/cc384e28-72ae-49a3-b4a1-3e7b1dd4a69f.jpg','Nồi cơm điện'),
    (NULL,'Ấm siêu tốc Philips','Ấm siêu tốc Philips giúp bạn có ngay nước nóng để pha trà, cà phê hay nấu mì tôm chỉ sau vài phút ngắn ngủi nhờ công suất hoạt động mạnh mẽ. Thân ấm làm từ chất liệu cao cấp chống bỏng và có độ bền cực cao trong suốt quá trình sử dụng lâu dài. Hệ thống ngắt điện tự động khi nước đạt độ sôi hoặc khi ấm cạn nước đảm bảo an toàn tuyệt đối cho người dùng, phòng chống các nguy cơ cháy nổ trong ngôi nhà bạn. Đế xoay 360 độ thông minh giúp việc nhấc ấm và đặt ấm trở nên dễ dàng từ mọi góc độ khác nhau. Đây là thiết bị không thể thiếu trong gian bếp.',520000,30,450000,'Gia dụng','https://bizweb.dktcdn.net/thumb/1024x1024/100/364/851/products/2-am-sieu-toc-philips-hd933980.jpg','Ấm siêu tốc'),
    (NULL,'Quạt điện Panasonic','Quạt điện Panasonic mang đến luồng gió mát tự nhiên, êm ái nhờ thiết kế cánh quạt tối ưu hóa khí động học và động cơ vận hành bền bỉ theo năm tháng. Sản phẩm được trang bị nhiều mức độ gió khác nhau từ nhẹ đến mạnh cùng chức năng hẹn giờ thông minh, mang lại sự tiện lợi và tiết kiệm điện năng đáng kể cho gia đình bạn. Lồng quạt được thiết kế đan khít vô cùng chắc chắn, đảm bảo an toàn tuyệt đối cho trẻ nhỏ khi vô tình tiếp cận. Với kiểu dáng thanh lịch và hiện đại, chiếc quạt này không chỉ làm mát mà còn là điểm nhấn thẩm mỹ cho căn phòng.',820000,25,720000,'Gia dụng','https://bizweb.dktcdn.net/thumb/1024x1024/100/340/518/products/untitled-1-recovered.jpg','Quạt điện'),
    (NULL,'Máy xay sinh tố','Máy xay sinh tố đa năng với lưỡi dao bằng thép không gỉ cực kỳ sắc bén có khả năng xay nhuyễn mọi loại trái cây, rau củ và cả đá viên cứng trong tích tắc. Cối xay được làm bằng nhựa cao cấp chịu lực tốt, không chứa các chất độc hại, đảm bảo an toàn vệ sinh thực phẩm tuyệt đối cho gia đình bạn. Sản phẩm tích hợp nhiều tốc độ xay khác nhau và chế độ nhồi tiện dụng giúp bạn dễ dàng chế biến được những ly sinh tố thơm ngon, bổ dưỡng hàng ngày. Thiết kế chân đế chống trượt giúp máy luôn vận hành ổn định, không bị rung lắc hay gây tiếng ồn lớn.',650000,18,560000,'Gia dụng','https://toplist.vn/images/800px/may-xay-sinh-to-da-nang-sunhouse-shd5322-1066512.jpg','Máy xay'),
    (NULL,'Bếp điện từ mini','Bếp điện từ mini là giải pháp nấu nướng cực kỳ nhanh chóng, an toàn và tiết kiệm diện tích cho các căn hộ nhỏ, chung cư mini hoặc các bạn sinh viên ở trọ. Bếp sử dụng công nghệ cảm ứng từ hiện đại giúp làm nóng đáy nồi nhanh tức thì mà không tỏa nhiệt dư thừa ra môi trường xung quanh, giữ cho không gian bếp luôn mát mẻ. Mặt kính cường lực chịu nhiệt cao, sáng bóng và cực kỳ dễ dàng lau chùi sau mỗi lần sử dụng xong. Nhiều chế độ nấu cài đặt sẵn như lẩu, xào, súp giúp bạn chế biến đa dạng món ăn một cách dễ dàng chỉ với một vài thao tác.',900000,22,780000,'Gia dụng','https://down-vn.img.susercontent.com/file/vn-11134207-820l4-mdzu7rvrnhmv80','Bếp điện'),
    (NULL,'Máy sấy tóc','Máy sấy tóc là thiết bị gia dụng cực kỳ tiện lợi giúp làm khô tóc nhanh chóng và tạo kiểu tóc dễ dàng ngay sau khi gội đầu. Sản phẩm được thiết kế nhỏ gọn, trọng lượng nhẹ giúp người dùng dễ dàng sử dụng và mang theo bên mình khi đi du lịch hoặc công tác. Công suất hoạt động ổn định giúp sấy khô tóc hiệu quả nhưng vẫn hạn chế tối đa việc làm khô xơ hay hư tổn mái tóc của bạn. Máy tích hợp nhiều chế độ nhiệt và gió khác nhau, phù hợp cho cả gia đình từ người lớn đến trẻ nhỏ. Đây là thiết bị cần thiết giúp bạn chăm sóc mái tóc mỗi ngày.',460000,20,390000,'Gia dụng','https://tse3.mm.bing.net/th/id/OIP.2NqhX0EbpMXC49uZTvCAmgHaHa?pid=Api&P=0&h=180','Máy sấy'),
    (NULL,'Bàn ủi hơi nước','Bàn ủi hơi nước cao cấp giúp quần áo của bạn luôn phẳng phiu, sạch sẽ và gọn gàng trước khi đi học, đi làm hoặc tham gia các sự kiện quan trọng. Nhờ công nghệ phun hơi nước mạnh mẽ, sản phẩm có thể làm mềm sợi vải nhanh chóng và loại bỏ các nếp nhăn cứng đầu một cách vô cùng hiệu quả. Thiết kế tay cầm chắc chắn kết hợp với mặt đế chống dính giúp người dùng thao tác dễ dàng và an toàn trên mọi bề mặt vải. Bàn ủi phù hợp cho nhiều loại vải khác nhau như cotton, lụa hay vải tổng hợp, giúp bảo vệ và giữ form dáng quần áo luôn như mới.',600000,18,520000,'Gia dụng','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lss0l4rzmqx092','Bàn ủi'),
    (NULL,'Máy lọc không khí ','Máy lọc không khí là thiết bị cực kỳ hữu ích giúp cải thiện chất lượng môi trường sống và bảo vệ hệ hô hấp cho các thành viên trong gia đình bạn. Sản phẩm có khả năng lọc sạch bụi mịn PM2.5, phấn hoa, các loại nấm mốc và một số tạp chất có hại trong không khí, mang lại môi trường sống trong lành và tươi mới hơn. Máy rất phù hợp sử dụng trong phòng ngủ, phòng làm việc hoặc phòng khách có diện tích vừa và nhỏ. Thiết kế hiện đại, tinh tế cùng khả năng vận hành êm ái giúp người dùng cảm thấy dễ chịu và thư giãn tuyệt đối khi sử dụng.',1250000,12,1100000,'Gia dụng','https://airsafe.vn/wp-content/uploads/2023/04/airsafe-may-loc-khong-khi-la-gi-9.jpg','Máy lọc'),
    (NULL,'Cân tiểu ly','Cân tiểu ly điện tử là thiết bị đo lường nhỏ gọn nhưng vô cùng mạnh mẽ, giúp đo lường trọng lượng với độ chính xác cực cao cho nhiều mục đích khác nhau. Sản phẩm thường được các bà nội trợ sử dụng trong nhà bếp để cân chính xác nguyên liệu nấu ăn, làm bánh hoặc trong các công việc cần độ chi tiết cao như cân vàng, bạc, thảo dược. Màn hình hiển thị LCD rõ nét với đèn nền giúp người dùng dễ dàng theo dõi kết quả đo ngay cả trong bóng tối. Thiết kế mỏng nhẹ giúp bạn dễ dàng mang theo bên mình hoặc cất giữ gọn gàng trong ngăn kéo.',290000,25,240000,'Gia dụng','https://cf.shopee.vn/file/3c870ca00f1a5e519b696283d163a337','Cân điện tử'),
    (NULL,'Máy hút bụi mini','Máy hút bụi mini cầm tay là thiết bị vệ sinh hiện đại và tiện lợi, giúp bạn dễ dàng làm sạch hoàn toàn bụi bẩn trong các không gian nhỏ hẹp như bàn làm việc, khe ghế sofa hay nội thất ô tô. Thiết kế cực kỳ nhỏ gọn giúp người dùng dễ dàng cầm nắm bằng một tay và di chuyển linh hoạt đến mọi vị trí cần làm sạch. Máy sở hữu lực hút ổn định và mạnh mẽ giúp loại bỏ bụi, lông thú cưng và các mảnh vụn nhỏ một cách nhanh chóng nhất. Đây là giải pháp hoàn hảo cho những ai muốn giữ không gian sống và làm việc luôn luôn sạch sẽ, ngăn nắp.',850000,15,760000,'Gia dụng','https://down-vn.img.susercontent.com/file/sg-11134201-22120-ocig7s06tplvdc','Máy hút bụi'),
    (NULL,'Túi chống sốc laptop','Túi chống sốc laptop là phụ kiện bắt buộc phải có để bảo vệ chiếc máy tính đắt tiền của bạn khỏi những vết trầy xước không đáng có và các chấn động mạnh khi di chuyển. Sản phẩm được làm từ chất liệu vải lặn dẻo dai kết hợp với lớp lót nhung siêu mềm mại bên trong giúp ôm sát máy tính và giảm thiểu lực va đập. Thiết kế mỏng nhẹ, tối giản tạo cảm giác gọn gàng nhưng vẫn đảm bảo độ an toàn tối đa cho thiết bị bên trong. Khóa kéo kép mượt mà giúp bạn thao tác lấy máy ra vào một cách nhanh chóng và thuận tiện mỗi khi cần sử dụng.',240000,50,190000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lq8zb94o9vpudd','Túi laptop'),
    (NULL,'Miếng lót chuột gaming','Miếng lót chuột gaming kích thước lớn mang lại diện tích di chuột cực kỳ thoải mái cho game thủ, đặc biệt phù hợp cho các tựa game yêu cầu độ nhạy chuột thấp và diện tích thao tác rộng. Bề mặt vải được dệt bằng công nghệ tinh xảo giúp các loại chuột quang và chuột laser có thể nhận diện chính xác từng pixel chuyển động, mang lại lợi thế lớn trong thi đấu. Đế bằng cao su tự nhiên có độ bám dính cực tốt trên mặt bàn, hoàn toàn không bị trượt khi thao tác mạnh. Các mép của lót chuột được may bo viền chắc chắn, chống bong tróc sau thời gian dài sử dụng.',190000,45,150000,'Phụ kiện','https://tse3.mm.bing.net/th/id/OIP.aOfl1nbCm80-Rbg0DcJazAHaHa?pid=Api&P=0&h=180','Lót chuột'),
    (NULL,'Bóng đá tiêu chuẩn','Bóng đá đạt tiêu chuẩn thi đấu quốc tế với thiết kế 32 miếng ghép vô cùng chắc chắn, mang lại quỹ đạo bay ổn định và độ nảy cực chuẩn trên mọi mặt sân cỏ tự nhiên hay nhân tạo. Chất liệu da tổng hợp cao cấp có khả năng chống thấm nước tuyệt đối và chịu được sự mài mòn cao trong điều kiện thời tiết khắc nghiệt. Van khí được thiết kế đặc biệt giúp giữ hơi cực tốt, bạn không cần phải bơm bóng thường xuyên trước mỗi trận đấu. Đây là món đồ thể thao lý tưởng để bạn rèn luyện sức khỏe, nâng cao kỹ thuật cá nhân và tận hưởng niềm vui cùng bạn bè.',330000,40,280000,'Thể thao','https://yousport.vn/Media/Products/231216100629/qua-bong-da-tieu-chuan-fifa-uhv-2-07.jpg','Bóng đá'),
    (NULL,'Vợt cầu lông Yonex','Vợt cầu lông Yonex chính hãng sở hữu khung vợt được chế tạo từ chất liệu carbon siêu nhẹ, mang lại sự linh hoạt tối đa cho người chơi trong từng cú đập uy lực hay những pha bỏ nhỏ tinh tế. Công nghệ giảm chấn tiên tiến tích hợp trên khung vợt giúp bảo vệ cổ tay người chơi khỏi những tác động lực mạnh đột ngột, giảm thiểu tối đa nguy cơ chấn thương. Vợt có độ căng dây tốt, khả năng chịu lực cao mang lại sức mạnh vượt trội cho các pha tấn công. Đây là sự lựa chọn hàng đầu cho những ai đam mê cầu lông muốn nâng cao trình độ và kỹ năng thi đấu chuyên nghiệp.',750000,18,650000,'Thể thao','https://bissport.com/uploads/images/product/detail/2023/12/2023-11-12-11-02-201vot-cau-long.jpg','Vợt cầu lông'),
    (NULL,'Dây nhảy thể dục','Dây nhảy thể dục là công cụ tập luyện cardio tuyệt vời giúp bạn đốt cháy calo một cách nhanh chóng và tăng cường sức bền hệ tim mạch hiệu quả ngay tại nhà mà không cần ra phòng tập. Sợi dây được làm từ chất liệu PVC dẻo dai kết hợp với lõi thép chắc chắn bên trong, đảm bảo tốc độ quay nhanh, mượt mà và hoàn toàn không bị xoắn rối khi tập luyện. Tay cầm bọc mút êm ái, thấm hút mồ hôi tốt giúp bạn cầm nắm chắc chắn trong suốt quá trình vận động. Bạn có thể dễ dàng điều chỉnh độ dài của dây cho phù hợp với chiều cao cá nhân của mình.',120000,60,90000,'Thể thao','https://thethaominhphu.com/wp-content/uploads/2022/06/Day-nhay-2.jpg','Dây nhảy'),
    (NULL,'Thảm tập yoga','Thảm tập yoga được làm từ chất liệu TPE cao cấp mang lại độ đàn hồi tuyệt vời và khả năng chống trơn trượt tối ưu cho người tập ngay cả trong những tư thế khó nhất. Thảm hoàn toàn không chứa các chất gây độc hại, thân thiện với môi trường và cực kỳ an toàn cho làn da nhạy cảm của bạn. Độ dày lý tưởng của thảm giúp bảo vệ tối đa các khớp xương và đầu gối khỏi những va chạm trực tiếp với sàn nhà cứng, mang lại cảm giác êm ái và sự tập trung tối đa cho buổi tập. Thảm dễ dàng cuộn lại gọn gàng và vệ sinh sau khi sử dụng xong mỗi ngày.',420000,25,350000,'Thể thao','https://down-vn.img.susercontent.com/file/d8373b73d2684e0e4acb92e1c2c2795d','Thảm yoga'),
    (NULL,'Sổ tay ghi chép','Cuốn sổ tay ghi chép nhỏ gọn chính là trợ thủ đắc lực giúp bạn lưu lại mọi ý tưởng sáng tạo hay danh sách công việc cần làm một cách nhanh chóng và đầy đủ nhất. Bìa sổ được làm từ giấy kraft cứng cáp hoặc bìa da tinh tế, mang lại phong cách cổ điển đầy cảm hứng cho người sử dụng. Chất lượng giấy bên trong mịn màng, màu vàng nhạt giúp bảo vệ mắt khỏi mỏi và không bị lóa khi viết dưới ánh đèn điện. Sổ có thiết kế đơn giản, thanh lịch, rất phù hợp để mang theo trong túi xách hay balo khi đi học, đi làm hoặc tham gia các buổi họp quan trọng.',60000,80,45000,'Văn phòng','https://cf.shopee.vn/file/4776c51dde15cb3d9f54f26b4537404b','Sổ tay'),
    (NULL,'Bút bi cao cấp','Bút bi cao cấp với thiết kế thân kim loại sang trọng, mang lại cảm giác cầm đầm tay và vô cùng chắc chắn cho người sử dụng khi viết hoặc ký tên. Mực bút đều màu, khô nhanh và hoàn toàn không gây hiện tượng tắc mực hay lem giấy, giúp nét chữ của bạn luôn rõ ràng và chuyên nghiệp nhất có thể. Đầu bi làm từ hợp kim siêu bền giúp thao tác viết lách trở nên mượt mà, êm ái trên mọi loại bề mặt giấy khác nhau. Đây là món quà tặng vô cùng ý nghĩa dành cho doanh nhân, giáo viên hoặc đồng nghiệp trong các dịp lễ quan trọng của năm.',35000,100,25000,'Văn phòng','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ln81leam7x08d2','Bút bi'),
    (NULL,'Hộp bút học sinh','Hộp bút học sinh đa năng giúp các bạn trẻ sắp xếp gọn gàng toàn bộ dụng cụ học tập thiết yếu như bút viết, thước kẻ, compa và gôm tẩy vào một nơi duy nhất. Sản phẩm được làm từ chất liệu vải canvas bền đẹp hoặc nhựa cao cấp có khả năng chống va đập vô cùng hiệu quả. Thiết kế nhiều ngăn chứa thông minh cùng các họa tiết trẻ trung, bắt mắt tạo thêm nguồn cảm hứng học tập mỗi ngày cho các bạn học sinh. Khóa kéo trơn tru, bền bỉ giúp bảo vệ đồ dùng bên trong không bị rơi mất khi di chuyển, rất tiện lợi để bỏ vào cặp sách đi học.',110000,60,85000,'Văn phòng','https://tuitotegiare.com/wp-content/uploads/2021/05/hop-dung-but-12.jpg','Hộp bút'),
    (NULL,'Máy tính cầm tay Casio','Máy tính cầm tay Casio là công cụ tính toán có độ chính xác tuyệt đối, hỗ trợ đắc lực cho các bạn học sinh sinh viên trong các kỳ thi toán học và kỹ thuật quan trọng nhất. Sản phẩm tích hợp hàng trăm tính năng tính toán thông minh từ cơ bản đến phức tạp như giải phương trình, tính tích phân và các hàm lượng giác chuyên sâu. Màn hình hiển thị lớn, sắc nét giúp người dùng dễ dàng quan sát kết quả trong mọi điều kiện ánh sáng khác nhau. Phím bấm có độ nảy tốt, bền bỉ cùng thời lượng pin sử dụng cực lâu giúp bạn hoàn toàn yên tâm khi sử dụng.',380000,30,320000,'Văn phòng','https://vn-test-11.slatic.net/p/35007d2d10364116693a654557e8818f.jpg','Máy tính'),
    (NULL,'Kẹp tài liệu văn phòng','Kẹp tài liệu văn phòng giúp bạn sắp xếp và quản lý các loại giấy tờ, hồ sơ một cách khoa học và chuyên nghiệp nhất trong môi trường làm việc bận rộn. Sản phẩm được làm từ thép cao cấp có độ đàn hồi cực tốt, giữ chặt giấy tờ mà hoàn toàn không làm rách hay biến dạng các góc giấy. Bề mặt kẹp được sơn tĩnh điện chống gỉ sét hiệu quả, đảm bảo độ bền màu theo thời gian sử dụng lâu dài. Nhiều kích cỡ khác nhau giúp bạn linh hoạt kẹp từ vài tờ giấy mỏng đến cả một xấp tài liệu dày. Đây là vật dụng không thể thiếu giúp bàn làm việc của bạn luôn gọn gàng.',45000,90,30000,'Văn phòng','https://down-vn.img.susercontent.com/file/sg-11134201-22110-tmq4wcd0ozjve2','Kẹp giấy'),
