-- Truy vấn tạo ra database
#create database shoppingonline;

USE mini_mart_dev;

Set foreign_key_checks  = 0;

Drop table users;

CREATE TABLE users (
                       ID_USER INT AUTO_INCREMENT PRIMARY KEY,
                       email VARCHAR(255) UNIQUE NOT NULL,
                       password VARCHAR(255) NOT NULL,
                       full_name VARCHAR(255) NOT NULL,
                       status VARCHAR(50) NOT NULL,
                       role VARCHAR(50) NOT NULL,
                       real_name VARCHAR(50),
                       number_phone BIGINT,
                       birth_day DATE,
                       address VARCHAR(100),
                       sex VARCHAR(10),
                       image TEXT
);






create table product(
    ID_PRODUCT INT  UNIQUE AUTO_INCREMENT PRIMARY KEY,
    name varchar(500)not null,
    description text,
    price numeric(18,3) not null,
    stock int,
    original_price numeric(18,3) not null,
    category varchar(255) not null,
    image_link text not null,
    sub_category varchar(255) not null


);




-- NHÓM TRANG TRÍ
    (NULL,'Đồng hồ treo tường','Đồng hồ treo tường với thiết kế tối giản, tinh tế mang lại vẻ đẹp hiện đại và vô cùng sang trọng cho không gian sống của gia đình bạn. Sản phẩm sử dụng máy đồng hồ kim trôi cực kỳ êm ái, hoàn toàn không gây ra tiếng động tích tắc khó chịu, đảm bảo giấc ngủ yên bình cho các thành viên. Chữ số hiển thị rõ ràng, sắc nét giúp bạn dễ dàng quan sát thời gian từ khoảng cách xa một cách chính xác nhất. Đây không chỉ là một vật dụng xem giờ cần thiết mà còn là một món đồ trang trí nội thất tuyệt vời cho phòng khách, phòng ngủ hay văn phòng.',260000,25,210000,'Trang trí','https://donghotreotuongdep.com.vn/wp-content/uploads/2022/04/dong-ho-treo-tuong-hien-dai.jpg','Đồng hồ'),
    (NULL,'Đèn ngủ để bàn','Đèn ngủ để bàn mang lại ánh sáng vàng dịu nhẹ, tạo nên không gian ấm cúng và giúp bạn dễ dàng đi vào giấc ngủ sâu hơn sau một ngày dài làm việc mệt mỏi. Chụp đèn được thiết kế tinh xảo giúp phân tán ánh sáng đều khắp phòng, không gây chói mắt khó chịu khi bạn đọc sách buổi đêm. Thân đèn làm từ gỗ tự nhiên hoặc kim loại chắc chắn, mang lại vẻ đẹp sang trọng và đẳng cấp cho tủ đầu giường của bạn. Sản phẩm tích hợp công tắc điều chỉnh độ sáng linh hoạt, giúp bạn tùy chỉnh mức độ ánh sáng phù hợp nhất theo nhu cầu cá nhân.',230000,35,180000,'Trang trí','https://tse2.mm.bing.net/th/id/OIP.0r0yutPoutEL38SW6d7FegHaHa?pid=Api&P=0&h=180','Đèn ngủ'),
    (NULL,'Chậu cây mini để bàn','Chậu cây mini để bàn là món đồ trang trí nhỏ gọn nhưng mang lại cảm giác vô cùng tươi mới và tràn đầy sức sống cho không gian sống và làm việc của bạn. Sản phẩm rất phù hợp đặt trên bàn học, bàn làm việc văn phòng hoặc các kệ trang trí nhỏ trong phòng khách gia đình. Thiết kế đơn giản nhưng tinh tế giúp tạo điểm nhấn nhẹ nhàng cho không gian nội thất xung quanh. Ngoài ra, việc đặt một chậu cây xanh nhỏ trên bàn còn giúp giảm thiểu căng thẳng, tạo cảm giác thư giãn tuyệt vời và tăng khả năng tập trung khi làm việc hay học tập.',130000,50,95000,'Trang trí','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lo28ublk13zu17','Cây cảnh'),
    (NULL,'Khung ảnh để bàn','Khung ảnh để bàn được thiết kế vô cùng nhỏ gọn, tinh tế giúp bạn lưu giữ lại những khoảnh khắc đáng nhớ nhất cùng gia đình, bạn bè hoặc những người thân yêu. Sản phẩm cực kỳ phù hợp để đặt trên bàn làm việc, kệ sách cá nhân hoặc tủ trang trí trong phòng ngủ ấm cúng. Chất liệu khung bền đẹp, sang trọng và rất dễ dàng để thay đổi hình ảnh bên trong theo ý thích mỗi ngày. Với thiết kế đơn giản nhưng không kém phần sang trọng, khung ảnh không chỉ bảo vệ hình ảnh khỏi bụi bẩn mà còn tạo điểm nhấn trang trí đẹp mắt cho ngôi nhà.',150000,40,120000,'Trang trí','https://inanhvietnam.com/image/cache/catalog/product/AnhDeBan/khungAnh/ban-khung-anh.jpg','Khung ảnh'),
    (NULL,'Nến thơm thư giãn','Nến thơm thư giãn là dòng sản phẩm được rất nhiều người ưa chuộng nhờ khả năng tạo ra không gian sống ấm áp, lãng mạn và vô cùng dễ chịu cho tinh thần. Khi thắp nến, hương thơm tinh dầu nhẹ nhàng sẽ lan tỏa khắp căn phòng giúp giảm bớt mọi căng thẳng, lo âu sau một ngày dài làm việc mệt mỏi. Sản phẩm rất phù hợp sử dụng trong phòng ngủ, phòng tắm hoặc trong lúc thực hành thiền và yoga hàng ngày. Thiết kế hũ nến đẹp mắt cũng giúp sản phẩm trở thành một món đồ trang trí tinh tế cho không gian sống hiện đại của bạn.',200000,30,160000,'Trang trí','https://down-vn.img.susercontent.com/file/vn-11134207-820l4-mfqzuwyzm3v13f','Nến thơm'),


-- NHÓM ĐỒ DÙNG & CÔNG NGHỆ
    (NULL,'Hộp cơm giữ nhiệt','Hộp cơm giữ nhiệt cao cấp giúp bạn mang theo những bữa ăn tự chuẩn bị từ nhà một cách tiện lợi, tiết kiệm và đảm bảo vệ sinh thực phẩm tối đa. Sản phẩm có khả năng giữ nhiệt cực tốt giúp thức ăn luôn duy trì được độ ấm nóng thơm ngon trong nhiều giờ liên tục. Thiết kế nhiều ngăn chứa riêng biệt giúp phân chia các món ăn mặn, canh, rau gọn gàng và dễ dàng mang theo khi đi học hoặc đi làm mỗi ngày. Chất liệu làm hộp hoàn toàn an toàn cho thực phẩm, dễ dàng vệ sinh sau khi sử dụng xong. Đây là lựa chọn hoàn hảo cho lối sống lành mạnh.',210000,35,170000,'Đồ dùng','https://down-vn.img.susercontent.com/file/sg-11134201-7rd6w-lwio2hfqdbx6e0','Hộp cơm'),
    (NULL,'Ô dù gấp gọn','Ô dù gấp gọn là vật dụng cá nhân cực kỳ cần thiết giúp bảo vệ sức khỏe của bạn khỏi những ngày nắng gắt gay gắt hoặc những cơn mưa bất chợt không báo trước. Sản phẩm sở hữu thiết kế thông minh nhỏ gọn, cho phép người dùng dễ dàng gấp lại và mang theo bên mình trong túi xách, balo hay cốp xe máy. Khung ô được làm từ chất liệu chắc chắn giúp chịu được sức gió vừa phải và đảm bảo thời gian sử dụng lâu dài. Chất liệu vải chống thấm nước và chống tia UV hiệu quả giúp bạn luôn khô ráo và an tâm khi di chuyển ngoài trời.',150000,50,120000,'Đồ dùng','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lma7sa8qnr33ac','Ô dù'),
    (NULL,'Đèn pin siêu sáng','Đèn pin siêu sáng là thiết bị chiếu sáng cầm tay nhỏ gọn nhưng cực kỳ mạnh mẽ, rất hữu ích trong nhiều tình huống khẩn cấp như mất điện đột ngột, đi du lịch phượt, cắm trại hay sửa chữa đồ đạc trong bóng tối. Sản phẩm cung cấp luồng ánh sáng mạnh với tầm chiếu xa, giúp bạn quan sát rõ ràng mọi vật thể trong điều kiện thiếu sáng trầm trọng. Thiết kế vỏ đèn bằng hợp kim chắc chắn, chống va đập tốt và rất thuận tiện để mang theo bên mình mọi lúc mọi nơi. Pin sạc có thời gian sử dụng lâu dài giúp bạn hoàn toàn yên tâm khi dùng.',220000,40,180000,'Đồ dùng','https://cf.shopee.vn/file/vn-11134207-7r98o-lo4vbxrn91mze1','Đèn pin'),
    (NULL,'Ổ cắm điện đa năng','Ổ cắm điện đa năng cao cấp giúp bạn kết nối cùng lúc nhiều thiết bị điện tử khác nhau một cách an toàn, gọn gàng và cực kỳ tiện lợi trong quá trình sử dụng. Sản phẩm rất phù hợp để sử dụng trong gia đình, văn phòng làm việc hiện đại hoặc phòng học tập cá nhân. Thiết kế ổ cắm nhỏ gọn giúp tiết kiệm không gian bàn làm việc và dễ dàng mang theo khi cần di chuyển xa. Hệ thống ổ cắm chắc chắn kết hợp với màng che an toàn giúp đảm bảo tiếp xúc điện ổn định, hỗ trợ nhiều loại phích cắm khác nhau theo tiêu chuẩn quốc tế hiện nay.',120000,60,95000,'Đồ dùng','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lg0lxgyn6cc7de','Ổ cắm'),
    (NULL,'Tai nghe gaming','Tai nghe gaming chuyên nghiệp được thiết kế đặc biệt dành riêng cho những người đam mê trò chơi điện tử với chất lượng âm thanh rõ ràng, trung thực và cực kỳ sống động. Sản phẩm giúp bạn nghe rõ từng chi tiết âm thanh nhỏ nhất trong game như tiếng bước chân quân địch, tiếng súng nổ từ xa hay các hiệu ứng môi trường chân thực. Phần đệm tai được làm từ chất liệu da mềm mại giúp người dùng có thể đeo trong thời gian dài mà vẫn cảm thấy thoải mái. Micro tích hợp có khả năng lọc tiếng ồn tốt giúp bạn giao tiếp rõ ràng với đồng đội.',780000,25,680000,'Công nghệ','https://cf.shopee.vn/file/0369dc7bf96a5e2de65984e9cdda8310','Tai nghe'),
    (NULL,'Webcam máy tính','Webcam máy tính thế hệ mới giúp bạn dễ dàng thực hiện các cuộc gọi video chất lượng cao, tham gia các buổi học online hoặc họp trực tuyến chuyên nghiệp một cách thuận tiện nhất. Sản phẩm cung cấp chất lượng hình ảnh HD rõ nét, màu sắc trung thực giúp người đối diện có thể nhìn thấy bạn rõ ràng hơn bao giờ hết. Thiết kế sản phẩm nhỏ gọn, tinh tế và cực kỳ dễ dàng lắp đặt chắc chắn trên màn hình laptop hoặc màn hình máy tính để bàn. Đây chính là thiết bị ngoại vi không thể thiếu cho nhu cầu học tập, làm việc và giải trí từ xa hiện nay.',620000,20,540000,'Công nghệ','https://cameramini.vn/wp-content/uploads/2021/10/Webcam-may-tinh-1080p-1.jpg','Webcam'),
    (NULL,'Đèn LED RGB trang trí','Đèn LED RGB trang trí giúp tạo nên một không gian ánh sáng cực kỳ hiện đại, lung linh và sinh động cho phòng ngủ, phòng gaming chuyên nghiệp hoặc góc làm việc cá nhân của bạn. Sản phẩm sở hữu dải màu sắc đa dạng với hàng triệu màu khác nhau, cho phép bạn dễ dàng tùy chỉnh theo sở thích cá nhân hoặc theo tâm trạng mỗi ngày. Đèn rất dễ dàng lắp đặt bằng lớp băng keo chuyên dụng và cực kỳ tiết kiệm điện năng trong suốt quá trình sử dụng. Đây là món phụ kiện trang trí nội thất phổ biến được rất nhiều bạn trẻ yêu thích hiện nay.',320000,35,260000,'Công nghệ','https://cf.shopee.vn/file/cadd6518c88aaf50d8e47795741acc98','Đèn LED'),
    (NULL,'Hub USB 4 cổng','Hub USB 4 cổng cao cấp giúp mở rộng tối đa số lượng cổng kết nối USB cho các dòng laptop mỏng nhẹ hoặc máy tính để bàn có ít cổng cắm ngoại vi. Sản phẩm cho phép bạn kết nối đồng thời nhiều thiết bị khác nhau như chuột, bàn phím, USB lưu trữ, ổ cứng ngoài hay máy in chỉ qua một cổng kết nối duy nhất. Thiết kế hub nhỏ gọn, sang trọng giúp người dùng dễ dàng mang theo trong túi chống sốc khi đi làm việc bên ngoài hoặc đi công tác. Đây là phụ kiện hữu ích cho những ai thường xuyên làm việc với nhiều thiết bị công nghệ hỗ trợ.',240000,45,190000,'Công nghệ','http://phukiencom.vn/wp-content/uploads/2024/03/bo-chia-usb-1-4-hud3.0-4ports.png','Hub USB'),
    (NULL,'Thẻ nhớ microSD 128GB','Thẻ nhớ microSD dung lượng lớn 128GB giúp bạn mở rộng tối đa không gian lưu trữ cho các thiết bị di động như điện thoại thông minh, máy ảnh số hay máy quay hành trình cá nhân. Với dung lượng cực lớn, người dùng có thể thoải mái lưu trữ hàng ngàn bức ảnh độ phân giải cao, các video chất lượng 4K sắc nét và những tài liệu quan trọng khác. Tốc độ đọc ghi dữ liệu vô cùng ổn định giúp quá trình truy xuất thông tin diễn ra nhanh chóng, mượt mà và không bị gián đoạn. Sản phẩm có kích thước nhỏ gọn nhưng mang lại tiện ích lưu trữ vô cùng to lớn.',340000,40,280000,'Công nghệ','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lfz8noc7arxz30','Thẻ nhớ'),


-- NHÓM ÁO (19 món)
    (NULL,'Áo polo nam basic ','Áo polo nam basic là lựa chọn đơn giản nhưng luôn mang lại vẻ ngoài lịch sự và gọn gàng cho người mặc trong mọi hoàn cảnh khác nhau. Thiết kế cổ bẻ đặc trưng kết hợp với form áo vừa vặn giúp tạo cảm giác thoải mái và tự tin trong nhiều hoạt động hằng ngày từ đi học đến đi làm. Chất liệu vải mềm mại, có khả năng thoáng khí cực tốt giúp người mặc luôn cảm thấy dễ chịu ngay cả khi sử dụng trong thời gian dài dưới thời tiết nóng bức. Sản phẩm cực kỳ phù hợp để mặc đi học, đi làm công sở hoặc đi chơi dạo phố cùng bạn bè vào dịp cuối tuần.',300000,40,250000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lvw0rfp64yjf20','Áo polo'),
    (NULL,'Áo polo nam thể thao ','Áo polo nam thể thao được thiết kế đặc biệt dành cho những người đàn ông yêu thích sự năng động, trẻ trung và phong cách sống thoải mái. Chất liệu vải thun lạnh thoáng khí giúp thấm hút mồ hôi cực kỳ tốt, rất phù hợp với các hoạt động ngoài trời hoặc vận động thể dục thể thao nhẹ nhàng. Form áo được cắt may gọn gàng giúp người mặc trông khỏe khoắn, mạnh mẽ và vô cùng hiện đại trong mắt người đối diện. Đây là lựa chọn tuyệt vời cho các buổi đi chơi, dạo phố buổi tối hoặc tham gia các hoạt động ngoại khóa đầy sôi động cùng người thân.',305000,39,255000,'Áo','https://gympassion.vn/upload/store/2022-01-18/ao-polo-nam-the-thao-a636-xam.jpg','Áo polo'),
    (NULL,'Áo polo nam cotton ','Áo polo nam cotton được làm từ chất liệu vải sợi cotton tự nhiên mềm mại, mang lại cảm giác dễ chịu và thân thiện với làn da người mặc. Thiết kế đơn giản nhưng vô cùng tinh tế giúp sản phẩm dễ dàng phối cùng nhiều loại trang phục khác nhau như quần jean cá tính, quần kaki lịch sự hoặc quần short năng động. Sản phẩm phù hợp cho nhiều hoàn cảnh đa dạng từ đi học, làm việc tại văn phòng đến những buổi gặp gỡ bạn bè thân mật. Độ bền của vải cotton giúp áo giữ được form dáng và màu sắc bền lâu sau nhiều lần giặt giũ và sử dụng hàng ngày.',310000,38,260000,'Áo','https://cf.shopee.vn/file/940700fe04a15c5ae545a30a2901f040','Áo polo'),
    (NULL,'Áo polo nam kẻ sọc ','Áo polo nam kẻ sọc mang phong cách trẻ trung và hiện đại nhờ họa tiết sọc ngang tinh tế, giúp người mặc trở nên nổi bật và thu hút hơn. Thiết kế cổ áo bẻ đặc trưng tạo nên vẻ ngoài lịch sự, chỉn chu nhưng vẫn giữ được sự thoải mái cần thiết cho các hoạt động di chuyển. Chất liệu vải cao cấp mềm mại giúp người mặc luôn cảm thấy dễ chịu, không gây bí bách trong suốt ngày dài làm việc căng thẳng. Đây là sản phẩm cực kỳ dễ phối đồ và phù hợp với nhiều phong cách thời trang khác nhau từ cổ điển đến hiện đại thời thượng.',320000,36,270000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lofk7zk93nqra8','Áo polo'),
    (NULL,'Áo hoodie nam basic 4','Áo hoodie nam phiên bản basic là món đồ thời trang không thể thiếu trong tủ đồ của các bạn trẻ yêu thích phong cách đơn giản và tiện lợi. Thiết kế mũ trùm đầu rộng rãi kết hợp với form áo thoải mái giúp người mặc luôn cảm thấy ấm áp và dễ chịu trong mọi cử động hàng ngày. Chất liệu vải nỉ dày dặn đặc biệt phù hợp để sử dụng trong những ngày thời tiết se lạnh hoặc khi đi du lịch vùng cao. Sản phẩm có thể dễ dàng phối cùng quần jean rách hoặc quần thể thao để tạo nên một bộ trang phục dạo phố cực kỳ ấn tượng.',430000,40,380000,'Áo','https://tse4.mm.bing.net/th/id/OIP.6LYsKZrTssNPS8KoZ9hfGAHaHa?pid=Api&P=0&h=180','Áo hoodie'),
    (NULL,'Áo hoodie nam form rộng ','Áo hoodie nam thiết kế form rộng mang đậm phong cách thời trang trẻ trung, phóng khoáng và cực kỳ năng động của giới trẻ hiện đại. Thiết kế rộng rãi tối đa giúp người mặc luôn cảm thấy thoải mái tuyệt đối khi vận động hay tham gia các hoạt động ngoài trời sôi nổi. Chất liệu vải cotton nỉ mềm mại và ấm áp giúp bảo vệ cơ thể tối ưu trong những ngày thời tiết lạnh giá của mùa đông. Đây là sản phẩm luôn nằm trong danh sách yêu thích của nhiều bạn trẻ theo đuổi phong cách streetwear bụi bặm và đầy cá tính mạnh mẽ.',435000,39,385000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-ljyynbmh2iesd8','Áo hoodie'),
    (NULL,'Áo hoodie nam streetwear ','Áo hoodie nam streetwear mang trong mình phong cách cá tính, độc đáo và đầy hơi thở hiện đại của thời trang đường phố cao cấp. Thiết kế trẻ trung với các điểm nhấn sáng tạo giúp người mặc tự tin thể hiện phong cách thời trang cá nhân riêng biệt của mình trước đám đông. Chất liệu vải nỉ cao cấp giữ nhiệt cực tốt, đảm bảo cơ thể luôn ấm áp trong những ngày đông lạnh lẽo nhất. Sản phẩm rất phù hợp để mặc đi học, đi chơi cùng người yêu hoặc tham gia vào các hoạt động ngoại khóa năng động và đầy thú vị hàng ngày.',440000,38,390000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-m2o5vlfusr2e1a','Áo hoodie'),
    (NULL,'Áo hoodie thể thao ','Áo hoodie thể thao được thiết kế chuyên dụng dành cho những người yêu thích vận động và phong cách sống khỏe khoắn, tràn đầy năng lượng. Chất liệu vải nỉ nhẹ thoáng khí giúp người mặc luôn cảm thấy thoải mái và không bị bí bách mồ hôi khi tập luyện nhẹ nhàng. Thiết kế năng động với các đường cắt may tinh tế giúp sản phẩm phù hợp cho các hoạt động thể thao ngoài trời như chạy bộ, tập gym hoặc chỉ đơn giản là dạo phố hằng ngày. Đây là món đồ đa năng giúp bạn giữ ấm cơ thể hiệu quả mà vẫn đảm bảo được tính thời trang sành điệu.',445000,37,395000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7ra0g-m6psdftp0s6907','Áo hoodie'),
    (NULL,'Áo len nam basic 1','Áo len nam basic là lựa chọn hoàn hảo nhất cho những ngày thời tiết bắt đầu chuyển se lạnh của mùa thu đông năm nay. Thiết kế đơn giản nhưng vô cùng tinh tế giúp người mặc dễ dàng phối hợp với nhiều loại trang phục khác nhau như quần jean bụi bặm, quần kaki lịch lãm hoặc quần tây sang trọng. Chất liệu len sợi tự nhiên mềm mại mang lại cảm giác ấm áp và vô cùng dễ chịu khi mặc trong thời gian dài liên tục suốt cả ngày. Sản phẩm rất phù hợp để mặc đi học, đi làm công sở hoặc đi dạo phố buổi tối cùng bạn bè thân thiết.',420000,35,360000,'Áo','https://pos.nvncdn.com/540324-121901/ps/20250905_Sfj0c06Y6i.jpeg','Áo len'),
    (NULL,'Áo len nam cổ tròn','Áo len nam thiết kế cổ tròn mang lại phong cách trẻ trung, hiện đại và vô cùng thanh lịch, phù hợp với nhiều lứa tuổi nam giới khác nhau. Thiết kế cổ tròn đơn giản giúp tạo cảm giác thoải mái khi mặc và rất dễ phối hợp với các loại áo khoác bên ngoài trong nhiều hoàn cảnh đa dạng. Chất liệu len dệt cao cấp giúp giữ ấm cơ thể cực tốt nhưng vẫn đảm bảo được độ thoáng khí cần thiết khi sử dụng lâu. Đây là sản phẩm cực kỳ dễ phối đồ và là item không thể thiếu cho tủ đồ mùa thu đông của các chàng trai.',425000,34,365000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lnsf317a7mct62','Áo len'),
    (NULL,'Áo len nam cổ tim','Áo len nam cổ tim được thiết kế tinh tế với kiểu cổ chữ V thanh lịch giúp người mặc trông gọn gàng, nam tính và trưởng thành hơn rất nhiều. Chất liệu len mềm mại cao cấp tạo cảm giác cực kỳ dễ chịu và êm ái khi tiếp xúc với làn da suốt cả ngày dài làm việc. Sản phẩm rất phù hợp khi kết hợp cùng với một chiếc áo sơ mi có cổ bên trong để tạo nên phong cách lịch sự, chỉn chu khi đi học, đi làm hoặc tham gia các buổi tiệc tối quan trọng. Đây là trang phục giúp tôn lên nét thư sinh và lịch lãm của phái mạnh.',430000,33,370000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lm9uuc55lnfj70','Áo len'),
    (NULL,'Áo tanktop nam thể thao','Áo tanktop nam thể thao được thiết kế chuyên dụng dành cho những người yêu thích các hoạt động vận động mạnh và tập luyện thể hình chuyên nghiệp. Kiểu dáng sát nách không tay giúp cơ thể hoàn toàn thoải mái khi di chuyển các khớp vai và thực hiện các bài tập tạ khó. Chất liệu vải lưới siêu nhẹ và thoáng khí tối đa giúp thấm hút mồ hôi cực nhanh, giữ cho cơ thể luôn khô thoáng. Đây là lựa chọn hàng đầu khi bạn tập gym, chạy bộ buổi sáng hoặc tham gia vào các hoạt động thể thao ngoài trời đầy năng lượng.',220000,50,180000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lg1z5ne7utt656','Áo tanktop'),
    (NULL,'Áo tanktop nam basic','Áo tanktop nam basic mang đậm phong cách đơn giản, năng động và cực kỳ thoải mái cho các hoạt động thường ngày tại nhà hoặc dạo phố. Thiết kế không tay phóng khoáng giúp người mặc cảm thấy vô cùng dễ chịu, mát mẻ trong những ngày thời tiết mùa hè nóng bức và oi ả. Chất liệu vải cotton mềm mại và thoáng khí giúp sản phẩm phù hợp sử dụng trong nhiều hoạt động hằng ngày như tập thể thao nhẹ, mặc lót bên trong hoặc mặc ở nhà. Sản phẩm có nhiều màu sắc trung tính giúp bạn dễ dàng lựa chọn theo sở thích cá nhân của mình.',215000,48,175000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lhx7hfb6thtxbc','Áo tanktop'),
    (NULL,'Áo cardigan nam basic','Áo cardigan nam basic mang phong cách thời trang nhẹ nhàng, thanh lịch và pha chút lãng tử của các chàng trai hiện đại. Thiết kế dạng áo khoác len có hàng nút cài phía trước giúp người mặc dễ dàng thay đổi kiểu dáng và kết hợp linh hoạt với nhiều loại trang phục bên trong như áo thun hay áo sơ mi. Chất liệu len mềm mại và mịn màng giúp giữ ấm cơ thể vừa đủ trong tiết trời thu se lạnh hoặc khi làm việc trong môi trường máy lạnh văn phòng. Đây là lựa chọn hoàn hảo cho những ai yêu thích vẻ ngoài chỉn chu và ấm áp.',450000,32,390000,'Áo','https://m.yodycdn.com/blog/cach-phoi-do-voi-ao-cardigan-nam-yody-vn-21.jpg','Áo cardigan'),
    (NULL,'Áo cardigan nam form rộng','Áo cardigan nam thiết kế form rộng mang phong cách trẻ trung và hiện đại, hiện đang là xu hướng thời trang rất được ưa chuộng trong giới trẻ Hàn Quốc và Việt Nam. Thiết kế rộng rãi giúp người mặc cảm thấy thoải mái tuyệt đối khi vận động và cực kỳ dễ dàng trong việc phối đồ theo phong cách nhiều lớp (layering). Sản phẩm phù hợp cho phong cách thời trang casual hàng ngày, đi cà phê cùng bạn bè hoặc dạo phố buổi tối. Chất liệu len dệt kim dày dặn đảm bảo độ bền cao và giữ ấm tốt cho người mặc trong mùa đông.',455000,30,395000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lzx6zud7osi544','Áo cardigan'),
    (NULL,'Áo gió nam thể thao','Áo gió nam thể thao được thiết kế thông minh để bảo vệ cơ thể bạn hoàn toàn khỏi những luồng gió lạnh khi tham gia các hoạt động ngoài trời hay di chuyển trên đường. Chất liệu vải gió siêu nhẹ nhưng bền bỉ giúp người mặc cảm thấy cực kỳ thoải mái và linh hoạt trong mọi cử động mà không cảm thấy nặng nề. Sản phẩm rất phù hợp cho các hoạt động năng động như đi xe máy đường dài, chạy bộ buổi sáng hoặc đi du lịch dã ngoại. Áo có khả năng cản gió tuyệt vời và chống bám bụi bẩn hiệu quả, giúp bạn luôn sạch sẽ.',470000,28,410000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134202-7ras8-m3ucb83r40qk3e','Áo gió'),
    (NULL,'Áo gió nam chống nước','Áo gió nam chống nước là sản phẩm cực kỳ tiện dụng giúp bảo vệ cơ thể bạn khỏi những cơn gió lạnh và cả những trận mưa phùn nhẹ bất chợt. Thiết kế vô cùng gọn nhẹ giúp người dùng có thể dễ dàng gấp lại để bỏ vào balo hay túi xách và mang theo bên mình khi đi làm hoặc đi phượt. Chất liệu vải dù cao cấp bền bỉ và có lớp phủ chống nước chuyên dụng giúp áo giữ được độ bền đẹp lâu dài theo thời gian sử dụng. Đây là trang phục lý tưởng cho những người thường xuyên phải di chuyển ngoài trời trong mùa mưa.',475000,27,415000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lu2580fx6ioh83','Áo gió'),
    (NULL,'Áo blazer nam công sở','Áo blazer nam công sở mang đậm phong cách lịch sự, chuyên nghiệp và đầy quyền lực cho phái mạnh trong môi trường làm việc văn phòng. Thiết kế gọn gàng với đường cắt may tinh xảo giúp người mặc trông chỉn chu, lịch lãm và tự tin hơn rất nhiều khi gặp gỡ đối tác hoặc tham gia các cuộc họp quan trọng. Sản phẩm cực kỳ dễ dàng phối cùng áo sơ mi trắng và quần tây tối màu để tạo nên một diện mạo hoàn hảo. Chất liệu vải cao cấp giúp áo luôn giữ được form dáng đứng, không bị nhăn nhúm sau khi ngồi làm việc lâu.',600000,20,520000,'Áo','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lne3hpnwoctpee','Áo blazer'),
    (NULL,'Áo blazer nam casual','Áo blazer nam casual được thiết kế với phong cách trẻ trung, năng động và linh hoạt hơn rất nhiều so với những dòng blazer công sở truyền thống cứng nhắc. Chất liệu vải mềm mại và có độ co giãn nhẹ giúp người mặc cảm thấy vô cùng thoải mái khi sử dụng trong suốt cả ngày dài. Đây là lựa chọn hoàn hảo cho cả việc đi làm văn phòng lẫn tham gia các buổi đi chơi, tiệc tùng tối nhẹ nhàng. Bạn có thể kết hợp áo cùng với áo thun bên trong và quần jean để tạo nên một phong cách thời trang vừa lịch sự vừa phóng khoáng.',595000,19,515000,'Áo','https://cf.shopee.vn/file/39ba55af4ef2c88080163ecb7a478a13','Áo blazer'),


-- NHÓM CÔNG NGHỆ (7 món)
    (NULL,'Tai nghe bluetooth gaming','Tai nghe bluetooth gaming mang lại trải nghiệm âm thanh cực kỳ sống động và chân thực cho người dùng khi tham gia vào các trận đấu game đỉnh cao hoặc nghe nhạc giải trí. Thiết kế hiện đại mang đậm chất gaming kết hợp với phần đệm tai siêu mềm mại giúp bạn có thể sử dụng thoải mái trong thời gian dài mà không gây đau tai. Sản phẩm sở hữu công nghệ kết nối không dây bluetooth ổn định và tiện lợi, giúp loại bỏ hoàn toàn sự vướng víu của dây cáp. Đây là thiết bị không thể thiếu để bạn tận hưởng những giây phút giải trí tuyệt vời.',720000,15,650000,'Công nghệ','https://down-vn.img.susercontent.com/file/vn-11134207-23010-g3juk2m4q7lvf7','Tai nghe'),
    (NULL,'Chuột gaming RGB','Chuột gaming RGB cao cấp được thiết kế chuyên biệt dành riêng cho game thủ với độ nhạy cực cao và khả năng phản hồi tín hiệu nhanh tức thì trong quá trình chơi game. Hệ thống đèn LED RGB rực rỡ nhiều màu sắc tạo điểm nhấn vô cùng nổi bật cho góc máy tính chơi game của bạn vào ban đêm. Thiết kế công thái học ôm sát lòng bàn tay giúp người dùng cầm nắm thoải mái và không bị mỏi khi sử dụng trong nhiều giờ liên tục. Sản phẩm tích hợp các nút chức năng tiện lợi giúp bạn thao tác nhanh chóng và giành lợi thế khi thi đấu.',380000,25,320000,'Công nghệ','https://tse3.mm.bing.net/th/id/OIP.UJ5QeiXr0DfrAhOR_h4MtAHaHa?pid=Api&P=0&h=180','Chuột'),
    (NULL,'Bàn phím cơ gaming','Bàn phím cơ gaming mang lại trải nghiệm gõ phím cực kỳ chính xác, âm thanh clicky vui tai và tốc độ phản hồi nhanh vượt trội so với bàn phím thường. Thiết kế chắc chắn từ chất liệu nhựa và kim loại cao cấp kết hợp với hệ thống đèn LED nền sinh động giúp tạo ra một không gian chơi game vô cùng chuyên nghiệp và đầy cảm hứng. Sản phẩm phù hợp cho cả nhu cầu chơi game thi đấu cường độ cao và công việc soạn thảo văn bản hàng ngày. Đây là món đồ nâng cấp đáng giá nhất cho bất kỳ dàn máy tính nào hiện nay.',850000,12,780000,'Công nghệ','https://cf.shopee.vn/file/3e1670924dd96d742ce0b5c844b4eaf8','Bàn phím'),
    (NULL,'Sạc dự phòng 10000mAh','Sạc dự phòng dung lượng 10000mAh là món phụ kiện công nghệ cực kỳ tiện lợi giúp bạn duy trì năng lượng cho điện thoại hoặc các thiết bị di động khi đang di chuyển ngoài đường. Với dung lượng pin lớn, sản phẩm có thể sạc đầy điện thoại nhiều lần trong ngày, rất phù hợp cho các chuyến đi công tác xa, du lịch dài ngày hoặc sử dụng hằng ngày tại văn phòng. Thiết kế nhỏ gọn giúp bạn dễ dàng mang theo trong balo, túi xách hay thậm chí là túi quần. Thiết bị có hệ thống ngắt điện an toàn khi sạc đầy giúp bảo vệ pin của máy.',350000,0,299000,'Phụ kiện','https://salt.tikicdn.com/ts/tmp/72/56/09/a2bdd860a40e701dffb3aa4c47a6ed45.jpg','Sạc dự phòng'),
    (NULL,'Chuột gaming Razer','Chuột gaming từ thương hiệu Razer nổi tiếng là thiết bị được thiết kế đỉnh cao dành riêng cho các vận động viên esports với độ nhạy cực lớn và khả năng phản hồi nhanh trong tích tắc. Kiểu dáng công thái học tối ưu giúp người dùng cầm nắm cực kỳ thoải mái ngay cả khi tham gia vào các trận đấu kéo dài nhiều giờ. Hệ thống cảm biến quang học chính xác giúp di chuyển chuột mượt mà trên mọi bề mặt khác nhau mà không gặp lỗi. Sản phẩm sở hữu thiết kế hiện đại, đèn nền Chroma rực rỡ phù hợp với mọi góc máy tính chơi game sành điệu.',850000,30,690000,'Thiết bị','https://tse1.mm.bing.net/th/id/OIP.ChieuFay4Hjzqx1EyFqkKQHaHa?pid=Api&P=0&h=180','Chuột'),
    (NULL,'Ống kính điện thoại','Biến chiếc điện thoại thông minh của bạn thành một chiếc máy ảnh chuyên nghiệp chỉ với bộ ống kính rời tiện lợi và đa năng này. Sản phẩm giúp bạn mở rộng góc chụp kiến trúc, tăng cường khả năng thu phóng zoom xa hoặc tạo ra những bức ảnh macro sắc nét đến từng chi tiết nhỏ nhất mà camera thường không thể làm được. Thấu kính được chế tác tỉ mỉ từ thủy tinh quang học chất lượng cao, giúp giảm thiểu hiện tượng nhiễu sáng và méo hình ảnh. Bộ sản phẩm rất dễ dàng tháo lắp và tương thích với hầu hết các dòng smartphone phổ biến.',150000,100,110000,'Phụ kiện','https://tse2.mm.bing.net/th/id/OIP.9x-BW8_j1mi4ENW-Up8WZQHaHa?pid=Api&P=0&h=180','Ống kính'),
    (NULL,'Đồng hồ thông minh','Chiếc đồng hồ thông minh này chính là một người trợ lý sức khỏe cá nhân thông minh ngay trên cổ tay của bạn mỗi ngày. Sản phẩm tích hợp đầy đủ các tính năng hiện đại như đo nhịp tim liên tục, theo dõi chất lượng giấc ngủ, đếm bước chân và hiển thị thông báo cuộc gọi, tin nhắn từ điện thoại tức thì. Màn hình AMOLED hiển thị sắc nét với độ phân giải cao, cho phép người dùng quan sát rõ ràng các chỉ số ngay cả dưới ánh nắng gay gắt. Thời lượng pin ấn tượng giúp bạn yên tâm sử dụng trong mọi hoạt động thể thao dã ngoại.',2090000,25,1850000,'Thiết bị','https://cellphones.com.vn/media/catalog/product/h/u/huawei_4_.png','Đồng hồ'),


-- NHÓM ÂM THANH & PHỤ KIỆN (11 món)
    (NULL,'Tai nghe True Wireless','Tận hưởng sự tự do hoàn toàn trong âm nhạc với tai nghe True Wireless không dây, mang đến cho bạn một trải nghiệm âm thanh không giới hạn và đỉnh cao. Công nghệ Bluetooth phiên bản mới nhất giúp kết nối nhanh chóng, ổn định và hoàn toàn không có độ trễ khi bạn xem phim độ phân giải cao hoặc chơi game. Hộp sạc đi kèm thiết kế nhỏ gọn, không chỉ bảo vệ tai nghe an toàn mà còn cung cấp thêm hàng chục giờ sử dụng liên tục cho cả ngày dài. Mic thoại tích hợp công nghệ khử tiếng ồn giúp các cuộc trò chuyện trở nên rõ ràng hơn bao giờ hết.',999000,45,799000,'Âm thanh','https://cdn.tgdd.vn/Products/Images/54/324578/tai-nghe-bluetooth-true-wireless-jbl-wave-beam-xanhmint-thumb-600x600.jpg','Tai nghe'),
    (NULL,'Miếng dán cường lực','Bảo vệ tối ưu cho màn hình điện thoại đắt tiền của bạn với miếng dán cường lực độ cứng tiêu chuẩn quốc tế 9H siêu bền bỉ. Sản phẩm có khả năng chống trầy xước tuyệt đối từ các vật sắc nhọn như chìa khóa và giảm thiểu tối đa nguy cơ nứt vỡ khi vô tình va đập mạnh xuống đất. Lớp phủ nano đặc biệt giúp hạn chế bám dấu vân tay và mồ hôi, giữ cho màn hình điện thoại luôn sáng bóng như mới và thao tác chạm vuốt cực kỳ mượt mà. Với thiết kế siêu mỏng, miếng dán không hề làm ảnh hưởng đến chất lượng hiển thị hình ảnh của máy.',70000,150,50000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134201-7r98o-lldelfbtsuko28','Dán màn hình'),
    (NULL,'Cáp sạc USB-C','Sợi cáp sạc USB-C cao cấp là giải pháp truyền tải dữ liệu tốc độ cao và sạc năng lượng nhanh chóng, ổn định cho mọi thiết bị công nghệ hiện đại. Phần lõi bằng đồng nguyên chất giúp giảm thiểu tối đa sự tiêu hao năng lượng trong quá trình sạc, trong khi lớp vỏ bọc ngoài chắc chắn có khả năng chống rối và chịu được hàng ngàn lần uốn cong mà không lo bị đứt gãy. Độ dài dây cáp hợp lý giúp bạn thuận tiện sử dụng ở khoảng cách xa nguồn điện văn phòng. Sản phẩm tương thích hoàn hảo với nhiều dòng điện thoại và laptop đời mới.',90000,120,70000,'Phụ kiện','https://tse4.mm.bing.net/th/id/OIP.DMlJ4ZFGohnpXTNh_HrZZwHaHa?pid=Api&P=0&h=180','Cáp sạc'),
    (NULL,'Balo thời trang','Balo thời trang với thiết kế hiện đại, phong cách trẻ trung, cực kỳ phù hợp cho cả học sinh đi học, nhân viên đi làm văn phòng hay đi du lịch ngắn ngày. Sản phẩm được làm từ chất liệu vải cao cấp siêu bền bỉ và có khả năng chống thấm nước nhẹ, giúp bảo vệ an toàn cho các đồ dùng điện tử bên trong. Ngăn chứa rộng rãi cùng nhiều ngăn phụ thông minh giúp bạn sắp xếp sách vở, laptop và phụ kiện một cách khoa học. Quai đeo được đệm mút êm ái, giúp giảm thiểu áp lực lên vai khi phải mang đồ nặng trong thời gian dài.',390000,35,320000,'Phụ kiện','https://down-vn.img.susercontent.com/file/b9b9fcac0d93187ee597cca68a6bcb4c','Balo'),
    (NULL,'Quạt mini USB','Giải tỏa cơn nóng nực tức thì ngay tại bàn làm việc với chiếc quạt mini sử dụng cổng USB tiện lợi, rất phù hợp cho nhân viên văn phòng hoặc học sinh sinh viên. Quạt có kích thước vô cùng nhỏ gọn, có thể đặt gọn gàng trên bàn học hoặc mang theo trong túi xách khi đi ra ngoài. Động cơ quạt vận hành êm ái, không gây ra tiếng ồn khó chịu nhưng vẫn tạo ra luồng gió mát mẻ và ổn định. Bạn có thể dễ dàng cắm quạt vào cổng USB máy tính, sạc dự phòng hoặc củ sạc điện thoại để sử dụng mọi lúc mọi nơi cực kỳ linh hoạt.',190000,80,150000,'Thiết bị','https://tse1.mm.bing.net/th/id/OIP.ChieuFay4Hjzqx1EyFqkKQHaHa?pid=Api&P=0&h=180','Quạt'),
    (NULL,'Bàn gập học sinh','Bàn gập học sinh đa năng với thiết kế thông minh, có khả năng gấp gọn lại hoàn toàn sau khi sử dụng để tiết kiệm tối đa diện tích phòng ngủ hoặc ký túc xá. Mặt bàn được làm từ gỗ công nghiệp cao cấp, có khả năng chống trầy xước và rất dễ dàng lau chùi vệ sinh hàng ngày. Chân bàn bằng thép không gỉ chắc chắn, có tích hợp thêm đệm cao su chống trượt giúp bàn luôn ổn định trên mọi bề mặt sàn nhà. Đây là lựa chọn tuyệt vời cho các không gian nhỏ hẹp, dùng để học tập, làm việc với laptop vô cùng tiện dụng.',490000,25,390000,'Nội thất','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lfklq40b7hpxcd','Bàn'),
    (NULL,'Kính chống ánh sáng xanh','Bảo vệ đôi mắt quý giá của bạn khỏi những tác hại nguy hiểm từ màn hình máy tính và điện thoại với kính chống ánh sáng xanh chuyên dụng. Tròng kính được phủ một lớp lọc đặc biệt giúp ngăn chặn hiệu quả các tia sáng xanh có hại, giảm thiểu tình trạng mỏi mắt, khô mắt và đau đầu khi phải làm việc liên tục. Gọng kính được làm từ chất liệu nhựa dẻo siêu nhẹ, bền bỉ, mang lại cảm giác cực kỳ thoải mái khi đeo trong nhiều giờ. Thiết kế thời trang, hiện đại phù hợp cho cả nam và nữ trong mọi hoàn cảnh.',290000,100,230000,'Phụ kiện','https://cf.shopee.vn/file/0e49ba54546573346bf6fe10166321b6','Kính'),
    (NULL,'Hub chuyển USB-C to HDMI','Bộ chuyển đổi Hub USB-C sang HDMI là món phụ kiện bắt buộc phải có để xuất hình ảnh chất lượng cao từ laptop hoặc điện thoại lên màn hình lớn, tivi hay máy chiếu. Sản phẩm hỗ trợ độ phân giải sắc nét 4K, đảm bảo truyền tải tín hiệu âm thanh và hình ảnh ổn định, hoàn toàn không bị trễ hay nhiễu sóng. Thiết kế vỏ nhôm cao cấp giúp tản nhiệt tốt, nhỏ gọn, dễ dàng mang theo trong túi đựng laptop đi làm mỗi ngày. Đây là giải pháp tối ưu cho các buổi thuyết trình, xem phim giải trí hoặc làm việc đa màn hình chuyên nghiệp.',620000,70,520000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134201-23030-hysp3679dbovba','Hub chuyển'),
    (NULL,'Cân điện tử thông minh','Cân điện tử thông minh giúp bạn chủ động theo dõi các chỉ số cơ thể một cách chính xác và khoa học ngay tại nhà của mình. Ngoài việc đo cân nặng thông thường, sản phẩm còn hỗ trợ phân tích sâu các chỉ số quan trọng như tỉ lệ mỡ, lượng nước trong cơ thể và khối lượng cơ thông qua ứng dụng kết nối bluetooth trên điện thoại. Bề mặt cân được làm từ kính cường lực cao cấp chịu lực tốt và cực kỳ dễ dàng vệ sinh. Màn hình LED ẩn hiển thị rõ ràng các thông số đo được giúp bạn kiểm soát sức khỏe hiệu quả.',990000,0,880000,'Thiết bị','https://mivietnam.vn/wp-content/uploads/2020/06/MIVIETNAM-CAN-DIEN-TU-THONG-MINH-XIAOMI-SMART-SCALE-GEN-2-09.jpg','Cân'),
    (NULL,'Khăn thể thao gym','Khăn thể thao chuyên dụng dành riêng cho người tập gym và chơi thể thao với khả năng thấm hút mồ hôi cực kỳ mạnh mẽ và nhanh chóng. Chất liệu vải sợi microfiber cao cấp mang lại sự mềm mại tuyệt đối, hoàn toàn không gây kích ứng da và có đặc tính nhanh khô vượt trội, giúp ngăn ngừa mùi hôi và vi khuẩn phát triển. Kích thước khăn được tính toán vừa vặn để bạn quàng cổ hoặc lau người sau những giờ tập luyện cường độ cao. Sản phẩm có độ bền màu cao, không bị xơ vải, là người bạn đồng hành tin cậy mỗi ngày.',125000,100,95000,'Thể thao','https://down-vn.img.susercontent.com/file/c0aef11ee266024fb165c2474fc04e96','Khăn'),
    (NULL,'Vỏ laptop 14 inch','Túi chống sốc dành riêng cho các dòng laptop 14 inch mang lại sự bảo vệ toàn diện nhất cho thiết bị của bạn khỏi những va chạm không đáng có trong quá trình di chuyển. Lớp lót bên trong túi vô cùng dày dặn và mềm mại giúp chống trầy xước vỏ máy tối ưu, trong khi lớp vải bên ngoài có khả năng kháng nước hiệu quả giúp bảo vệ máy khi gặp mưa. Thiết kế khóa kéo chắc chắn và mượt mà giúp bạn thao tác lấy máy ra vào một cách dễ dàng. Kiểu dáng đơn giản, lịch sự, phù hợp để đựng máy tính đặt trong balo đi làm.',290000,75,210000,'Phụ kiện','https://hienlaptop.com/wp-content/uploads/2023/05/Vo-laptop-Dell-Inspiron-14-3480-3481-3482-3493.jpg','Túi laptop'),


-- NHÓM THIẾT BỊ VĂN PHÒNG & NHÀ CỬA (9 món)
    (NULL,'Túi giữ nhiệt mini','Túi giữ nhiệt mini chính là giải pháp tuyệt vời nhất để giữ cho bữa trưa tự chuẩn bị của bạn luôn ấm nóng thơm ngon hoặc giữ cho đồ uống mát lạnh suốt nhiều giờ. Lớp lót bạc cách nhiệt bên trong cao cấp giúp duy trì nhiệt độ ổn định cho thực phẩm bên trong túi suốt cả buổi làm việc. Vỏ ngoài bằng vải Oxford bền đẹp, có khả năng chống bám bẩn và rất dễ dàng lau chùi. Kích thước nhỏ gọn nhưng lòng túi đủ rộng để chứa được hộp cơm lớn và bình nước, rất tiện lợi cho nhân viên văn phòng hoặc học sinh sinh viên.',220000,60,180000,'Gia dụng','https://thuvienmuasam.com/uploads/default/original/2X/a/a20a74d97ec98677a13b5c829b4c254e39a37e43.jpeg','Túi'),
    (NULL,'Máy tạo độ ẩm USB','Máy tạo độ ẩm mini sử dụng cổng USB giúp cân bằng độ ẩm không khí trong phòng điều hòa khô hanh, bảo vệ làn da và hệ hô hấp của bạn luôn khỏe mạnh. Sản phẩm hoạt động bằng công nghệ phun sương siêu âm cực kỳ êm ái, hoàn toàn không tạo ra tiếng ồn gây ảnh hưởng đến giấc ngủ hay sự tập trung của bạn khi làm việc. Thiết kế nhỏ gọn tích hợp thêm đèn LED đổi màu sinh động, có thể dùng thay thế cho đèn ngủ trang trí. Chỉ cần cắm vào cổng USB của máy tính là bạn đã có một không gian làm việc tươi mát.',410000,0,330000,'Thiết bị','https://tse3.mm.bing.net/th/id/OIP.dCIq5X5uaI0CjAvuyglNpAHaHa?pid=Api&P=0&h=180','Máy tạo ẩm'),
    (NULL,'Giá đỡ laptop ','Giá đỡ laptop bằng hợp kim nhôm cao cấp giúp nâng cao màn hình máy tính lên ngang tầm mắt người dùng, từ đó cải thiện tư thế ngồi và hạn chế tối đa đau mỏi cổ vai gáy. Thiết kế dạng rỗng thông minh hỗ trợ tản nhiệt cho máy tính hiệu quả hơn trong suốt quá trình sử dụng làm việc lâu dài. Sản phẩm có thể điều chỉnh linh hoạt nhiều mức độ cao khác nhau và gấp gọn lại để mang theo trong balo vô cùng tiện lợi. Chất liệu nhôm chắc chắn cùng các miếng đệm silicon giúp cố định laptop an toàn và ổn định.',520000,50,430000,'Thiết bị','https://bizweb.dktcdn.net/100/210/976/products/12.png?v=1625143835567','Giá đỡ'),
    (NULL,'Bộ vệ sinh laptop 5 món','Hãy luôn giữ cho chiếc máy tính laptop của bạn luôn sạch sẽ và sáng bóng như mới với bộ vệ sinh chuyên dụng 5 trong 1 đầy đủ dụng cụ này. Bộ sản phẩm bao gồm đầy đủ bình xịt dung dịch vệ sinh màn hình, khăn lau sợi microfiber mịn màng, chổi quét bụi bàn phím, dụng cụ thổi bụi và tăm bông chuyên dụng. Sản phẩm giúp loại bỏ hoàn toàn các loại bụi bẩn bám lâu ngày trên màn hình và các kẽ phím khó tiếp cận. Dung dịch vệ sinh hoàn toàn an toàn, không gây hại cho các lớp phủ màn hình hay vỏ máy tính của bạn.',210000,0,170000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134208-7r98o-lppfolqqgfcp1b','Vệ sinh laptop'),
    (NULL,'Đèn cảm biến chuyển động','Đèn cảm biến chuyển động thông minh có khả năng tự động bật sáng khi phát hiện thấy có người đi qua và tự động tắt sau một khoảng thời gian ngắn để tiết kiệm điện năng tối đa. Sản phẩm rất phù hợp để lắp đặt tại các khu vực như hành lang, cầu thang, nhà vệ sinh hoặc lắp đặt ngay bên trong tủ quần áo. Ánh sáng vàng dịu nhẹ tạo cảm giác ấm áp và không gây chói mắt vào ban đêm. Đèn sử dụng pin sạc vô cùng linh hoạt, dễ dàng lắp đặt bằng miếng dán nam châm tiện lợi mà không cần phải khoan tường.',360000,40,310000,'Thiết bị','https://cf.shopee.vn/file/e1e8c4ad70b13fa55bb7523837993e38','Đèn'),
    (NULL,'Sạc nhanh 33W ','Củ sạc nhanh với công suất tối đa lên đến 33W giúp bạn rút ngắn đáng kể thời gian nạp đầy năng lượng cho điện thoại và các thiết bị di động hàng ngày của mình. Sản phẩm hỗ trợ nhiều chuẩn sạc nhanh phổ biến nhất hiện nay, đảm bảo dòng điện đầu ra luôn ổn định và an toàn cho tuổi thọ pin của thiết bị. Thiết bị được tích hợp nhiều lớp bảo vệ thông minh giúp chống quá nhiệt, quá dòng và ngắn mạch đột ngột. Thiết kế củ sạc vô cùng nhỏ gọn, bền bỉ, dễ dàng mang theo trong mọi chuyến hành trình của bạn.',450000,50,390000,'Phụ kiện','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-mausslih0nt850','Sạc'),
    (NULL,'Áo mưa tiện lợi','Áo mưa tiện lợi với chất liệu nilon cao cấp thế hệ mới, vô cùng dày dặn và dẻo dai, giúp bảo vệ bạn hoàn toàn khỏi những trận mưa bất chợt khi đang di chuyển ngoài trời. Thiết kế dạng áo choàng rộng rãi phù hợp cho mọi vóc dáng, giúp che kín toàn bộ cơ thể và có mũ trùm đầu đi kèm dây rút chắc chắn. Sản phẩm có khả năng chống thấm nước tuyệt đối, bạn có thể dễ dàng giũ sạch nước và gấp gọn lại sau khi sử dụng để bỏ vào cốp xe máy. Đây là vật dụng không thể thiếu để bảo vệ sức khỏe của bạn.',70000,200,50000,'Tiện ích','https://tse1.mm.bing.net/th/id/OIP.zH-BtaX4yYn2BnAxjYY8BQHaHa?pid=Api&P=0&h=180','Áo mưa'),
    (NULL,'Bàn phím Bluetooth mini','Bàn phím Bluetooth mini là giải pháp nhập liệu văn bản tuyệt vời cho các loại máy tính bảng, điện thoại di động và cả laptop khi bạn cần di chuyển nhiều nơi. Với kích thước cực kỳ mỏng và gọn nhẹ, bạn có thể dễ dàng mang theo sản phẩm trong túi xách hoặc cặp tài liệu. Các phím bấm của bàn phím có độ nảy rất tốt, khoảng cách phím hợp lý giúp thao tác gõ văn bản diễn ra nhanh chóng và chính xác. Công nghệ kết nối không dây ổn định giúp bạn có thể làm việc hiệu quả trong phạm vi lên đến 10 mét.',650000,40,540000,'Thiết bị','https://down-vn.img.susercontent.com/file/sg-11134201-7rbkm-lnwo2kxb7b1s50','Bàn phím'),
    (NULL,'Loa bluetooth mini','Loa Bluetooth mini tuy sở hữu thiết kế nhỏ gọn nhưng mang lại công suất âm thanh cực kỳ ấn tượng và mạnh mẽ, đủ để lấp đầy không gian phòng cá nhân của bạn bằng âm nhạc chất lượng cao. Sản phẩm tích hợp công nghệ kết nối Bluetooth 5.0 nhanh chóng và ổn định, hỗ trợ phát nhạc mượt mà từ nhiều nguồn khác nhau như điện thoại hay máy tính. Lớp vỏ ngoài được làm từ chất liệu cao cấp có khả năng chống va đập tốt. Pin sạc dung lượng cao cho phép bạn nghe nhạc liên tục suốt nhiều giờ đồng hồ liên tục.',320000,55,260000,'Âm thanh','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-loal7rw9iu47b9','Loa'),


-- NHÓM CUỐI (2 món)
    (NULL,'Đế tản nhiệt laptop','Đế tản nhiệt laptop được trang bị hệ thống quạt làm mát công suất lớn giúp hạ nhiệt độ máy tính hiệu quả, bảo vệ linh kiện quan trọng bên trong và tăng đáng kể tuổi thọ cho máy. Bề mặt đế tản nhiệt được làm từ lưới kim loại giúp thoát nhiệt nhanh chóng và có khả năng chịu lực cực tốt. Bạn có thể dễ dàng điều chỉnh độ nghiêng của đế để tạo ra góc làm việc thoải mái nhất cho cổ tay và mắt khi sử dụng lâu. Đèn LED tích hợp tạo điểm nhấn thẩm mỹ vô cùng đẹp mắt và chuyên nghiệp cho góc máy.',390000,40,320000,'Thiết bị','https://tse3.mm.bing.net/th/id/OIP.IqRTB5-hPiHHHZrXNl8Y1gHaHa?pid=Api&P=0&h=180','Tản nhiệt'),
    (NULL,'Tai nghe gaming RGB','Hãy trải nghiệm thế giới game sống động đỉnh cao với tai nghe gaming chuyên dụng tích hợp hệ thống đèn LED RGB rực rỡ và chuyên nghiệp. Sản phẩm sở hữu màng loa kích thước lớn mang lại âm thanh vòm 7.1 chi tiết, giúp bạn nhận diện chính xác vị trí đối thủ thông qua tiếng bước chân hay tiếng súng nổ từ xa. Phần đệm tai bằng da cao cấp cực kỳ êm ái, có khả năng cách âm tốt và không gây đau tai khi đeo lâu. Micro tích hợp lọc tiếng ồn giúp việc đàm thoại với đồng đội luôn rõ ràng và sắc nét nhất.',750000,30,650000,'Âm thanh','https://product.hstatic.net/1000343056/product/997873f9e28349d3bcb735d0d9ea6dc6.jpg','Tai nghe'),


-- NHÓM PHỤ KIỆN & VĂN PHÒNG
    (NULL,'Cáp Lightning iPhone','Sợi cáp Lightning dành riêng cho các thiết bị iPhone và iPad đảm bảo tốc độ sạc và truyền tải dữ liệu luôn ở mức ổn định nhất trong suốt quá trình sử dụng. Lõi dây được làm từ đồng nguyên chất bọc lớp cách điện dày dặn, giúp giảm thiểu tiêu hao năng lượng và chống nhiễu tín hiệu cực kỳ hiệu quả khi kết nối với máy tính. Vỏ ngoài bằng nhựa TPE bền bỉ, dẻo dai, có khả năng chống gãy gập ở hai đầu đầu cắm giúp tăng tuổi thọ sản phẩm lên đáng kể. Sản phẩm đạt tiêu chuẩn an toàn, không gây hiện tượng nóng máy hay báo lỗi phụ kiện không tương thích, bảo vệ pin thiết bị một cách tối ưu nhất.',160000,100,120000,'Phụ kiện','https://bizweb.dktcdn.net/100/021/944/files/techwear-cap-sac-yungsong-lightning-to-usb-a-6ft.jpg','Cáp sạc'),
    (NULL,'Balo laptop chống nước','Balo laptop chuyên dụng với khả năng chống thấm nước tuyệt vời nhờ chất liệu vải cao cấp, giúp bảo vệ máy tính và tài liệu quan trọng của bạn luôn an toàn dưới mọi điều kiện thời tiết khắc nghiệt. Ngăn đựng laptop có đệm chống sốc dày dặn, phù hợp cho các dòng máy từ 13 đến 15.6 inch, đảm bảo thiết bị không bị va đập khi di chuyển xa. Thiết kế nhiều ngăn chứa thông minh giúp bạn sắp xếp phụ kiện như chuột, sạc, sổ tay và bút viết một cách khoa học và ngăn nắp. Quai đeo và mặt lưng có lớp lưới thoát khí êm ái, mang lại cảm giác thoải mái suốt ngày dài.',450000,45,390000,'Phụ kiện','https://tse4.mm.bing.net/th/id/OIP.P1s2mlIsFXDtwm6Qd9auOgHaHa?pid=Api&P=0&h=180','Balo'),
    (NULL,'Bút bi cao cấp','Bút bi cao cấp với thiết kế thân kim loại sang trọng và tinh tế, mang lại cảm giác cầm đầm tay và vô cùng chắc chắn cho người sử dụng khi viết lách hàng ngày. Mực bút đều màu, khô nhanh tức thì và hoàn toàn không gây hiện tượng tắc mực hay lem giấy, giúp nét chữ của bạn luôn rõ ràng và chuyên nghiệp nhất trong các bản ký kết. Đầu bi làm từ hợp kim siêu bền giúp thao tác ký tên hay viết lách trở nên mượt mà, êm ái trên nhiều loại bề mặt giấy khác nhau. Đây là món quà tặng ý nghĩa dành cho doanh nhân hoặc đồng nghiệp trong các dịp quan trọng hàng năm.',35000,100,25000,'Văn phòng','https://bizweb.dktcdn.net/100/117/539/files/but-ky-cao-cap-picasso-915.jpg','Bút bi'),
    (NULL,'Hộp bút học sinh','Hộp bút học sinh đa năng giúp các bạn trẻ sắp xếp gọn gàng toàn bộ dụng cụ học tập thiết yếu như bút viết, thước kẻ và gôm tẩy vào một nơi duy nhất để dễ dàng tìm kiếm. Sản phẩm được làm từ chất liệu vải canvas bền đẹp hoặc nhựa cao cấp có khả năng chống va đập hiệu quả, bảo vệ đồ dùng bên trong an toàn. Thiết kế nhiều ngăn chứa thông minh cùng họa tiết trẻ trung, bắt mắt tạo thêm nguồn cảm hứng học tập mới mẻ mỗi ngày cho học sinh. Khóa kéo trơn tru bảo vệ đồ dùng không bị rơi mất, rất tiện lợi để bỏ vào cặp sách mang đi học hàng ngày.',110000,60,85000,'Văn phòng','https://down-vn.img.susercontent.com/file/my-11134201-7qul4-lfe1z0tqtyd62f','Hộp bút'),
    (NULL,'Kẹp tài liệu văn phòng','Kẹp tài liệu văn phòng giúp bạn sắp xếp và quản lý các loại giấy tờ hồ sơ một cách khoa học, chuyên nghiệp nhất trong môi trường làm việc bận rộn tại công sở. Sản phẩm được làm từ thép cao cấp có độ đàn hồi cực tốt, giữ chặt giấy tờ mà không làm rách hay biến dạng góc giấy dù kẹp với số lượng lớn tài liệu. Bề mặt kẹp được sơn tĩnh điện chống gỉ sét, bền màu theo thời gian sử dụng lâu dài và mang lại vẻ thẩm mỹ cao. Nhiều kích cỡ khác nhau giúp bạn linh hoạt kẹp tài liệu theo từng mục đích sử dụng. Đây là vật dụng không thể thiếu giúp văn phòng ngăn nắp.',45000,90,30000,'Văn phòng','https://down-vn.img_susercontent.com/file/ec2edaca64b498ac0f56f0d154c24634','Kẹp giấy'),


-- NHÓM TRANG TRÍ & GIA DỤNG
    (NULL,'Đồng hồ treo tường','Đồng hồ treo tường với thiết kế tối giản mang lại vẻ đẹp hiện đại và sang trọng cho không gian sống của gia đình bạn hoặc môi trường làm việc tại văn phòng. Sản phẩm sử dụng máy đồng hồ kim trôi cực êm, hoàn toàn không gây tiếng động tích tắc khó chịu, đảm bảo giấc ngủ yên bình và sự tập trung cao độ cho mọi người. Chữ số hiển thị rõ ràng, sắc nét giúp bạn dễ dàng quan sát thời gian từ khoảng cách xa một cách chính xác nhất. Đây không chỉ là một vật dụng xem giờ mà còn là món đồ trang trí nội thất tuyệt vời, tạo điểm nhấn phong cách cho căn phòng.',260000,25,210000,'Trang trí','https://down-vn.img_susercontent.com/file/db0479a273f1a48b70acddd9d35da18c','Đồng hồ'),
    (NULL,'Đèn ngủ để bàn','Đèn ngủ để bàn mang lại ánh sáng vàng dịu nhẹ, tạo không gian ấm cúng và giúp bạn dễ dàng đi vào giấc ngủ sâu sau một ngày dài làm việc mệt mỏi và căng thẳng. Chụp đèn thiết kế tinh xảo giúp phân tán ánh sáng đều khắp phòng, không gây chói mắt khi bạn đọc sách hay làm việc riêng vào buổi tối muộn. Thân đèn làm từ gỗ tự nhiên chắc chắn mang lại vẻ đẹp sang trọng và đẳng cấp cho phòng ngủ của bạn. Sản phẩm tích hợp công tắc điều chỉnh độ sáng linh hoạt, giúp bạn tùy chỉnh mức độ ánh sáng phù hợp nhất theo tâm trạng mỗi tối.',230000,35,180000,'Trang trí','https://uploads-ssl.webflow.com/5eb51614ce7c0b6b10d42789/5f1ea726cea92f137e0a1a01_den-ngu-de-ban-dep-6.jpg','Đèn ngủ'),
    (NULL,'Chậu cây mini để bàn','Mang không gian xanh tươi mát vào bàn làm việc của bạn với chậu cây mini trang trí vô cùng đáng yêu và tràn đầy sức sống mỗi ngày. Cây được trồng trong chậu sứ cao cấp, có kích thước nhỏ gọn không chiếm nhiều diện tích, rất phù hợp cho các không gian văn phòng hiện đại ngày nay. Việc ngắm nhìn sắc xanh của lá cây giúp giảm căng thẳng, mệtỏi và tăng khả năng tập trung hiệu quả khi làm việc hay học tập căng thẳng. Sản phẩm rất dễ chăm sóc, chỉ cần tưới nước định kỳ là cây có thể phát triển tốt, mang lại sự tươi mới cho không gian cá nhân của bạn.',130000,50,95000,'Trang trí','https://tse3.mm.bing.net/th/id/OIP.71tFpJ84Kepcx3poqU4-SwHaGP','Cây cảnh'),
    (NULL,'Khung ảnh để bàn','Khung ảnh để bàn với thiết kế tinh tế giúp bạn lưu giữ những khoảnh khắc kỷ niệm đáng nhớ nhất bên gia đình, người thân và bạn bè trong suốt những năm tháng qua. Sản phẩm được làm từ chất liệu gỗ hoặc nhựa cao cấp, có mặt kính trong suốt bảo vệ ảnh khỏi bụi bẩn, ẩm mốc và giữ cho màu sắc bức ảnh luôn bền đẹp như mới. Bạn có thể đặt khung ảnh trên bàn làm việc, kệ sách hay tab đầu giường để tạo điểm nhấn ấm áp và thân thuộc cho căn phòng. Kiểu dáng khung hiện đại phù hợp với nhiều phong cách trang trí nội thất khác nhau hiện nay.',150000,40,120000,'Trang trí','https://khunganhgiare.com/wp-content/uploads/2024/05/khung-anh-de-ban-4.jpg','Khung ảnh'),
    (NULL,'Nến thơm thư giãn','Tạo bầu không khí thư thái và dễ chịu cho ngôi nhà với nến thơm được chiết xuất từ tinh dầu thiên nhiên nguyên chất, mang lại mùi hương thanh khiết và nhẹ nhàng. Khi thắp nến, hương thơm dịu nhẹ sẽ lan tỏa khắp căn phòng, giúp xua tan mọi mệt mỏi và mang lại cảm giác bình yên, thư giãn tuyệt đối sau một ngày làm việc bận rộn. Sản phẩm được đựng trong hũ thủy tinh sang trọng, không chỉ tỏa hương mà còn là món đồ trang trí tinh tế cho bàn trà. Nến cháy đều, không tạo khói đen, an toàn cho sức khỏe và giúp cải thiện chất lượng không khí.',200000,30,160000,'Trang trí','https://ofarmfood.com/wp-content/uploads/2024/12/nen-thom-thu-gian-1-1.png','Nến thơm'),
    (NULL,'Máy sấy tóc','Máy sấy tóc công suất mạnh mẽ giúp bạn nhanh chóng làm khô tóc và tạo kiểu dễ dàng ngay tại nhà mà không cần phải ra tiệm làm tóc chuyên nghiệp. Sản phẩm tích hợp nhiều chế độ nhiệt và tốc độ gió khác nhau, bao gồm cả chế độ sấy mát giúp bảo vệ tóc khỏi hư tổn và xơ rối do nhiệt độ cao gây ra. Thiết kế tay cầm chắc chắn, nhẹ nhàng giúp bạn không bị mỏi tay khi sử dụng trong thời gian dài để tạo kiểu phức tạp. Công nghệ ion hiện đại giúp tóc luôn bóng mượt và giữ được độ ẩm tự nhiên nhất. Đây là thiết bị cá nhân không thể thiếu.',460000,20,390000,'Gia dụng','http://giadungphanle.vn/upload/product/eh-na98-k645-1.jpg','Máy sấy'),
    (NULL,'Máy hút bụi mini','Máy hút bụi mini cầm tay là giải pháp dọn dẹp tuyệt vời và nhanh chóng cho các không gian nhỏ hẹp như bàn làm việc, kệ sách hay nội thất bên trong ô tô của bạn. Với lực hút mạnh mẽ ẩn bên trong một thiết kế gọn nhẹ, sản phẩm dễ dàng lấy đi mọi bụi bẩn, vụn thức ăn bám ở những khe hẹp khó tiếp cận nhất bằng tay thông thường. Máy sử dụng pin sạc tiện lợi, cho phép bạn di chuyển tự do mà không bị vướng víu bởi dây điện rườm rà hay giới hạn khoảng cách. Hệ thống lọc bụi thông minh giúp giữ lại các hạt bụi siêu nhỏ, trả lại bầu không khí sạch.',850000,15,760000,'Gia dụng','https://down-vn.img_susercontent.com/file/7faaee999ae01950a89f09437a3b336d','Máy hút bụi'),


-- NHÓM ĐỒ DÙNG
    (NULL,'Bình giữ nhiệt inox','Bình giữ nhiệt chất liệu inox 304 hai lớp với lớp chân không ở giữa giúp giữ nhiệt cho đồ uống cực kỳ hiệu quả trong suốt 12 giờ liên tục mà không làm mất đi hương vị gốc. Sản phẩm không chỉ giữ ấm cho trà, cà phê mà còn giữ lạnh tuyệt vời cho các loại nước ép trái cây trong mùa hè nóng nực. Vỏ ngoài sơn tĩnh điện bền màu, chống trầy xước và mang lại vẻ ngoài tinh tế cho người dùng. Với kích thước vừa vặn, bình dễ dàng đặt trong khay đựng nước của ô tô hoặc túi hông balo, là món quà sức khỏe ý nghĩa dành tặng cho người thân.',350000,30,290000,'Gia dụng','https://images.unsplash.com/photo-1587731340320-78e6a6a14c6c','Bình nước'),
    (NULL,'Hộp cơm giữ nhiệt','Hộp cơm giữ nhiệt đa năng giúp bạn thưởng thức bữa trưa tự nấu thơm ngon và ấm nóng ngay tại văn phòng hay trường học mà không cần sử dụng đến lò vi sóng của công ty. Sản phẩm gồm nhiều ngăn tách biệt giúp giữ trọn hương vị các món ăn mà không bị lẫn mùi, đảm bảo bữa ăn luôn ngon miệng như vừa mới nấu xong. Lớp vỏ cách nhiệt cao cấp đảm bảo giữ nhiệt hiệu quả trong nhiều giờ mà vẫn an toàn khi chạm vào bề mặt bên ngoài. Đây là giải pháp tiết kiệm và đảm bảo vệ sinh thực phẩm, giúp bạn duy trì thói quen ăn uống lành mạnh hàng ngày.',210000,35,170000,'Đồ dùng','https://locknlockvietnam.com/wp-content/uploads/2022/11/bo-hop-com-giu-nhiet-hut-chan-khong-lock-lock-nvy-4-lhc8052s01-1.jpg','Hộp cơm'),
    (NULL,'Ô dù gấp gọn','Ô dù gấp gọn thông minh với khung xương chắc chắn bằng hợp kim, có khả năng chống chịu gió mạnh và bảo vệ bạn hoàn toàn trước những cơn mưa bất chợt hay ánh nắng gay gắt của mùa hè. Vải dù cao cấp có lớp phủ chống tia UV hiệu quả, bảo vệ làn da của bạn tối ưu hơn khi phải đi bộ ngoài trời trong thời gian dài. Với tính năng gấp gọn linh hoạt chỉ bằng một nút bấm, sản phẩm dễ dàng nằm gọn trong túi xách hay cốp xe máy, luôn sẵn sàng đồng hành cùng bạn trên mọi nẻo đường di chuyển. Màu sắc nhã nhặn phù hợp cho mọi lứa tuổi.',150000,50,120000,'Đồ dùng','https://tse2.mm.bing.net/th/id/OIP.kuH1ZLuCyUUhC2v--cRG9wHaHa','Ô dù'),


-- NHÓM QUẦN NAM (Tiếp theo)
    (NULL,'Quần Baggy Vải','Quần Baggy vải nam với thiết kế ống rộng thoải mái đang là xu hướng thời trang cực kỳ được ưa chuộng bởi giới trẻ yêu thích phong cách năng động và phóng khoáng hiện nay. Chất liệu vải thô cao cấp bền bỉ, có khả năng thoáng mát vượt trội giúp người mặc luôn cảm thấy dễ chịu ngay cả trong tiết trời mùa hè nóng nực nhất của Việt Nam. Kiểu dáng này cực kỳ dễ phối đồ theo nhiều phong cách khác nhau từ vintage cổ điển đến streetwear cá tính đầy ấn tượng. Chỉ cần kết hợp khéo léo với một chiếc áo phông basic và giày sneaker là bạn đã có ngay một diện mạo trẻ trung, thu hút mọi ánh nhìn khi xuống phố.',450000,40,380000,'Quần','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-m4psnpa9klhr4c','Quần Baggy'),
    (NULL,'Quần Đùi Thể Thao','Quần đùi thể thao nam chuyên dụng được làm từ chất liệu thun lạnh siêu nhẹ, có khả năng co giãn 4 chiều linh hoạt và sở hữu công nghệ thoát nhiệt cực nhanh giúp cơ thể luôn khô thoáng. Thiết kế xẻ gấu nhẹ tinh tế ở hai bên đùi giúp bạn thực hiện các động tác chạy bộ, squat hoặc tập gym một cách linh hoạt và thoải mái nhất có thể. Phần lưng thun co giãn tốt tích hợp thêm dây rút thông minh để bạn điều chỉnh kích cỡ vòng bụng một cách dễ dàng và chắc chắn. Sản phẩm chính là người bạn đồng hành tin cậy cho những giờ luyện tập cường độ cao hằng ngày giúp bạn nâng cao hiệu suất.',250000,100,180000,'Quần','https://cf.shopee.vn/file/bef12a21ef7ab2d24f79d1bc8ae4cb9c','Quần Đùi'),
    (NULL,'Quần Jean Rách Gối','Quần Jean nam thiết kế rách gối cá tính mang đậm phong cách đường phố bụi bặm, dành riêng cho các chàng trai yêu thích sự phá cách và muốn khẳng định cái tôi cá nhân mạnh mẽ. Chất liệu vải denim dày dặn cao cấp nhưng vẫn được pha thêm sợi co giãn nhẹ giúp người mặc không bị cảm thấy gò bó khi di chuyển hay ngồi lâu. Từng vết sờn rách trên gối được xử lý thủ công tinh xảo, tạo nên vẻ ngoài phóng khoáng, tự do và vô cùng ấn tượng. Bạn có thể dễ dàng phối chiếc quần này cùng với áo hoodie oversize và giày cao cổ để hoàn thiện phong cách thời trang cực chất của mình.',620000,35,520000,'Quần','https://tse3.mm.bing.net/th/id/OIP.MxRfD0jaNFuD361nCwuqqgHaJ4','Quần Jean'),
    (NULL,'Quần Cargo Túi Hộp','Quần Cargo túi hộp mang phong cách quân đội mạnh mẽ và nam tính với thiết kế nhiều ngăn túi tiện dụng nằm ở hai bên đùi và phía sau, giúp bạn thoải mái đựng các vật dụng cá nhân. Chất liệu vải kaki thun bền chắc, có khả năng chịu được ma sát tốt và cực kỳ bền màu, rất phù hợp cho các chuyến đi phượt dài ngày hoặc những hoạt động dã ngoại ngoài trời thú vị. Form dáng rộng rãi mang lại sự thoải mái tối đa cho người mặc trong suốt hành trình di chuyển hay vận động mạnh. Đây là sự lựa chọn hoàn hảo cho những quý ông yêu thích vẻ đẹp thực dụng, mạnh mẽ và sự tiện lợi tối đa.',540000,25,460000,'Quần','https://tse4.mm.bing.net/th/id/OIP.9m3Yq6PqSc92-fftnYis7gHaHa','Quần Cargo'),
    (NULL,'Quần Vải Đũi Mùa Hè','Quần vải đũi nam với đặc tính siêu mỏng nhẹ, thoáng mát và khả năng thấm hút mồ hôi cực tốt là trang phục không thể thiếu trong tủ đồ mùa hè của bất kỳ chàng trai nào. Chất liệu vải đũi tự nhiên cao cấp vô cùng thân thiện với làn da, mang lại cảm giác mát lạnh và dễ chịu mỗi khi chạm vào hay vận động dưới nắng nóng. Thiết kế ống suông rộng kết hợp cùng cạp chun linh hoạt giúp bạn luôn cảm thấy thoải mái nhất khi đi biển, dạo phố dã ngoại hoặc mặc ở nhà. Màu sắc pastel nhẹ nhàng của quần rất dễ phối cùng các loại áo sơ mi ngắn tay, áo ba lỗ hay dép sandal.',360000,55,290000,'Quần','https://down-vn.img.susercontent.com/file/0d308975db92cf85477f2b739b8f5132','Quần Đũi'),


-- NHÓM GIÀY NAM
    (NULL,'Giày Sneaker Trắng','Giày Sneaker nam màu trắng với thiết kế basic mang phong cách tối giản nhưng vô cùng thời thượng, giúp bạn dễ dàng phối hợp với mọi loại trang phục từ quần jean đến quần tây công sở. Sản phẩm được làm từ chất liệu da tổng hợp cao cấp, có khả năng chống bám bẩn vượt trội và rất dễ dàng lau chùi vệ sinh sau mỗi lần sử dụng ngoài trời. Phần đế cao su nguyên khối có độ đàn hồi cao kết hợp cùng thiết kế rãnh chống trượt thông minh giúp bảo vệ đôi chân bạn an toàn trong từng bước đi. Đây là món đồ thời trang bền vững, thanh lịch và không bao giờ lo bị lỗi mốt theo thời gian.',850000,25,650000,'Giày','https://cf.shopee.vn/file/bd4104b5a81ee2a4cefaefa66f6751c2','Sneaker'),
    (NULL,'Giày Tây Oxford','Giày tây dáng Oxford là biểu tượng của sự sang trọng và lịch lãm, được thiết kế dành riêng cho các quý ông trong những sự kiện quan trọng, lễ cưới hoặc môi trường công sở chuyên nghiệp. Sản phẩm được chế tác hoàn toàn từ da bò thật 100%, sở hữu bề mặt bóng mịn tự nhiên và đặc biệt là càng sử dụng lâu da sẽ càng trở nên mềm mại, ôm chân hơn. Thiết kế dây buộc tinh tế kết hợp cùng phom dáng mũi giày thon gọn tạo nên một vẻ ngoài vô cùng thanh lịch, đĩnh đạc và đẳng cấp. Lớp lót đệm bên trong siêu êm ái giúp bạn thoải mái di chuyển suốt ngày dài làm việc.',1500000,15,1250000,'Giày','https://tse4.mm.bing.net/th/id/OIP.q8hJridu-mrXZYQjzuxbzwHaHa','Giày Tây'),
    (NULL,'Giày Lười Loafer','Giày lười Loafer mang đến sự kết hợp hoàn hảo giữa vẻ đẹp lịch sự truyền thống và tính tiện dụng tối đa khi bạn có thể xỏ chân vào ngay mà không cần tốn thời gian buộc dây phức tạp. Sản phẩm sở hữu thiết kế hiện đại với các chi tiết trang trí tinh xảo trên mui giày, phù hợp cho cả đi làm văn phòng lẫn đi chơi dạo phố cuối tuần cùng bạn bè. Chất liệu da bò cao cấp cùng công nghệ đế đúc siêu nhẹ giúp giảm đáng kể trọng lượng đôi giày, mang lại cảm giác nhẹ tênh và linh hoạt trong từng bước chuyển động hàng ngày. Đây là lựa chọn hàng đầu cho phái mạnh.',1100000,20,890000,'Giày','https://tse2.mm.bing.net/th/id/OIP.AsEOJqd8qu6KFAaEXEWkLgHaHa','Giày Lười'),
    (NULL,'Giày Chạy Bộ Pro','Giày chạy bộ chuyên nghiệp được trang bị công nghệ đệm khí tiên tiến ở phần đế giúp giảm chấn thương và bảo vệ tối đa khớp gối của bạn trong suốt quá trình tập luyện cường độ cao. Thân giày được làm từ chất liệu vải lưới mesh thoáng khí cao cấp, hỗ trợ thoát hơi nước nhanh chóng và luôn giữ cho đôi chân bạn khô ráo, thoải mái. Trọng lượng siêu nhẹ cùng thiết kế ôm sát vòng bàn chân một cách khoa học giúp bạn tự tin bứt phá tốc độ một cách dễ dàng nhất trên mọi cung đường. Sản phẩm là sự lựa chọn tuyệt vời cho các vận động viên và người yêu chạy bộ.',1200000,40,950000,'Giày','https://tse4.mm.bing.net/th/id/OIP.d3ekDhmh9RNi7MG-v5BVigHaHa','Giày Chạy'),
    (NULL,'Giày Chelsea Boots','Giày Chelsea Boots nam với thiết kế không dây đặc trưng và hai miếng chun co giãn bên hông mang lại vẻ ngoài cực kỳ lịch lãm, lãng tử và đầy cuốn hút cho phái mạnh hiện đại. Sản phẩm được làm từ chất liệu da lộn cao cấp với tông màu trầm ấm, cực kỳ phù hợp để phối cùng các loại quần jean rách bụi bặm hoặc quần kaki công sở thanh lịch. Phần đế giày được làm từ sự kết hợp giữa gỗ và cao su chịu lực tốt, đảm bảo độ bền cao và sự chắc chắn theo thời gian sử dụng. Đây là món đồ mang đậm phong cách thời trang cổ điển Anh quốc dành cho quý ông sành điệu.',1750000,12,1450000,'Giày','https://tse4.mm.bing.net/th/id/OIP.EKI3tqXHmEjrTCHLOnj52QHaHa','Giày Boots'),
    (NULL,'Giày Đá Bóng Sân Cỏ','Giày đá bóng chuyên dụng cho sân cỏ nhân tạo với hệ thống đinh dăm bám đường cực tốt, giúp cầu thủ duy trì sự ổn định tuyệt đối trong các pha bứt tốc nhanh và ngoặt bóng lắt léo. Phần thân giày được làm từ chất liệu tổng hợp siêu bền, có khả năng chống thấm nước và rất dễ dàng lau chùi sau mỗi trận đấu căng thẳng. Thiết kế ôm chân tối ưu giúp tăng cảm giác bóng chân thực, hỗ trợ bạn thực hiện những cú sút xa hay đường chuyền chính xác nhất. Đây là món vũ khí không thể thiếu cho các anh em đam mê bóng đá phong trào mỗi tối.',680000,50,550000,'Giày','https://dothethao.net.vn/wp-content/uploads/2020/05/112650574_o.jpg','Giày Bóng Đá'),
    (NULL,'Giày Cao Cổ Streetwear','Giày sneaker cao cổ phong cách streetwear mang lại diện mạo cá tính, nổi bật và vô cùng phong cách cho các bạn trẻ yêu thích văn hóa Hip-hop đường phố. Thiết kế phối màu ấn tượng cùng các chi tiết trang trí bằng nhựa TPU bền bỉ tạo nên vẻ ngoài hiện đại và mạnh mẽ cho đôi giày. Lớp đệm lót ở vùng cổ chân dày dặn giúp bảo vệ tối đa vùng cá chân và mang lại sự êm ái khi bạn di chuyển liên tục trong thời gian dài. Sản phẩm cực kỳ bắt mắt khi kết hợp cùng các loại quần túi hộp cargo hoặc quần jogger dạo phố cực ngầu.',950000,28,820000,'Giày','https://auguris.vn/wp-content/uploads/2025/05/9-5.jpg','Sneaker Cao Cổ'),
    (NULL,'Sandal Nam Quai Ngang','Sandal nam thiết kế quai ngang bản to vô cùng chắc chắn và trẻ trung, là sự lựa chọn hoàn hảo nhất cho những buổi đi dạo biển, đi du lịch dã ngoại hoặc đi chơi hằng ngày. Chất liệu quai bằng vải dù siêu bền bỉ kết hợp cùng phần đế cao su đúc nguyên khối chống mài mòn cực tốt trên nhiều bề mặt khác nhau. Thiết kế thông thoáng giúp đôi chân bạn luôn mát mẻ, khô ráo và không bị bí bách trong thời tiết mùa hè nắng nóng. Sản phẩm có tích hợp chốt khóa điều chỉnh linh hoạt, phù hợp với nhiều kích cỡ chân khác nhau của phái nam.',400000,75,320000,'Giày','https://down-vn.img.susercontent.com/file/sg-11134201-22110-is08euuvqrjv98','Sandal Nam'),
    (NULL,'Giày Leo Núi Chống Nước','Giày leo núi và đi phượt chuyên dụng với công nghệ màng lọc chống thấm nước tuyệt đối nhưng vẫn đảm bảo độ thoát khí tối ưu cho đôi chân của người sử dụng. Phần đế giày được thiết kế đặc biệt với các rãnh sâu và gai cao su cứng giúp tăng độ bám vững chắc trên các bề mặt đá trơn trượt hoặc bùn đất lầy lội. Phần mũi giày bọc thép nhẹ giúp bảo vệ ngón chân khỏi va đập mạnh với đá sắc nhọn dọc đường đi. Đây là trang phục bảo hộ quan trọng nhất cho những ai đam mê khám phá thiên nhiên hoang dã và chinh phục đỉnh cao.',1950000,18,1680000,'Giày','https://adanaphuot.com/upload/sanpham/giay-leo-nui-cao-co-humtto-240783a-06-7542.jpg','Giày Leo Núi'),
    (NULL,'Giày Slip-on Vải','Giày Slip-on vải với thiết kế đơn giản, nhẹ nhàng và vô cùng tiện lợi khi bạn có thể xỏ chân vào ngay mà không cần tốn thời gian buộc dây rườm rà. Chất liệu vải canvas thoáng mát kết hợp cùng lớp lót bông siêu êm ái mang lại sự dễ chịu tuyệt vời cho các hoạt động đi dạo, đi học hay đi làm hằng ngày. Đế giày bằng nhựa dẻo có độ bền cao, nhẹ nhàng và chống trơn trượt hiệu quả trên nhiều loại bề mặt sàn khác nhau. Sản phẩm có nhiều màu sắc trẻ trung, trung tính, cực kỳ phù hợp cho cả học sinh và sinh viên năng động.',350000,90,280000,'Giày','https://down-vn.img.susercontent.com/file/sg-11134201-7qvef-lfw14vq7fgnie4','Giày Slip-on'),


-- NHÓM MŨ / NÓN
    (NULL,'Mũ Lưỡi Trai Cotton','Mũ lưỡi trai phong cách cổ điển được làm từ vải 100% cotton thoáng mát, giúp thấm hút mồ hôi cực tốt và mang lại cảm giác dễ chịu dưới ánh nắng mặt trời gay gắt. Thiết kế mũ có tích hợp chốt điều chỉnh kích cỡ linh hoạt ở phía sau, giúp phù hợp hoàn hảo với mọi vòng đầu của cả nam và nữ giới. Form mũ được may cứng cáp, đường chỉ sắc sảo cùng bảng màu sắc đa dạng giúp bạn dễ dàng tạo điểm nhấn cá tính cho bộ trang phục dạo phố hàng ngày. Đây là phụ kiện thời trang vô cùng năng động và thực dụng cho mọi dịp.',220000,100,150000,'Mũ','https://tse2.mm.bing.net/th/id/OIP.jy8XLpdJAdVkTVP-Dd_WnwHaHa','Mũ Lưỡi Trai'),
    (NULL,'Mũ Bucket Canvas','Mũ Bucket tai bèo đang là xu hướng thời trang đường phố cực kỳ hot dành cho giới trẻ yêu thích sự phá cách và độc đáo. Sản phẩm có thiết kế vành tròn đặc trưng giúp che chắn nắng hiệu quả từ mọi góc độ, đồng thời tạo nên một diện mạo cực kỳ thời thượng và "chill" cho người đội. Chất liệu vải canvas dày dặn cao cấp, bền bỉ và có khả năng giữ form cực tốt ngay cả khi bạn thường xuyên gấp gọn bỏ vào balo. Đây là phụ kiện lý tưởng cho các chuyến dã ngoại, chụp ảnh ngoại cảnh hoặc tham gia lễ hội âm nhạc sôi động.',250000,80,180000,'Mũ','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lfihtcxjdx855f','Mũ Bucket'),
    (NULL,'Mũ Len Beanie','Mũ len Beanie là phụ kiện giữ ấm tuyệt vời và mang đậm phong cách lãng tử cho phái mạnh trong những ngày mùa đông lạnh giá. Sản phẩm được dệt từ sợi len cotton mềm mịn cao cấp, có độ co giãn cực tốt và hoàn toàn không gây ngứa hay khó chịu cho vùng da đầu nhạy cảm. Thiết kế đơn giản với kiểu dáng ôm sát giúp giữ nhiệt cơ thể hiệu quả và rất dễ dàng phối cùng các loại áo hoodie, áo len hay áo khoác denim. Mũ có nhiều tông màu trung tính sang trọng, là điểm nhấn ấm áp và thời trang cho diện mạo của bạn.',180000,70,120000,'Mũ','https://tse3.mm.bing.net/th/id/OIP._HUpDMIgRezmmIsBzo5E2AHaHa','Mũ Len'),
    (NULL,'Mũ Snapback Hip-hop','Mũ Snapback với phần lưỡi phẳng đặc trưng và form mũ cao mang đậm phong cách văn hóa Hip-hop đường phố đầy mạnh mẽ và cá tính. Mặt trước của mũ thường được thêu chữ hoặc logo nổi bật với công nghệ thêu 3D, tạo nên nét riêng biệt hoàn toàn cho người sử dụng. Khóa nhựa bấm phía sau cho phép bạn điều chỉnh độ rộng của mũ một cách nhanh chóng, chắc chắn và cực kỳ bền bỉ theo thời gian. Sản phẩm cực kỳ phù hợp khi diện cùng các trang phục oversize, giày sneaker để tạo nên phong cách thời trang chuẩn streetwear.',290000,45,220000,'Mũ','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-m3cbuvc41z1k35','Mũ Snapback'),
    (NULL,'Mũ Fedora Sang Trọng','Mũ Fedora cổ điển với vành rộng vừa phải và dải ruy băng lụa cao cấp bao quanh thân mũ mang lại vẻ ngoài cực kỳ lịch lãm, lãng tử như các quý ông châu Âu thời xưa. Sản phẩm được làm hoàn toàn từ chất liệu nỉ cao cấp, có độ mịn màng và khả năng giữ form dáng cực chuẩn theo thời gian dài sử dụng. Đây là món phụ kiện tuyệt vời dành cho những ai muốn tạo sự khác biệt, đẳng cấp trong các buổi tiệc cưới, sự kiện thời trang hoặc các buổi chụp hình nghệ thuật. Mũ Fedora sẽ giúp nâng tầm bộ suit của bạn lên tầm cao mới.',550000,15,450000,'Mũ','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ltyw6sdvw7xbd3','Mũ Fedora'),


-- NHÓM GIA DỤNG / ĐIỆN TỬ
    (NULL,'Máy Pha Cà Phê Mini','Máy pha cà phê Espresso mini mang đến trải nghiệm thưởng thức cà phê chuẩn vị nhà hàng ngay tại không gian sống hoặc văn phòng làm việc của bạn mỗi ngày. Sản phẩm sở hữu hệ thống áp suất bơm mạnh mẽ đạt chuẩn quốc tế giúp chiết xuất trọn vẹn hương vị tinh túy nhất từ hạt cà phê, tạo nên lớp crema dày mịn và quyến rũ trên bề mặt. Thiết kế máy vô cùng nhỏ gọn, sang trọng với các nút điều khiển trực quan rất dễ sử dụng ngay cả cho người mới bắt đầu tìm hiểu về cà phê. Đây là thiết bị lý tưởng để bạn khởi đầu một ngày mới tràn đầy năng lượng và cảm hứng sáng tạo.',2900000,15,2500000,'Gia dụng','https://img.websosanh.vn/v10/users/review/images/2s2ztlzd59q6j/1542883521947_7130654.jpg','Máy pha cà phê'),
    (NULL,'Robot Hút Bụi Tự Động','Robot hút bụi thông minh chính là giải pháp giải phóng sức lao động tối ưu nhất cho các gia đình hiện đại bận rộn trong cuộc sống ngày nay. Sản phẩm tích hợp hệ thống cảm biến chống va chạm và chống rơi tiên tiến, cho phép robot tự động lập bản đồ căn phòng và làm sạch mọi ngóc ngách, gầm giường, gầm tủ một cách vô cùng hiệu quả. Với lực hút mạnh mẽ và khả năng tự động quay về trạm sạc khi pin yếu, robot đảm bảo sàn nhà bạn luôn sạch bóng mà không cần sự can thiệp của con người. Bạn có thể dễ dàng điều khiển và hẹn giờ làm sạch qua ứng dụng.',6500000,10,5800000,'Gia dụng','https://tse3.mm.bing.net/th/id/OIP.yzNz0rtZ6mvrxiYWaun2vQHaHa','Robot hút bụi'),
    (NULL,'Nồi Chiên Không Dầu Pro','Nồi chiên không dầu thế hệ mới giúp bạn dễ dàng chế biến những món chiên nướng thơm ngon, giòn rụm mà không cần sử dụng đến dầu mỡ, từ đó bảo vệ tối đa sức khỏe tim mạch cho cả gia đình. Công nghệ lưu thông khí nóng 360 độ với tốc độ cao giúp thực phẩm chín đều từ trong ra ngoài, giữ trọn vẹn độ ẩm và các dưỡng chất tự nhiên quý giá bên trong thực phẩm. Lòng nồi được phủ lớp chống dính cao cấp giúp việc vệ sinh sau khi nấu trở nên vô cùng nhanh chóng và đơn giản. Thiết bị nhà bếp hiện đại này giúp việc nội trợ trở nên an tâm và nhẹ nhàng hơn.',2100000,25,1850000,'Gia dụng','https://xiaomihaiduong.vn/wp-content/uploads/2023/09/xiaomihaiduong.vn-noi-chien-khong-dau-xiaomi-smart-air-fryer-pro-4l-avatar.jpg','Nồi chiên'),
    (NULL,'Ấm Siêu Tốc Thủy Tinh','Ấm đun nước siêu tốc với thân bình làm hoàn toàn bằng thủy tinh chịu nhiệt cao cấp, cho phép bạn quan sát quá trình đun sôi nước bên trong một cách rõ ràng và thú vị. Hệ thống đèn LED xanh dương bao quanh chân ấm tự động bật sáng khi hoạt động, tạo nên hiệu ứng thị giác hiện đại và sang trọng cho không gian bếp nhà bạn. Ấm tích hợp rơ-le tự ngắt thông minh khi nước đạt độ sôi hoặc khi ấm cạn nước, đảm bảo an toàn tuyệt đối chống cháy nổ cho gia đình. Đây là món đồ gia dụng tinh tế kết hợp hoàn hảo giữa thẩm mỹ và tính năng tiện dụng nhất.',550000,40,450000,'Gia dụng','https://tse1.mm.bing.net/th/id/OIP.kVwxKyqYaMdo73cvJ5U9vwHaHa','Ấm Siêu Tốc'),
    (NULL,'Máy Xay Sinh Tố Đa Năng','Máy xay sinh tố công suất lớn với lưỡi dao bằng thép không gỉ sắc bén có khả năng xay nhuyễn mọi loại trái cây, rau củ và cả đá viên cứng trong tích tắc. Bộ sản phẩm đi kèm nhiều cối xay với kích thước khác nhau phù hợp cho việc xay thịt, xay hạt khô hay làm sinh tố hằng ngày cho cả gia đình một cách đa dạng. Chân đế máy có lực hút chân không giúp cố định chắc chắn trên mặt bàn bếp, giúp giảm đáng kể rung lắc và tiếng ồn khi vận hành ở cường độ cao. Đây chính là trợ thủ đắc lực giúp bạn bổ sung lượng vitamin cần thiết mỗi ngày một cách dễ dàng.',950000,30,820000,'Gia dụng','https://down-vn.img.susercontent.com/file/sg-11134201-7rdvi-lxsy5ohzwsxy9d','Máy Xay'),
    (NULL,'Bếp Từ Đơn Cảm Ứng','Bếp từ đơn với mặt kính Ceramic cao cấp có khả năng chịu nhiệt cực tốt và rất dễ dàng lau chùi vệ sinh sạch sẽ sau mỗi lần nấu nướng vất vả. Bảng điều khiển cảm ứng thông minh tích hợp nhiều chế độ nấu tự động tiện lợi như nấu lẩu, xào rau, nấu súp giúp bạn tiết kiệm được nhiều thời gian chuẩn bị bữa ăn hàng ngày. Công suất đun nấu cực nhanh và hiệu quả chuyển đổi nhiệt cao giúp giảm thiểu tối đa hao phí điện năng so với các dòng bếp hồng ngoại. Thiết kế siêu mỏng và gọn nhẹ rất phù hợp cho các căn hộ nhỏ hoặc các buổi liên hoan lẩu.',1150000,20,950000,'Gia dụng','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ln0etqflhann6d','Bếp Từ'),
    (NULL,'Lò Vi Sóng Có Nướng','Lò vi sóng hiện đại tích hợp thêm tính năng nướng vô cùng tiện lợi, giúp bạn vừa có thể rã đông, hâm nóng thực phẩm nhanh chóng vừa có thể chế biến các món nướng giòn ngon cho gia đình. Khoang lò rộng rãi với lớp phủ chống dính cao cấp và hệ thống đèn chiếu sáng bên trong giúp bạn dễ dàng theo dõi toàn bộ quá trình nấu nướng. Hệ thống quạt đối lưu thông minh giúp nhiệt lượng tỏa đều khắp khoang lò, đảm bảo món ăn luôn chín ngon đúng vị và đẹp mắt. Bảng điều khiển cơ bền bỉ với các mốc thời gian rõ ràng, cực kỳ dễ sử dụng.',2450000,12,2100000,'Gia dụng','https://cdn.mediamart.vn/images/product/noi-chien-khong-dau-da-nang-ket-hop-vi-song.jpg','Lò Vi Sóng'),
    (NULL,'Quạt Tháp Không Cánh','Quạt tháp không cánh với công nghệ khuếch tán gió êm ái hiện đại, mang lại luồng khí mát dịu tự nhiên như gió trời mà hoàn toàn không gây ra tiếng ồn khó chịu cho giấc ngủ. Thiết kế không cánh quạt đảm bảo an toàn tuyệt đối cho các gia đình có trẻ nhỏ và vật nuôi nghịch ngợm, đồng thời rất dễ dàng để lau chùi vệ sinh hằng ngày. Quạt tích hợp màn hình hiển thị nhiệt độ phòng thông minh và chế độ xoay 90 độ giúp lan tỏa khí mát rộng khắp mọi vị trí trong căn phòng. Kiểu dáng tháp sang trọng biến chiếc quạt thành món đồ trang trí hiện đại.',2200000,15,1850000,'Gia dụng','https://giadungphanle.vn/upload/product/ts9175_1.jpg','Quạt Tháp'),
    (NULL,'Máy Lọc Nước RO','Máy lọc nước công nghệ RO với hệ thống 9 lõi lọc giúp loại bỏ hoàn toàn các loại vi khuẩn, kim loại nặng và các hóa chất độc hại tồn dư trong nguồn nước sinh hoạt hằng ngày. Sản phẩm bổ sung thêm các khoáng chất có lợi cho sức khỏe, mang lại nguồn nước tinh khiết và vị ngọt mát tự nhiên cho cả gia đình sử dụng trực tiếp. Thiết kế tủ kính cường lực sang trọng và đẳng cấp, phù hợp đặt tại phòng bếp gia đình hoặc văn phòng làm việc. Hệ thống tự động báo lỗi và thông báo thời gian thay lõi giúp bạn luôn an tâm tuyệt đối.',5500000,8,4800000,'Gia dụng','https://fpt123.net/uploads/images/may-loc-nuoc/may-loc-nuoc-kangaroo.jpg','Máy Lọc Nước'),
    (NULL,'Camera Giám Sát Wifi','Camera an ninh kết nối Wifi thế hệ mới cho phép bạn dễ dàng giám sát ngôi nhà, cửa hàng hay văn phòng của mình từ xa thông qua ứng dụng trên điện thoại mọi lúc mọi nơi. Sản phẩm được trang bị cảm biến hồng ngoại thông minh giúp quan sát ban đêm cực kỳ rõ nét như ban ngày và tích hợp thêm tính năng đàm thoại hai chiều vô cùng tiện lợi. Hệ thống cảnh báo chuyển động thông minh sẽ ngay lập tức gửi thông báo khẩn cấp về điện thoại khi phát hiện có người đột nhập, mang lại sự an tâm tuyệt đối cho gia đình bạn. Thiết kế camera rất nhỏ gọn và dễ lắp đặt.',890000,55,750000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-m4fvvj0bqxswad','Camera Wifi'),

-- NHÓM THIẾT BỊ CÔNG NGHỆ
    (NULL,'Sạc Không Dây 3 Trong 1','Đế sạc không dây đa năng thế hệ mới cho phép bạn sạc cùng lúc iPhone, Apple Watch và tai nghe Airpods một cách vô cùng gọn gàng và thẩm mỹ ngay trên bàn làm việc hoặc tab đầu giường. Công nghệ sạc thông minh tiên tiến tích hợp bên trong giúp tự động nhận diện thiết bị và điều chỉnh công suất sạc phù hợp nhất để bảo vệ tuổi thọ pin tối ưu cho các thiết bị đắt tiền của bạn. Thiết kế đế sạc tinh tế có đệm cao su chống trượt chắc chắn và đèn LED báo trạng thái sạc dịu nhẹ, giúp không gian làm việc của bạn trở nên chuyên nghiệp, hiện đại và sạch sẽ hơn bao giờ hết. Đây là món phụ kiện công nghệ cần có để loại bỏ hoàn toàn các loại dây cáp rườm rà.',790000,42,680000,'Thiết bị','https://bizweb.dktcdn.net/thumb/1024x1024/100/425/492/products/de-sac-khong-day-20w-swan-3in1-wireless-magnetic-charging-bracket.jpg','Sạc Không Dây'),
    (NULL,'Hub USB-C 8 Trong 1','Bộ chuyển đổi Hub đa năng tích hợp 8 cổng kết nối khác nhau giúp mở rộng tối đa khả năng kết nối cho các dòng laptop siêu mỏng chỉ có cổng USB-C đời mới hiện nay. Sản phẩm bao gồm đầy đủ các cổng ăn chơi như HDMI 4K sắc nét, khe cắm thẻ nhớ SD/TF tiện lợi, cổng mạng LAN tốc độ cao và nhiều cổng USB 3.0 giúp truyền tải dữ liệu dung lượng lớn một cách nhanh chóng nhất. Vỏ ngoài của thiết bị được làm bằng nhôm nguyên khối tản nhiệt cực tốt, giúp bảo vệ mạch điện bên trong luôn hoạt động ổn định dù bạn có sử dụng đồng thời nhiều thiết bị cùng lúc. Thiết kế nhỏ gọn giúp bạn dễ dàng mang theo trong túi xách.',1050000,50,890000,'Thiết bị','https://aukeyvietnam.com/wp-content/uploads/2021/04/C71-1.jpg','Hub USB-C'),
    (NULL,'Chuột Không Dây Ergonomic','Chuột máy tính không dây cao cấp với thiết kế công thái học (Ergonomic) uốn lượn theo dáng bàn tay giúp người dùng giảm thiểu tối đa tình trạng mỏi cổ tay và ngón tay khi phải làm việc liên tục suốt cả ngày dài. Sản phẩm trang bị mắt đọc laser có độ nhạy cực cao, hoạt động mượt mà và chính xác trên hầu hết mọi bề mặt kể cả mặt kính mà không cần đến lót chuột chuyên dụng. Các nút bấm được tích hợp công nghệ Silent giúp hoạt động im lặng hoàn toàn, rất phù hợp cho môi trường văn phòng chuyên nghiệp hoặc làm việc tại nhà vào ban đêm mà không ảnh hưởng đến người xung quanh. Kết nối không dây 2.4GHz ổn định trong phạm vi 10 mét.',520000,70,450000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7ras8-m4mxy0cu2qknbd','Chuột Ergonomic'),
    (NULL,'Bút Trình Chiếu Laser','Bút trình chiếu chuyên nghiệp là công cụ hỗ trợ đắc lực không thể thiếu cho giáo viên, giảng viên và nhân viên văn phòng trong các buổi diễn thuyết, hội thảo hoặc giảng dạy trên lớp hàng ngày. Sản phẩm tích hợp đèn laser đỏ rõ nét để người dùng dễ dàng nhấn mạnh vào các nội dung quan trọng trên màn hình và hệ thống phím điều khiển slide từ xa vô cùng tiện lợi. Công nghệ kết nối không dây ổn định cho phép bạn di chuyển tự do trong phòng với khoảng cách lên đến 20 mét mà vẫn điều chỉnh chính xác tuyệt đối. Thiết kế nhỏ gọn như một cây bút bi thông thường giúp bạn dễ dàng cầm nắm và cất giữ.',400000,90,320000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lpqk9wwoihpza6','Bút Trình Chiếu'),
    (NULL,'Tay Cầm Chơi Game','Tay cầm chơi game không dây cao cấp tương thích hoàn hảo với PC, điện thoại thông minh và các dòng máy chơi game Console, mang lại trải nghiệm điều khiển mượt mà trong các tựa game hành động kịch tính. Sản phẩm sở hữu thiết kế ôm sát lòng bàn tay, phím bấm có độ nảy cực tốt và cần analog siêu nhạy giúp bạn thực hiện các combo chiêu thức chính xác nhất trong các trận đấu căng thẳng. Hệ thống rung phản hồi kép thông minh giúp tăng cảm giác chân thực theo từng nhịp chuyển động trong thế giới ảo. Pin sạc dung lượng cao tích hợp bên trong cho phép bạn chinh chiến suốt 10 giờ liên tục chỉ với một lần sạc đầy.',920000,32,780000,'Thiết bị','https://beegaming.com.vn/wp-content/uploads/2022/10/tay-cam-choi-game-khong-day-dareu-h101x-black-beegaming-6.jpg','Tay Cầm Game'),
    (NULL,'Webcam 2K Siêu Nét','Webcam độ phân giải 2K cung cấp chất lượng hình ảnh sắc nét đến từng chi tiết và màu sắc trung thực, sống động cho các buổi họp trực tuyến, học tập online hoặc livestream sáng tạo nội dung chuyên nghiệp. Sản phẩm tích hợp hệ thống mic thu âm kép có khả năng lọc tiếng ồn xung quanh hiệu quả, đảm bảo âm thanh truyền đi luôn rõ ràng và không bị nhiễu tạp âm. Thiết kế chân đế linh hoạt giúp bạn dễ dàng kẹp lên màn hình máy tính hoặc đặt cố định chắc chắn trên bàn làm việc. Tính năng tự động lấy nét (Auto Focus) cực nhanh giúp bạn luôn nổi bật và rõ ràng trong mọi khung hình di chuyển hằng ngày.',1350000,22,1150000,'Thiết bị','https://down-vn.img.susercontent.com/file/vn-11134207-7qukw-lfi6wvm5jf5h6c','Webcam'),


-- NHÓM PHỤ KIỆN GAMING
    (NULL,'Bàn Phím Cơ RGB Pro','Bàn phím cơ chuyên dụng dành riêng cho game thủ với hệ thống đèn LED RGB 16.8 triệu màu có thể tùy chỉnh nhiều hiệu ứng ánh sáng sống động thông qua phần mềm. Sản phẩm sử dụng Blue Switch cao cấp mang lại cảm giác gõ lạch cạch cực kỳ phấn khích và độ bền cơ học lên đến hơn 50 triệu lần nhấn phím liên tục. Thiết kế layout gọn gàng giúp tối ưu không gian bàn làm việc cùng tính năng Anti-ghosting toàn diện giúp các game thủ thực hiện những combo chiêu thức chính xác tuyệt đối trong các trận đấu kịch tính và căng thẳng. Đây chính là vũ khí tối thượng giúp bạn chinh phục mọi đỉnh cao trong ván đấu.',1600000,40,1250000,'Thiết bị','https://tse3.mm.bing.net/th/id/OIP.otZipsl8gKLTJjAj0FCIFwHaDf','Bàn phím cơ'),
    (NULL,'Chuột Gaming Không Dây','Chuột Gaming sở hữu mắt đọc quang học độ phân giải cao lên đến 16000 DPI, cho phép người dùng điều chỉnh độ nhạy linh hoạt thông qua nút bấm vật lý để phù hợp với nhiều tựa game khác nhau từ FPS tốc độ cao đến MOBA cần độ chính xác. Công nghệ kết nối không dây tốc độ cao đảm bảo độ trễ gần như bằng không, mang lại trải nghiệm mượt mà như đang sử dụng chuột có dây thông thường. Thiết kế công thái học ôm sát lòng bàn tay giúp giảm thiểu tối đa tình trạng mỏi cổ tay khi chơi game trong thời gian dài liên tục. Bề mặt nhám cao cấp giúp chống bám mồ hôi hiệu quả.',1200000,35,950000,'Gaming','https://hanoicomputercdn.com/media/product/69600_chuot_gaming_khong_day_steelseries_aerox_5_wireless.jpg','Chuột Gaming'),
    (NULL,'Tai Nghe Gaming Surround','Tai nghe gaming tích hợp công nghệ âm thanh vòm Surround 7.1 giúp bạn nghe rõ từng bước chân và định vị chính xác vị trí tiếng súng của kẻ địch trong các trận đấu bắn súng sinh tồn kịch tính. Màng loa kích thước lớn mang lại âm bass mạnh mẽ, rung động theo từng hành động cháy nổ trong game, tạo cảm giác nhập vai hoàn hảo nhất. Micro lọc ồn có thể tháo rời linh hoạt giúp bạn đàm thoại rõ ràng cùng đồng đội mà không bị ảnh hưởng bởi các tạp âm khó chịu xung quanh phòng. Đệm tai bằng vải lưới thoáng khí mang lại sự êm ái tối đa khi sử dụng liên tục suốt nhiều giờ đồng hồ dài.',1850000,28,1550000,'Gaming','https://owlgaming.vn/wp-content/uploads/2024/09/Tai-nghe-Corsair-HS55-Surround-1.jpg','Tai Nghe Gaming'),
    (NULL,'Lót Chuột RGB Cỡ Lớn','Miếng lót chuột kích thước XXL phủ kín mặt bàn với hệ thống đèn LED RGB bao quanh viền tạo hiệu ứng lung linh, huyền ảo cho góc máy tính chơi game của bạn vào ban đêm. Bề mặt vải micro-textured mịn màng giúp chuột di chuyển cực kỳ mượt mà và đạt độ chính xác tuyệt đối trong mọi tình huống game kịch tính yêu cầu phản xạ nhanh. Phần đế làm từ cao su thiên nhiên chống trượt giúp tấm lót luôn cố định chắc chắn trên bàn dù bạn có thao tác chuột mạnh bạo đến đâu. Sản phẩm tích hợp nút bấm chuyển đổi các chế độ màu sắc ngay trên cạnh viền vô cùng tiện dụng cho người dùng.',420000,65,350000,'Gaming','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lude1zx5pov348','Lót Chuột RGB'),
    (NULL,'Giá Đỡ Tai Nghe RGB','Giá đỡ tai nghe chuyên dụng không chỉ giúp treo tai nghe gọn gàng tránh tình trạng biến dạng phần đệm tai khi không sử dụng mà còn tích hợp hệ thống đèn LED RGB rực rỡ để trang trí góc làm việc thêm phần chuyên nghiệp. Sản phẩm trang bị các cổng USB mở rộng hỗ trợ truyền tải dữ liệu và sạc các thiết bị di động trực tiếp ngay từ chân đế giá đỡ vô cùng tiện lợi. Thiết kế khung thép vững chắc cùng chân đế chống trượt mang lại sự ổn định tuyệt đối trên bàn làm việc của bạn. Đây là phụ kiện không thể thiếu để nâng tầm thẩm mỹ và sự ngăn nắp cho không gian chơi game.',550000,50,420000,'Gaming','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lrvhks9h3xdw29','Giá Đỡ Tai Nghe'),
    (NULL,'Gậy Livestream Đa Năng','Gậy livestream thế hệ mới tích hợp đèn vòng LED chuyên dụng và giá đỡ điện thoại giúp các streamer dễ dàng thiết lập góc quay chuyên nghiệp ngay tại nhà mà không cần quá nhiều thiết bị cồng kềnh. Đèn LED có thể điều chỉnh linh hoạt 3 tông màu ánh sáng khác nhau và nhiều mức độ sáng từ nhẹ đến mạnh để tôn lên vẻ đẹp tự nhiên nhất của chủ thể trong khung hình. Chân đế tripod bằng hợp kim chắc chắn, có thể điều chỉnh độ cao linh hoạt lên đến 1m6 tùy theo nhu cầu quay. Đây là bộ công cụ hoàn hảo cho những ai đam mê quay vlog, dạy học online hoặc bán hàng trực tuyến hiệu quả.',720000,45,580000,'Gaming','https://tse2.mm.bing.net/th/id/OIP.B2l6oe-pxdhFdltBTJYR0AHaHa','Gậy Livestream'),
    (NULL,'Loa Gaming Soundbar','Loa Soundbar dành riêng cho game thủ với dải đèn LED RGB đồng bộ theo nhịp nhạc mang lại không gian giải trí vô cùng sống động và hiện đại cho góc máy tính cá nhân. Công suất loa mạnh mẽ với dải âm bass sâu trầm giúp bạn cảm nhận rõ nét từng rung động kịch tính trong các bộ phim ảnh hoặc trò chơi điện tử hành động. Kết nối Bluetooth 5.0 cực kỳ ổn định cùng các cổng cắm tai nghe và micro tiện lợi ngay phía trước mặt loa giúp bạn thao tác nhanh chóng. Kích thước dài của loa giúp lan tỏa âm thanh rộng khắp không gian bàn làm việc, mang lại trải nghiệm âm thanh bao trùm ấn tượng.',1050000,20,890000,'Gaming','https://salt.tikicdn.com/ts/product/00/68/24/9d684d8873a171bc9bef38933f3967ed.jpg','Loa Gaming'),
    (NULL,'Micro Thu Âm Streamer','Micro thu âm chuyên nghiệp sử dụng cổng kết nối USB Plug-and-Play cực kỳ đơn giản, rất phù hợp cho các buổi livestream, podcast hoặc lồng tiếng chất lượng cao ngay tại nhà. Sản phẩm sở hữu mô hình thu âm Cardioid tập trung lấy giọng nói từ phía trước và loại bỏ hiệu quả các âm nhiễu từ các hướng khác để giọng nói luôn trong trẻo nhất. Micro đi kèm bộ chân đế chống rung và màng lọc gió cao cấp giúp giọng nói truyền đi luôn ấm áp và rõ ràng. Đây là sự lựa chọn hàng đầu cho những vlogger và streamer muốn nâng cấp chất lượng âm thanh khi giao tiếp với khán giả trong thế giới ảo.',1350000,18,1150000,'Gaming','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lqvsiofbdb5wbc','Micro Streamer'),
    (NULL,'Kính Thực Tế Ảo VR','Kính thực tế ảo VR thế hệ mới mang đến trải nghiệm nhập vai không giới hạn vào thế giới trò chơi và phim ảnh 3D vô cùng sống động và chân thực ngay trước mắt bạn. Sản phẩm được thiết kế với thấu kính quang học cao cấp giúp giảm thiểu tối đa tình trạng mỏi mắt và chống lóa hiệu quả cho người dùng khi sử dụng lâu. Dây đeo đầu có đệm mềm mại và có thể điều chỉnh kích cỡ linh hoạt mang lại sự thoải mái tối đa trong suốt thời gian trải nghiệm ảo thuật. Bạn chỉ cần lắp điện thoại vào và bắt đầu hành trình khám phá những thế giới ảo diệu chỉ có trong trí tưởng tượng của con người.',780000,25,650000,'Gaming','https://vn-test-11.slatic.net/p/eabe53a4395cc0f1fb629bfbebdd324a.jpg','Kính VR'),
    (NULL,'Card Ghi Hình HDMI','Card ghi hình (Capture Card) là thiết bị hỗ trợ streamer chuyên nghiệp truyền tải hình ảnh chất lượng Full HD 1080p từ máy Console, máy ảnh hoặc điện thoại lên PC một cách mượt mà nhất. Sản phẩm đảm bảo tín hiệu hình ảnh và âm thanh không bị trễ tiếng hay giảm khung hình, mang lại trải nghiệm xem tuyệt vời và chất lượng cho khán giả trên các nền tảng mạng xã hội. Thiết kế vỏ nhôm cao cấp tản nhiệt tốt giúp thiết bị hoạt động bền bỉ trong các buổi livestream dài hàng giờ đồng hồ liên tục mà không lo bị nóng máy. Phụ kiện cần có để bắt đầu sự nghiệp streamer chuyên nghiệp.',1150000,15,950000,'Gaming','https://tse3.mm.bing.net/th/id/OIP.qGDF-b1369Ci_pk68ynW_wHaE8','Capture Card'),
    (NULL,'Ghế Gaming Công Thái Học','Ghế gaming thiết kế theo tiêu chuẩn công thái học chuyên sâu với bộ đệm tựa lưng và gối đầu êm ái giúp nâng đỡ cột sống hoàn hảo nhất trong những trận chiến game dài căng thẳng. Sản phẩm được bọc lớp da PU cao cấp thoáng khí, có khả năng chống trầy xước và rất dễ dàng lau chùi vệ sinh định kỳ sau khi sử dụng. Khung ghế được cấu tạo từ thép chắc chắn chịu tải trọng cực lớn kết hợp cùng chân đế xoay 360 độ linh hoạt vô cùng tiện dụng cho mọi thao tác di chuyển. Bạn có thể thoải mái ngả lưng ghế ra sau để nghỉ ngơi thư giãn một cách tuyệt vời nhất sau những giờ làm việc mệt mỏi.',4200000,10,3500000,'Gaming','https://tse1.mm.bing.net/th/id/OIP.u8WG1N6EhPmm7FAWWA6zogHaHa','Ghế Gaming'),
    (NULL,'Đèn Màn Hình Thông Minh','Đèn treo màn hình giúp chiếu sáng khu vực bàn làm việc một cách tối ưu nhất mà không gây ra hiện tượng lóa hay phản xạ ánh sáng khó chịu trên màn hình máy tính của bạn. Sản phẩm tích hợp hệ thống cảm biến ánh sáng tự động điều chỉnh độ sáng phù hợp với môi trường và tính năng điều khiển màu sắc ánh sáng linh hoạt từ ấm sang lạnh. Thiết kế kẹp thông minh không chiếm bất kỳ diện tích mặt bàn nào, mang lại sự gọn gàng và tinh tế cho góc setup gaming của bạn. Đèn sử dụng nguồn điện trực tiếp từ cổng USB vô cùng tiện lợi và giúp tiết kiệm năng lượng điện năng tiêu thụ hàng ngày.',980000,38,850000,'Gaming','https://tse2.mm.bing.net/th/id/OIP.gIgdy_iDYyW2wVrSku-gSQHaHa','Đèn Màn Hình'),
    (NULL,'Bàn Di Chuột Sưởi Ấm','Bàn di chuột tích hợp chức năng sưởi ấm thông minh chính là phụ kiện tuyệt vời giúp bảo vệ đôi tay của các game thủ luôn ấm áp và linh hoạt trong mùa đông lạnh giá của miền Bắc. Sản phẩm sử dụng chất liệu vải dẫn nhiệt an toàn tuyệt đối với khả năng điều chỉnh nhiều mức nhiệt độ khác nhau phù hợp với nhu cầu và nhiệt độ cơ thể của từng cá nhân. Bề mặt bàn di chuột vẫn đảm bảo độ mịn màng cần thiết giúp chuột di chuyển chính xác tuyệt đối trong các tác vụ hàng ngày. Đây là món quà công nghệ vô cùng ý nghĩa và thực tế cho những ai thường xuyên phải làm việc về đêm muộn.',350000,45,280000,'Gaming','https://tse3.mm.bing.net/th/id/OIP.c7ceXQDFTHzqMJyffvi_AgHaHa','Lót Chuột Sưởi'),
    (NULL,'Dây Cáp Mạng Gaming','Dây cáp mạng CAT7 tốc độ cao với khả năng truyền tải dữ liệu cực khủng lên đến 10Gbps, đảm bảo đường truyền internet luôn ổn định và mượt mà cho các trận game online đối kháng đỉnh cao. Sản phẩm được bọc lớp vỏ vải dù chắc chắn chống rối và tăng độ bền cơ học lên gấp nhiều lần so với các loại cáp nhựa thông thường trên thị trường. Đầu nối mạ vàng 24K giúp tăng khả năng dẫn điện và chống nhiễu tín hiệu hiệu quả nhất trong mọi môi trường. Đây là phụ kiện nhỏ nhưng cực kỳ quan trọng để bạn loại bỏ hoàn toàn hiện tượng giật lag phiền phức khi đang trong ván đấu quan trọng nhất.',240000,100,180000,'Gaming','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-ltq392k1ij2l12','Cáp Mạng'),


-- NHÓM HỌC TẬP
    (NULL,'Bút Máy Ký Tên Cao Cấp','Dòng bút máy thiết kế vô cùng sang trọng với phần thân được làm bằng kim loại cao cấp phủ lớp sơn mài bóng bẩy, là món quà tặng đầy ý nghĩa cho thầy cô hoặc cấp trên trong các dịp đặc biệt của năm. Ngòi bút được chế tác tinh xảo bằng chất liệu thép không gỉ bền bỉ, cho nét chữ thanh đậm mượt mà và hoàn toàn không gây hiện tượng tắc mực khi bạn viết nhanh hoặc ký tên. Hệ thống bơm mực hiện đại giúp việc nạp mực trở nên sạch sẽ và dễ dàng hơn bao giờ hết cho người dùng. Sản phẩm đi kèm hộp đựng bọc nhung cao cấp, thể hiện đẳng cấp và gu thẩm mỹ của người sử dụng.',350000,100,250000,'Học tập','https://tse4.mm.bing.net/th/id/OIP.qRJj7eFjoTCmo0AIug49NQHaHa','Bút máy'),
    (NULL,'Sổ Tay Da Handmade','Sổ tay ghi chép được làm thủ công tỉ mỉ với phần bìa bằng chất liệu da thật mang đậm phong cách vintage cổ điển và độc đáo cho những người dùng yêu thích sự cá tính, khác biệt. Ruột sổ sử dụng loại giấy kraft định lượng cao với tông màu hơi ngả vàng giúp bảo vệ mắt khỏi tình trạng mỏi khi bạn phải ghi chép dưới ánh đèn trong thời gian dài liên tục. Các trang giấy được khâu tay vô cùng chắc chắn, cho phép bạn mở phẳng 180 độ để ghi chép một cách dễ dàng và thuận tiện nhất. Đây là người bạn đồng hành lý tưởng để bạn lưu giữ lại những ý tưởng sáng tạo hay kế hoạch quan trọng.',250000,150,180000,'Học tập','https://down-vn.img.susercontent.com/file/16289aad1600fb1d8b808be96e0b58ef','Sổ tay da'),
    (NULL,'Bộ Bút Màu Marker 48 Màu','Bộ bút màu Marker đa dạng với 48 tông màu sắc sống động khác nhau, giúp các bạn sinh viên ngành mỹ thuật và những người đam mê hội họa có thể thỏa sức sáng tạo nên những tác phẩm nghệ thuật. Sản phẩm sở hữu thiết kế thông minh với hai đầu bút: một đầu nét nhỏ để vẽ chi tiết tỉ mỉ và một đầu dẹt để tô màu diện rộng vô cùng tiện lợi khi sử dụng. Mực bút khô nhanh chóng, màu sắc hiển thị chân thực và có khả năng chồng màu mượt mà trên nhiều loại giấy vẽ chuyên dụng. Sản phẩm đi kèm túi đựng bằng vải dù chắc chắn, giúp bạn dễ dàng mang theo bên mình mọi lúc.',420000,80,350000,'Học tập','https://tse4.mm.bing.net/th/id/OIP.Es5G8mWsgUxs6B7asK4oQgHaHa','Bút Màu'),
    (NULL,'Máy Tính Khoa Học Casio','Máy tính cầm tay chuyên dụng tích hợp hàng trăm tính năng tính toán thông minh từ cơ bản đến phức tạp như giải phương trình, tính tích phân và các hàm lượng giác chuyên sâu nhất hiện nay. Sản phẩm là trợ thủ đắc lực không thể thiếu cho các bạn học sinh và sinh viên trong các kỳ thi toán học và kỹ thuật quan trọng của cuộc đời. Màn hình hiển thị lớn và sắc nét giúp bạn quan sát các kết quả tính toán một cách dễ dàng và chính xác nhất. Phím bấm có độ nảy cực tốt và bền bỉ cùng thời lượng pin sử dụng lâu dài mang lại sự yên tâm tuyệt đối khi mang vào phòng thi.',650000,60,550000,'Học tập','https://down-vn.img.susercontent.com/file/sg-11134201-7rdvl-lzm7zaextdbr08','Máy Tính'),
    (NULL,'Hộp Bút Đa Năng','Hộp bút thiết kế nhiều ngăn chứa thông minh giúp bạn sắp xếp gọn gàng toàn bộ dụng cụ học tập thiết yếu như bút viết, thước kẻ, compa và gôm tẩy vào một nơi duy nhất để dễ dàng quản lý. Sản phẩm được làm từ chất liệu vải canvas bền đẹp kết hợp cùng các họa tiết trẻ trung, bắt mắt tạo thêm nguồn cảm hứng học tập mỗi ngày cho các bạn trẻ. Khóa kéo trơn tru bền bỉ giúp bảo vệ toàn bộ đồ dùng bên trong không bị rơi mất khi di chuyển, rất tiện lợi để bỏ vào cặp sách hoặc balo. Đây là món quà nhỏ xinh xắn dành tặng cho các bạn học sinh trong dịp khai trường đầu năm học mới.',110000,120,85000,'Học tập','https://down-vn.img.susercontent.com/file/vn-11134201-7qukw-lfhqi9kdxn5w8a','Hộp Bút'),
    (NULL,'Bộ Thước Kẻ Kỹ Thuật','Bộ thước kẻ bao gồm đầy đủ các loại dụng cụ như thước thẳng, thước đo độ và eke chuyên dụng cho việc học toán hình học và vẽ kỹ thuật chính xác nhất. Sản phẩm được làm từ chất liệu nhựa dẻo trong suốt cao cấp, có độ bền cơ học cao và không bị gãy gập khi bạn vô tình va đập mạnh hoặc uốn cong. Các vạch chia khoảng cách được in rõ ràng bằng loại mực cao cấp, hoàn toàn không bị phai mờ sau thời gian dài sử dụng thường xuyên hàng ngày. Toàn bộ bộ sản phẩm được đựng trong hộp nhựa gọn gàng, giúp bảo quản thước luôn sạch sẽ và tránh tình trạng trầy xước bề mặt.',65000,200,45000,'Học tập','https://salt.tikicdn.com/ts/product/af/de/d4/db35aeeb13913506e305a96f6e1961e0.jpg','Bộ Thước'),
    (NULL,'Giá Đỡ Sách Thông Minh','Giá đỡ sách giúp bạn luôn duy trì được khoảng cách đọc sách lý tưởng nhất, hỗ trợ đắc lực trong việc ngăn ngừa tình trạng cận thị và đau mỏi cổ vai gáy cho các bạn học sinh sinh viên. Thiết kế kẹp giữ sách chắc chắn cho phép bạn mở rộng toàn bộ trang sách mà không lo bị đóng lại tự động, giúp việc ghi chép bài học trở nên dễ dàng và thuận tiện hơn bao giờ hết. Sản phẩm có thể điều chỉnh linh hoạt nhiều mức độ nghiêng khác nhau phù hợp với tư thế ngồi hằng ngày. Chất liệu nhựa ABS bền bỉ với màu sắc bắt mắt trang trí thêm nét đẹp cho góc bàn học tập.',160000,45,120000,'Học tập','https://tse1.mm.bing.net/th/id/OIP.qyGXJpKPEnbDu0v0TuYPkAHaHa','Giá Đỡ Sách'),
    (NULL,'Bảng Viết Tự Xóa LCD','Bảng vẽ điện tử tự xóa là công cụ tuyệt vời và sáng tạo để các em nhỏ tập vẽ hoặc người lớn ghi chú nhanh các ý tưởng mà không cần dùng đến giấy mực gây lãng phí môi trường. Sản phẩm sử dụng công nghệ cảm ứng lực nhấn giúp nét vẽ thanh đậm rõ ràng và tính năng xóa toàn bộ nội dung chỉ bằng một nút bấm duy nhất vô cùng tiện lợi. Màn hình LCD không gây chói mắt, không phát xạ ánh sáng xanh và hoàn toàn an toàn cho thị lực trẻ em khi sử dụng lâu dài. Thiết kế mỏng nhẹ như một chiếc máy tính bảng mini, rất dễ dàng để mang đi chơi hay đi học mọi lúc mọi nơi.',250000,70,180000,'Học tập','https://images.unsplash.com/photo-1516534775068-ba3e7458af70','Bảng LCD'),
    (NULL,'Cặp Học Sinh Chống Gù','Cặp sách thiết kế đặc biệt theo tiêu chuẩn y khoa với hệ thống quai đeo ôm sát vòng vai và tấm đệm lưng giúp phân tán trọng lượng đều lên lưng, bảo vệ cột sống cho trẻ nhỏ một cách tối ưu. Chất liệu vải dù cao cấp có khả năng chống thấm nước và chống mài mòn cực tốt, đảm bảo độ bền bỉ qua nhiều năm học dài của bé. Thiết kế nhiều ngăn chứa rộng rãi và tích hợp thêm các chi tiết phản quang an toàn khi các bé di chuyển trong điều kiện ánh sáng yếu buổi chiều tối. Đây chính là sự lựa chọn hàng đầu của cha mẹ để đồng hành cùng con trẻ mỗi ngày đến trường.',980000,25,850000,'Học tập','https://down-vn.img.susercontent.com/file/vn-11134201-7r98o-lzvewd65ec9t0d','Cặp Học Sinh'),
    (NULL,'Bút Chì Màu Cao Cấp','Bộ bút chì màu chuyên nghiệp gồm 72 tông màu sắc phong phú và đa dạng, cho phép bạn thỏa sức tạo ra những tác phẩm hội họa sinh động và giàu cảm xúc nhất theo phong cách cá nhân. Lõi chì được làm từ chất liệu mềm mịn, có độ bám màu cực tốt trên các loại giấy vẽ và khả năng trộn màu hoàn hảo để tạo nên các hiệu ứng chuyển màu tinh tế và mượt mà. Vỏ bút được làm từ gỗ tuyết tùng cao cấp giúp bảo vệ lõi chì không bị gãy vụn khi chuốt hoặc khi vô tình đánh rơi. Sản phẩm được đựng trong hộp thiếc sang trọng, rất phù hợp để làm quà tặng giá trị.',520000,40,420000,'Học tập','https://tse4.mm.bing.net/th/id/OIP.hDI5BtBCxV5wdK3otuC4PgHaHa','Bút Chì Màu'),
    (NULL,'Bộ Com-pa Kỹ Thuật','Bộ Com-pa kỹ thuật bao gồm dụng cụ vẽ đường tròn chuyên dụng và các phụ kiện thay thế ngòi chì dành riêng cho môn toán hình học và các bản vẽ thiết kế kiến trúc chính xác. Sản phẩm được làm hoàn toàn từ chất liệu hợp kim thép bền bỉ, không bị gỉ sét và có cơ cấu điều chỉnh bán kính vô cùng chính xác, đảm bảo không bị xê dịch khi bạn thao tác vẽ. Thiết kế tay cầm có bọc lớp nhựa chống trượt giúp bạn thao tác linh hoạt và dễ dàng tạo ra những hình vẽ chuẩn mực nhất trong các bài kiểm tra. Sản phẩm là món đồ học tập thiết yếu gắn liền với tuổi học trò hằng ngày.',85000,150,65000,'Học tập','https://tse4.mm.bing.net/th/id/OIP.-FS22nhaUn1ZPGULC0rV0wAAAA','Bộ Com-pa'),
    (NULL,'Kính Hiển Vi Mini','Kính hiển vi cầm tay mini với độ phóng đại ấn tượng lên đến 60 lần giúp các em nhỏ thỏa sức khám phá thế giới vi mô kỳ thú xung quanh mình một cách sinh động nhất. Sản phẩm tích hợp thêm đèn LED chiếu sáng hỗ trợ việc quan sát rõ nét các chi tiết nhỏ trên lá cây, cánh côn trùng hay bề mặt vải vóc hằng ngày của con người. Thiết kế nhỏ gọn nằm vừa vặn trong lòng bàn tay, rất thuận tiện để mang theo bên mình trong các buổi dã ngoại ngoại khóa khám phá thiên nhiên. Đây là món đồ chơi giáo dục tuyệt vời giúp kích thích trí tò mò và niềm đam mê khoa học.',320000,35,250000,'Học tập','https://tse2.mm.bing.net/th/id/OIP.-qjLzhJ91cxEYztvMf9P-gHaHa','Kính Hiển Vi'),
    (NULL,'Địa Cầu Học Tập','Quả địa cầu học tập với thiết kế tinh xảo, mô tả chính xác bản đồ thế giới cùng các ranh giới quốc gia và đặc điểm địa hình lục địa rõ ràng nhất bằng ngôn ngữ chuẩn xác. Sản phẩm là công cụ trực quan sinh động giúp các em học sinh dễ dàng tiếp thu kiến thức địa lý tự nhiên và hiểu biết thêm về các nền văn hóa, đất nước trên thế giới. Chân đế bằng nhựa chắc chắn có thể xoay 360 độ linh hoạt giúp việc tìm kiếm vị trí các vùng đất trở nên thú vị và hấp dẫn hơn. Đây không chỉ là món đồ học tập bổ ích mà còn là vật phẩm trang trí bàn làm việc vô cùng thẩm mỹ.',460000,20,380000,'Học tập','https://www.bandochuyennghiep.com/datafiles/42187/upload/files/Dia%20cau%20-%20Inox/33TA/Dia%20cau%2033-2.jpg','Địa Cầu'),
    (NULL,'Đèn Bàn Chống Cận','Đèn bàn học sử dụng công nghệ LED hiện đại bậc nhất cung cấp nguồn ánh sáng liên tục, không nhấp nháy, giúp bảo vệ thị lực tối ưu cho trẻ nhỏ trong khi học bài buổi tối. Đèn tích hợp 3 chế độ ánh sáng linh hoạt phù hợp cho các nhu cầu đọc sách, học tập hay làm việc căng thẳng và có thêm tính năng hẹn giờ thông minh vô cùng tiện lợi. Thân đèn được thiết kế có thể xoay linh hoạt nhiều góc độ giúp bạn tập trung nguồn sáng đúng vị trí mong muốn trên trang sách. Đây chính là sản phẩm cần thiết trên mỗi bàn học để tạo ra một không gian học tập chất lượng cao.',650000,50,520000,'Học tập','https://minhlight.com/wp-content/uploads/2023/03/HHGLT042088-4.jpg','Đèn Bàn'),
    (NULL,'Gôm Tẩy Đồ Chơi','Bộ gôm tẩy thiết kế theo hình dáng các loại trái cây và đồ vật ngộ nghĩnh, mang lại niềm vui và hứng khởi cho trẻ nhỏ trong mỗi giờ học viết hay vẽ tranh hằng ngày tại trường. Sản phẩm được làm hoàn toàn từ chất liệu cao su tự nhiên an toàn tuyệt đối, không chứa hóa chất độc hại và có khả năng tẩy sạch mọi vết chì mà không làm rách hay nhăn giấy vẽ. Những cục tẩy xinh xắn này không chỉ giúp các bé sửa lỗi sai một cách nhanh chóng mà còn có thể sử dụng như món đồ chơi trang trí bàn học cực kỳ đáng yêu. Đây là phụ kiện học tập nhỏ gọn nhưng vô cùng thiết thực.',35000,300,25000,'Học tập','https://down-vn.img.susercontent.com/file/sg-11134201-22110-xdm0spxg5xjv53','Gôm Tẩy'),


-- NHÓM ĐỒ ĂN & TRANG SỨC
    (NULL,'Cơm Cháy Chà Bông','Cơm cháy chà bông đặc sản được chế biến từ những hạt gạo nếp thơm ngon nhất, chiên giòn rụm và phủ lên một lớp chà bông heo đậm đà cùng nước mắm ớt cay nồng vô cùng hấp dẫn vị giác. Sản phẩm được đóng gói bằng công nghệ hút chân không hiện đại, đảm bảo vệ sinh an toàn thực phẩm khắt khe nhất và giữ trọn độ giòn tan như vừa mới ra lò cho người thưởng thức. Đây chính là món ăn vặt lý tưởng để bạn nhâm nhi cùng bạn bè, gia đình trong những buổi xem phim thư giãn hoặc làm quà tặng ý nghĩa cho người thân sau mỗi chuyến đi du lịch xa về.',110000,200,85000,'Đồ ăn','https://down-vn.img.susercontent.com/file/vn-11134201-23020-ju6bo79vuznv10','Cơm cháy'),
    (NULL,'Hạt Điều Rang Muối','Hạt điều rang muối thượng hạng với những hạt điều to tròn, giòn bùi đặc trưng và được rang cẩn thận theo phương pháp thủ công để giữ nguyên được giá trị dinh dưỡng tự nhiên quý giá. Lớp muối mỏng phủ bên ngoài tạo nên vị mặn nhẹ nhàng, làm nổi bật lên hương vị béo ngậy đặc trưng của hạt điều Bình Phước nổi tiếng khắp cả nước. Đây là món ăn vặt vô cùng bổ dưỡng, giàu protein và các chất béo có lợi cho sức khỏe, phù hợp cho mọi lứa tuổi sử dụng để bổ sung năng lượng hàng ngày. Sản phẩm được đựng trong hũ nhựa cao cấp giúp bảo quản độ giòn tốt nhất.',190000,150,150000,'Đồ ăn','https://salt.tikicdn.com/ts/tmp/aa/f8/4e/83538dd75efd26dd1cff8611248724ef.jpg','Hạt điều'),
    (NULL,'Khô Bò Xé Cay','Khô bò xé cay được chế biến từ thịt bò tươi chọn lọc kỹ lưỡng, tẩm ướp các loại gia vị đậm đà cùng ớt cay và sả thơm nức lòng người thưởng thức ngay từ lần đầu tiên chạm vào. Từng sợi bò dai mềm vừa phải, thấm đẫm vị ngọt tự nhiên của thịt và vị cay nồng nàn của gia vị mang lại cảm giác phấn khích cực kỳ khó quên cho người dùng. Sản phẩm hoàn toàn không chứa chất bảo quản hóa học độc hại, đảm bảo an toàn tuyệt đối cho sức khỏe người tiêu dùng. Món ăn này chính là lựa chọn tuyệt vời cho những buổi tiệc trà họp mặt hay làm món nhắm nhâm nhi cùng bia lạnh.',280000,100,220000,'Đồ ăn','https://down-vn.img.susercontent.com/file/vn-11134207-7r98o-lvzrg9rbh6fvab','Khô bò'),
    (NULL,'Trái Cây Sấy Dẻo','Bộ sưu tập trái cây sấy dẻo đặc biệt bao gồm xoài, mít và thanh long được sản xuất bằng công nghệ sấy lạnh hiện đại nhất giúp giữ trọn vẹn hương vị và màu sắc tự nhiên như trái cây tươi vừa hái. Sản phẩm có độ dẻo vừa phải, vị ngọt thanh khiết tự nhiên và rất giàu chất xơ cùng các vitamin cần thiết cho cơ thể luôn năng động mỗi ngày. Đây là món ăn vặt lành mạnh hàng đầu cho phái đẹp muốn duy trì vóc dáng thon gọn mà vẫn được thưởng thức hương vị thơm ngon. Đóng gói túi zip tiện lợi giúp bạn dễ dàng mang theo bên mình mọi lúc mọi nơi.',155000,180,120000,'Đồ ăn','https://tse2.mm.bing.net/th/id/OIP.fsWTbEXCIkWT00IV5KhDLwHaHa','Trái cây sấy'),
    (NULL,'Bánh Gấu Nhân Kem','Bánh gấu nhân kem sữa thơm ngậy chính là món ăn vặt gắn liền với tuổi thơ của bao thế hệ người Việt với lớp vỏ bánh giòn tan và phần nhân kem ngọt ngào chảy ra bên trong lòng bánh. Hình dáng của những chú gấu nhỏ đáng yêu giúp kích thích vị giác và tạo sự thích thú tuyệt vời cho các em nhỏ khi thưởng thức món ăn hằng ngày cùng bạn bè. Sản phẩm được sản xuất trên dây chuyền công nghệ hiện đại, đảm bảo đầy đủ các tiêu chuẩn vệ sinh an toàn thực phẩm khắt khe nhất. Đây là món ăn nhẹ tuyệt vời để bổ sung năng lượng nhanh chóng cho bạn.',65000,250,45000,'Đồ ăn','https://tse1.mm.bing.net/th/id/OIP.rhT9a_vySyxXRQ9bMfwknwHaHa','Bánh gấu'),
    (NULL,'Dây Chuyền Bạc Ý','Dây chuyền tinh xảo được chế tác từ chất liệu bạc Ý 925 cao cấp nhất, sở hữu độ sáng bóng bền bỉ và hoàn toàn an toàn, thân thiện cho làn da nhạy cảm nhất của người sử dụng hàng ngày. Mặt dây chuyền được thiết kế hình trái tim cách điệu đính đá Zirconia lấp lánh như kim cương, tạo nên vẻ đẹp thanh lịch, dịu dàng nhưng không kém phần quý phái cho phái đẹp trong mọi sự kiện lớn nhỏ. Sợi dây mảnh tinh tế rất dễ phối hợp với các loại váy đầm dạ hội sang trọng hoặc trang phục công sở hằng ngày, giúp bạn luôn tự tin tỏa sáng và thu hút mọi ánh nhìn xung quanh.',550000,50,420000,'Trang sức','https://tse4.mm.bing.net/th/id/OIP.tdUqO504jdL0kJDf9QZWVwHaHa','Dây chuyền'),
    (NULL,'Lắc Tay Nam Mạnh Mẽ','Lắc tay nam với thiết kế dạng mắt xích to bản mang lại vẻ ngoài vô cùng mạnh mẽ, nam tính và đầy cá tính cho những phái mạnh yêu thích sự phá cách trong thời trang. Sản phẩm được làm hoàn toàn từ chất liệu thép không gỉ cao cấp, đảm bảo không bị đen hay gỉ sét dưới tác động của mồ hôi và nước biển khi bạn tham gia các hoạt động hàng ngày. Khóa cài chắc chắn giúp bạn hoàn toàn yên tâm khi vận động mạnh mà không lo bị rơi mất sản phẩm. Đây chính là món phụ kiện thời thượng giúp tạo điểm nhấn ấn tượng cho đôi tay khi diện cùng những trang phục bụi bặm.',450000,45,350000,'Trang sức','https://tse4.mm.bing.net/th/id/OIP.mymCLT7ymt3DRuL9sLKm_wHaHa','Lắc tay nam'),
    (NULL,'Nhẫn Cưới Kim Cương','Nhẫn cưới tinh tế được chế tác từ vàng trắng 18K đính kèm kim cương tự nhiên tinh xảo, là biểu tượng vĩnh cửu và cao quý cho tình yêu đôi lứa bền vững sâu đậm theo thời gian. Đường nét thiết kế tinh tế, hiện đại mang lại vẻ ngoài vô cùng sang trọng và đẳng cấp tuyệt đối cho các cặp đôi trong ngày trọng đại nhất cuộc đời mình. Mỗi viên kim cương đều được tuyển chọn kỹ lưỡng về độ tinh khiết và khả năng bắt sáng tuyệt vời nhất từ những thợ thủ công lành nghề. Sản phẩm đi kèm giấy kiểm định chất lượng quốc tế và chế độ bảo hành làm mới trọn đời cho quý khách.',18500000,10,15500000,'Trang sức','https://caohungdiamond.com/wp-content/uploads/2023/10/nhan-cuoi-kim-cuong-vang-nc-0022-img01.jpg','Nhẫn cưới');











create table carts(
    ID_CART INT AUTO_INCREMENT PRIMARY KEY,
    ID_USER INT,
    FOREIGN KEY (ID_USER) REFERENCES users(ID_USER)
);








create table cart_items
(
    ID          INT AUTO_INCREMENT PRIMARY KEY,
    ID_PRODUCT INT,
    QUANTITY    INT,
    ID_CART     INT,
    FOREIGN KEY (ID_CART) REFERENCES carts(ID_CART),
    FOREIGN KEY (ID_PRODUCT) REFERENCES product(ID_PRODUCT) ON DELETE CASCADE #ON DELETE CASCADE này sẽ xoá tất cả những j liên quan khi bên product bị xoá đi 1 instance nào đó


);









create table orders(
    ID_ORDER INT AUTO_INCREMENT PRIMARY KEY,
    DESCRIPTION VARCHAR(150),
    STATUS VARCHAR(150),
    TOTAL_AMOUNT NUMERIC(19,6),
    ID_USER INT NOT NULL,
    FOREIGN KEY (ID_USER) REFERENCES users(ID_USER)

);




create table oders_items(
    id INT AUTO_INCREMENT PRIMARY KEY,
    ID_PRODUCT INT,
    ID_ORDER INT,
    ORIGINAL_PRICE NUMERIC(19,3),
    PRICE NUMERIC(19,3),
    FOREIGN KEY (ID_PRODUCT) REFERENCES product (ID_PRODUCT) ON DELETE CASCADE,
    FOREIGN KEY (ID_ORDER) REFERENCES orders(ID_ORDER)
);





